    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  return NextResponse.json({ chat }, { status: 200 });
}

export async function PUT(request: NextRequest, { params }: { params: Promise<{ chatId: string }> }) {
  const session = await getServerSession(authOptions);
  if (!session) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }
  const { chatId } = await params;
  await dbConnect();

  try {
    const chat = await Chat.findById(chatId);
    if (!chat || chat.type !== 'consumer') {
      return NextResponse.json({ error: 'Consumer chat not found' }, { status: 404 });
    }

    const body = await request.json().catch(() => ({}));
    const action = typeof body.action === 'string' ? body.action : '';

    const currentUserId = session.user.id;
    const isParticipant = (chat.participants as any[]).some((id) => id.toString() === currentUserId);
    if (!isParticipant && session.user.role !== 'admin' && session.user.role !== 'staff') {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    if (action === 'accept') {
      const settings = await BusinessSettings.findOne();
      if (settings?.consumerChatEnabled === false && session.user.role === 'customer') {
        return NextResponse.json({ error: 'Consumer-to-consumer chat is currently disabled by the admin.' }, { status: 403 });
      }

      if (chat.status !== 'pending') {
        return NextResponse.json({ error: 'Chat is not pending' }, { status: 400 });
      }
      if (chat.targetUser?.toString() !== currentUserId) {
        return NextResponse.json({ error: 'Only the invited customer can accept this chat request' }, { status: 401 });
      }

      chat.status = 'active';
      chat.acceptedAt = new Date();
      chat.acceptedBy = currentUserId;
      chat.lastMessageAt = new Date();
      await chat.save();

      const acceptedUser = await User.findById(currentUserId);
      const requester = await User.findById(chat.user);

      if (acceptedUser && requester) {
        await Message.create({
          chat: chat._id,
          sender: 'user',
          senderId: acceptedUser._id,
          senderName: acceptedUser.name || 'Customer',
          content: 'I have accepted the chat request. You can now continue the conversation.',
          seen: false,
        });

        await createNotificationAndPush({
          userId: requester._id.toString(),
          type: 'user-action',
          message: `${acceptedUser.name || 'A customer'} accepted your chat request.`,
          meta: { chatId: chat._id.toString(), acceptedBy: acceptedUser._id.toString() },
        });

        const requesterEmail = requester.email || process.env.EMAIL_USER;
        if (requesterEmail) {
          try {
            await sendEmail(
              requesterEmail,
              'Your chat request has been accepted',
              `<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
                 <h2 style="color: #111;">Chat request accepted</h2>
                 <p>Hi ${requester.name || 'there'},</p>
                 <p>${acceptedUser.name || 'Another customer'} has accepted your chat request. You can now continue the conversation in your account.</p>
               </div>`,
              `${acceptedUser.name || 'Another customer'} accepted your chat request.`
            );
          } catch (emailError) {
            console.error('[consumer-chat accept PUT] Email send failed:', emailError);
          }
        }
      }

      const updatedChat = await Chat.findById(chat._id)
        .populate('participants', 'name email mobile customerId')
        .populate('targetUser', 'name email mobile customerId')
        .populate('user', 'name email mobile customerId');

      return NextResponse.json({ chat: updatedChat }, { status: 200 });
    }

    if (action === 'close') {
      chat.status = 'closed';
      chat.lastMessageAt = new Date();
      await chat.save();
      const updatedChat = await Chat.findById(chat._id)
        .populate('participants', 'name email mobile customerId')
        .populate('targetUser', 'name email mobile customerId')
        .populate('user', 'name email mobile customerId');
      return NextResponse.json({ chat: updatedChat }, { status: 200 });
    }

    return NextResponse.json({ error: 'Invalid action' }, { status: 400 });
  } catch (error) {
    console.error('[consumer-chat accept PUT] Unexpected error:', error);
    return NextResponse.json({ error: 'Unable to process chat update. Please try again.' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/auth';
import dbConnect from '@/lib/mongodb';
import { isValidObjectId } from 'mongoose';
import Chat from '@/models/Chat';
import Message from '@/models/Message';
import User from '@/models/User';
import BusinessSettings from '@/models/BusinessSettings';
import { createNotificationAndPush } from '@/lib/notifications';
import { sendEmail } from '@/lib/sendEmail';

async function findCustomer(identifier: string) {
  if (!identifier) return null;
  const normalized = identifier.trim();
  if (!normalized) return null;

  let query: any;
  if (isValidObjectId(normalized)) {
    query = { _id: normalized };
  } else {
    const emailRegex = new RegExp(`^${normalized.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}$`, 'i');
    const digits = normalized.replace(/\D/g, '');
    const normalizedMobile = digits.length === 10
      ? digits
      : digits.length === 12 && digits.startsWith('91')
        ? digits.slice(-10)
        : '';
    const mobileQuery = normalizedMobile
      ? [
          { mobile: normalizedMobile },
          { mobile: new RegExp(`(?:\\+?91)?${normalizedMobile}$`) },
        ]
      : [];
    query = {
      $or: [
        { email: emailRegex },
        { customerId: emailRegex },
        ...mobileQuery,
      ],
    };
  }

  const user = await User.findOne({ role: 'customer', ...query });
  return user;
}

export async function GET(request: NextRequest) {
  const session = await getServerSession(authOptions);
  if (!session) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  await dbConnect();

  if (session.user.role === 'admin' || session.user.role === 'staff') {
    const chats = await Chat.find({ type: 'consumer' }).sort({ updatedAt: -1 })
      .populate('participants', 'name email mobile customerId')
      .populate('targetUser', 'name email mobile customerId')
      .populate('user', 'name email mobile customerId');

    return NextResponse.json({ chats }, { status: 200 });
  }

  const chats = await Chat.find({ type: 'consumer', participants: session.user.id }).sort({ updatedAt: -1 })
    .populate('participants', 'name email mobile customerId')
    .populate('targetUser', 'name email mobile customerId')
    .populate('user', 'name email mobile customerId');

  return NextResponse.json({ chats }, { status: 200 });
}

export async function POST(request: NextRequest) {
  const session = await getServerSession(authOptions);
  if (!session || session.user.role !== 'customer') {
    return NextResponse.json({ error: 'Only customers can use consumer chat requests' }, { status: 401 });
  }

  await dbConnect();

  const settings = await BusinessSettings.findOne();
  if (settings?.consumerChatEnabled === false) {
    return NextResponse.json({ error: 'Customer-to-customer chat is currently disabled.' }, { status: 403 });
  }

  try {
    const body = await request.json().catch(() => ({}));
    const targetIdentifier = typeof body.targetIdentifier === 'string' ? body.targetIdentifier.trim() : '';
    const requestMessage = typeof body.message === 'string' ? body.message.trim() : '';

    if (!targetIdentifier) {
      return NextResponse.json({ error: 'Target customer identifier is required' }, { status: 400 });
    }

    const targetUser = await findCustomer(targetIdentifier);
    if (!targetUser || targetUser.role !== 'customer') {
      return NextResponse.json({ error: 'Target customer not found' }, { status: 404 });
    }

    if (targetUser._id.toString() === session.user.id) {
      return NextResponse.json({ error: 'Cannot send a chat request to yourself' }, { status: 400 });
    }

    const requester = await User.findById(session.user.id);
    if (!requester) {
      return NextResponse.json({ error: 'Requester not found' }, { status: 404 });
    }

    let consumerChat = await Chat.findOne({
      type: 'consumer',
      participants: { $all: [requester._id, targetUser._id] },
      status: { $in: ['pending', 'active'] },
    });

    if (!consumerChat) {
      consumerChat = await Chat.create({
        user: requester._id,
        type: 'consumer',
        participants: [requester._id, targetUser._id],
        targetUser: targetUser._id,
        status: 'pending',
        requestedAt: new Date(),
        lastMessageAt: new Date(),
      });
    } else {
      consumerChat.requestedAt = consumerChat.requestedAt || new Date();
      consumerChat.lastMessageAt = new Date();
      await consumerChat.save();
    }

    const messageText = requestMessage || `${requester.name || 'A customer'} has invited you to chat.`;
    await Message.create({
      chat: consumerChat._id,
      sender: 'user',
      senderId: requester._id,
      senderName: requester.name || 'Customer',
      type: 'text',
      content: messageText,
      seen: false,
    });

    await createNotificationAndPush({
      userId: targetUser._id.toString(),
      type: 'user-action',
      message: `${requester.name || 'A customer'} sent you a chat request.`,
      meta: { chatId: consumerChat._id.toString(), fromUserId: requester._id.toString() },
    });

    const targetEmail = targetUser.email || settings?.businessEmail || process.env.EMAIL_USER;
    if (targetEmail) {
      try {
        await sendEmail(
          targetEmail,
          'New chat request from another customer',
          `<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
             <h2 style="color: #111;">New consumer chat request</h2>
             <p>Hi ${targetUser.name || 'there'},</p>
             <p>${requester.name || 'A customer'} has requested to chat with you.</p>
             ${requestMessage ? `<p style="font-size: 14px; color: #555;">Message: ${requestMessage}</p>` : ''}
             <p>Please open your account to accept the chat request and continue the conversation.</p>
           </div>`,
          `You have a new chat request from ${requester.name || 'another customer'}.`
        );
      } catch (emailError) {
        console.error('[consumer-chats POST] Email send failed:', emailError);
      }
    }

    const messages = await Message.find({ chat: consumerChat._id }).sort({ createdAt: 1 });
    const populatedChat = await Chat.findById(consumerChat._id)
      .populate('participants', 'name email mobile customerId')
      .populate('targetUser', 'name email mobile customerId')
      .populate('user', 'name email mobile customerId');

    return NextResponse.json({ chat: populatedChat, messages }, { status: 201 });
  } catch (error) {
    console.error('[consumer-chats POST] Unexpected error:', error);
    return NextResponse.json({ error: 'Unable to create consumer chat request. Please try again.' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/auth';
import dbConnect from '@/lib/mongodb';
import User from '@/models/User';
import { isValidObjectId } from 'mongoose';

export async function GET(request: NextRequest) {
  const session = await getServerSession(authOptions);
  if (!session) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  await dbConnect();
  const query = request.nextUrl.searchParams.get('q')?.trim() || '';
  if (!query) {
    return NextResponse.json({ users: [] }, { status: 200 });
  }

  const searchRegex = new RegExp(query.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'i');
  const digits = query.replace(/\D/g, '');
  const normalizedMobile = digits.length === 10
    ? digits
    : digits.length === 12 && digits.startsWith('91')
      ? digits.slice(-10)
      : '';

  const searchQuery: any = {
    role: 'customer',
    _id: { $ne: session.user.id },
    $or: [
      { name: searchRegex },
      { email: searchRegex },
      { customerId: searchRegex },
    ],
  };

  if (normalizedMobile) {
    searchQuery.$or.push(
      { mobile: normalizedMobile },
      { mobile: new RegExp(`(?:\\+?91)?${normalizedMobile}$`) }
    );
  } else if (digits.length >= 6) {
    searchQuery.$or.push({ mobile: new RegExp(`${digits}$`) });
  }

  const users = await User.find(searchQuery)
    .select('name email mobile customerId')
    .limit(10)
    .sort({ createdAt: -1 });

  return NextResponse.json({ users }, { status: 200 });
}

import { getServerSession } from 'next-auth';
import connectDB from '@/lib/mongodb';
import ConsumerChat from '@/models/Chat';

interface VoiceCall {
  _id?: string;
  chatId: string;
  initiatorId: string;
  receiverId: string;
  initiatorName: string;
  receiverName: string;
  status: 'initiated' | 'ringing' | 'active' | 'ended';
  startedAt: Date;
  endedAt?: Date;
  duration?: number;
  callToken?: string; // For WebRTC or call service
}

const activeCalls = new Map<string, VoiceCall>();

export async function POST(req: Request) {
  try {
    const session = await getServerSession();
    if (!session?.user?.email) {
      return Response.json({ error: 'Unauthorized' }, { status: 401 });
    }

    await connectDB();
    const { chatId, action } = await req.json();

    if (!chatId) {
      return Response.json({ error: 'chatId required' }, { status: 400 });
    }

    const chat = await ConsumerChat.findById(chatId).populate('participants');

    if (!chat) {
      return Response.json({ error: 'Chat not found' }, { status: 404 });
    }

    if (chat.status !== 'active') {
      return Response.json({ error: 'Chat is not active' }, { status: 400 });
    }

    const initiator = chat.participants.find((p: any) => p._id.toString() === session.user.id);
    const receiver = chat.participants.find((p: any) => p._id.toString() !== session.user.id);

    if (!initiator || !receiver) {
      return Response.json({ error: 'Invalid participants' }, { status: 400 });
    }

    if (action === 'initiate') {
      const callId = `call_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
      const voiceCall: VoiceCall = {
        _id: callId,
        chatId,
        initiatorId: initiator._id.toString(),
        receiverId: receiver._id.toString(),
        initiatorName: initiator.name || 'Unknown',
        receiverName: receiver.name || 'Unknown',
        status: 'initiated',
        startedAt: new Date(),
        callToken: `token_${Math.random().toString(36).substr(2, 20)}`,
      };

      activeCalls.set(callId, voiceCall);

      // Auto-remove call after 30 seconds if not answered
      setTimeout(() => {
        if (activeCalls.get(callId)?.status === 'initiated') {
          activeCalls.delete(callId);
        }
      }, 30000);

      return Response.json({
        success: true,
        call: voiceCall,
      });
    } else if (action === 'answer') {
      const { callId } = await req.json();
      const call = activeCalls.get(callId);

      if (!call) {
        return Response.json({ error: 'Call not found' }, { status: 404 });
      }

      call.status = 'active';
      activeCalls.set(callId, call);

      return Response.json({
        success: true,
        call,
      });
    } else if (action === 'end') {
      const { callId } = await req.json();
      const call = activeCalls.get(callId);

      if (call) {
        call.status = 'ended';
        call.endedAt = new Date();
        call.duration = Math.floor(
          (call.endedAt.getTime() - call.startedAt.getTime()) / 1000
        );
        activeCalls.set(callId, call);

        // Remove from active calls after 5 seconds
        setTimeout(() => {
          activeCalls.delete(callId);
        }, 5000);
      }

      return Response.json({
        success: true,
        call,
      });
    } else if (action === 'get') {
      const { callId } = await req.json();
      const call = activeCalls.get(callId);

      return Response.json({
        call: call || null,
      });
    }

    return Response.json({ error: 'Invalid action' }, { status: 400 });
  } catch (err) {
    console.error('Error in voice call:', err);
    return Response.json({ error: 'Server error' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/auth';
import dbConnect from '@/lib/mongodb';
import Coupon from '@/models/Coupon';
import BusinessSettings from '@/models/BusinessSettings';

export async function POST(request: NextRequest) {
  try {
    const session = await getServerSession(authOptions);
    await dbConnect();
    const { code, total, productIds, cartItems } = await request.json();

    if (!code) {
      return NextResponse.json({ error: 'Coupon code required' }, { status: 400 });
    }

    if (typeof total !== 'number' || total <= 0) {
      return NextResponse.json({ error: 'Valid total required' }, { status: 400 });
    }

    const coupon = await Coupon.findOne({ code: code.toUpperCase() });
    if (!coupon) {
      return NextResponse.json({ error: 'Invalid coupon code' }, { status: 400 });
    }

    // Check if referral program is enabled for referral coupons
    if (coupon.type === 'referral') {
      const settings = await BusinessSettings.findOne();
      if (!settings || !settings.referralEnabled) {
        return NextResponse.json({ error: 'Referral program is currently disabled' }, { status: 400 });
      }
    }

    // Check if coupon belongs to a specific user and if current user can use it
    if (coupon.user) {
      if (!session) {
        return NextResponse.json({ error: 'Please login to use this coupon' }, { status: 401 });
      }
      if (coupon.user.toString() !== session.user.id) {
        return NextResponse.json({ error: 'This coupon is not available for your account' }, { status: 403 });
      }
    }

    // For bargain/bidding coupons, enforce ownership explicitly
    if ((coupon.type === 'bargain' || coupon.type === 'bidding') && !coupon.user) {
      return NextResponse.json({ error: 'This coupon is not available for your account' }, { status: 403 });
    }

    if ((coupon.type === 'bargain' || coupon.type === 'bidding') && session && coupon.user && coupon.user.toString() !== session.user.id) {
      return NextResponse.json({ error: 'This coupon is not available for your account' }, { status: 403 });
    }

    // Check if coupon is product-specific and if the products in cart match
    if (coupon.products && coupon.products.length > 0) {
      if (!productIds || !Array.isArray(productIds) || productIds.length === 0) {
        return NextResponse.json({ error: 'This coupon requires specific products in your cart' }, { status: 400 });
      }
      
      const allowedProductIds = coupon.products.map((couponProductId: any) => couponProductId.toString());
      const hasAnyValidProduct = productIds.some(cartProductId => allowedProductIds.includes(cartProductId));
      const hasOnlyValidProducts = productIds.every(cartProductId => allowedProductIds.includes(cartProductId));
      
      if (!hasAnyValidProduct) {
        return NextResponse.json({ error: 'This coupon is not valid for the products in your cart' }, { status: 400 });
      }
      
      if (!hasOnlyValidProducts) {
        return NextResponse.json({ error: 'This coupon can only be used with the selected products' }, { status: 400 });
      }
    }

    const now = new Date();
    const createdAt = new Date(coupon.createdAt);

    // Check expiration days
    if (coupon.expirationDays) {
      const expiryDate = new Date(createdAt.getTime() + coupon.expirationDays * 24 * 60 * 60 * 1000);
      if (now > expiryDate) {
        return NextResponse.json({ error: 'Coupon expired' }, { status: 400 });
      }
    }

    // Check expiration hours
    if (coupon.expirationHours) {
      const expiryTime = new Date(createdAt.getTime() + coupon.expirationHours * 60 * 60 * 1000);
      if (now > expiryTime) {
        return NextResponse.json({ error: 'Coupon expired' }, { status: 400 });
      }
    }

    // Check time range
    if (coupon.startHour !== null && coupon.endHour !== null) {
      const currentHour = now.getHours();
      if (currentHour < coupon.startHour || currentHour > coupon.endHour) {
        return NextResponse.json({ error: 'Coupon not valid at this time' }, { status: 400 });
      }
    }

    // Check usage limit
    if (coupon.usageLimit && coupon.usedCount >= coupon.usageLimit) {
      return NextResponse.json({ error: 'Coupon usage limit exceeded' }, { status: 400 });
    }

    // Calculate discount only on eligible products
    let discountBase = total;
    
    // If coupon is product-specific, calculate discount only on matching items
    if (coupon.products && coupon.products.length > 0 && cartItems && Array.isArray(cartItems)) {
      discountBase = cartItems.reduce((sum: number, item: any) => {
        const matchingCouponProduct = coupon.products.some((couponProdId: any) => 
          couponProdId.toString() === item.productId
        );
        if (matchingCouponProduct) {
          return sum + (item.price * item.quantity);
        }
        return sum;
      }, 0);
    }

    let discount = 0;
    if (coupon.type === 'bargain' || coupon.type === 'bidding') {
      if (!coupon.targetPrice || !coupon.products || coupon.products.length === 0) {
        return NextResponse.json({ error: 'Invalid coupon details' }, { status: 400 });
      }
      if (!cartItems || !Array.isArray(cartItems) || cartItems.length === 0) {
        return NextResponse.json({ error: 'This coupon requires specific products in your cart' }, { status: 400 });
      }

      const eligibleItem = cartItems.find((item: any) =>
        coupon.products.some((couponProdId: any) => couponProdId.toString() === item.productId)
      );
      if (!eligibleItem) {
        return NextResponse.json({ error: 'This coupon is not valid for the products in your cart' }, { status: 400 });
      }

      discount = Math.max(0, eligibleItem.price - coupon.targetPrice);
    } else if (coupon.discountType === 'percentage') {
      discount = (discountBase * coupon.discountValue) / 100;
    } else {
      // For product-specific fixed coupons, cap discount to eligible product total
      discount = Math.min(coupon.discountValue, discountBase);
    }

    return NextResponse.json({ 
      discount,
      couponProducts: coupon.products ? coupon.products.map((p: any) => p.toString()) : [],
      discountType: coupon.discountType,
      discountValue: coupon.discountValue
    }, { status: 200 });
  } catch (error) {
    console.error(error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/auth';
import dbConnect from '@/lib/mongodb';
import Device from '@/models/Device';

export async function POST(request: NextRequest) {
  const session = await getServerSession(authOptions);
  if (!session) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const body = await request.json();
  const { fcmToken, subscription, platform } = body;
  if (!fcmToken && !subscription) {
    return NextResponse.json({ error: 'fcmToken or subscription is required' }, { status: 400 });
  }

  await dbConnect();

  try {
    // Upsert by token or subscription endpoint
    const deviceQuery: any = { user: session.user.id };
    if (fcmToken) deviceQuery.fcmToken = fcmToken;
    if (subscription && subscription.endpoint) deviceQuery['webPushSubscription.endpoint'] = subscription.endpoint;

    const update: any = { platform: platform || 'web', lastSeen: new Date() };
    if (fcmToken) update.fcmToken = fcmToken;
    if (subscription) update.webPushSubscription = subscription;

    const device = await Device.findOneAndUpdate(deviceQuery, update, { upsert: true, new: true, setDefaultsOnInsert: true });
    return NextResponse.json({ device }, { status: 200 });
  } catch (error) {
    console.error('POST /api/devices/register error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

import dbConnect from '@/lib/mongodb';
import HomepageSection from '@/models/HomepageSection';
import { NextResponse } from 'next/server';

export async function PUT(req: Request) {
  await dbConnect();
  const body = await req.json();
  if (!body._id) return NextResponse.json({ error: 'ID is required' }, { status: 400 });
  const update: any = {};
  if (body.title !== undefined) update.title = body.title;
  if (body.type !== undefined) update.type = body.type;
  if (body.subtitle !== undefined) update.subtitle = body.subtitle;
  if (body.image !== undefined) update.image = body.image;
  if (body.link !== undefined) update.link = body.link;
  if (body.order !== undefined) update.order = body.order;
  if (body.isActive !== undefined) update.isActive = body.isActive;
  if (body.content !== undefined) update.content = body.content;
  const section = await HomepageSection.findByIdAndUpdate(body._id, update, { new: true });
  if (!section) return NextResponse.json({ error: 'Section not found' }, { status: 404 });
  return NextResponse.json({ section });
}

export async function DELETE(req: Request) {
  await dbConnect();
  const body = await req.json();
  if (!body._id) return NextResponse.json({ error: 'ID is required' }, { status: 400 });
  const result = await HomepageSection.findByIdAndDelete(body._id);
  if (!result) return NextResponse.json({ error: 'Section not found' }, { status: 404 });
  return NextResponse.json({ success: true });
}

import { NextResponse } from 'next/server';

type Product = { name: string; qty: number; price: number; total: number };
type Invoice = {
  invoiceNumber: string;
  invoiceDate: string;
  status?: string;
  company: { name: string; address: string; gst?: string; email?: string; phone?: string };
  order?: { id?: string; date?: string; paymentMethod?: string; shippingMethod?: string };
  customer: { name: string; address: string; phone?: string };
  shipping?: { name?: string; address?: string; courier?: string; tracking?: string; trackingLink?: string; deliveredOn?: string };
  products: Product[];
  subtotal: number;
  discount?: number;
  grandTotal: number;
};

function rupee(n: number) {
  return n.toLocaleString('en-IN', { style: 'currency', currency: 'INR', maximumFractionDigits: 0 });
}

function buildHtml(inv: Invoice) {
  const productsHtml = inv.products
    .map(
      (p) => `
        <tr>
          <td style="padding:10px;border-bottom:1px solid #eee">${p.name}</td>
          <td style="padding:10px;border-bottom:1px solid #eee">${p.qty}</td>
          <td style="padding:10px;border-bottom:1px solid #eee;text-align:right">${rupee(p.price)}</td>
          <td style="padding:10px;border-bottom:1px solid #eee;text-align:right">${rupee(p.total)}</td>
        </tr>`
    )
    .join('\n');

  return `<!doctype html>
  <html>
  <head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width,initial-scale=1" />
    <title>Invoice ${inv.invoiceNumber}</title>
    <style>
      body { font-family: Inter, system-ui, -apple-system, Arial; color:#111; }
      .root { max-width:900px;margin:24px auto;border:1px solid #e6e6e6;padding:16px;background:#fff }
      .header { display:flex;justify-content:space-between;border-bottom:1px solid #eee;padding-bottom:12px }
      .brand { font-weight:700;font-size:20px }
      .meta { text-align:right;color:#444 }
      table { width:100%;border-collapse:collapse;margin-top:12px }
    </style>
  </head>
  <body>
    <div class="root">
      <div class="header">
        <div>
          <div class="brand">${inv.company.name}</div>
          <div style="margin-top:6px">${inv.company.address}</div>
          <div style="margin-top:6px">${inv.company.gst ?? ''}</div>
        </div>
        <div class="meta">
          <div style="font-weight:700">${inv.status ?? 'INVOICE'}</div>
          <div>Invoice: <strong>${inv.invoiceNumber}</strong></div>
          <div>${inv.invoiceDate}</div>
        </div>
      </div>

      <div style="display:flex;gap:24px;margin-top:16px">
        <div style="flex:1">
          <div style="font-weight:600">Bill To</div>
          <div style="margin-top:8px">${inv.customer.name}</div>
          <div style="margin-top:4px;color:#444">${inv.customer.address}</div>
        </div>
        <div style="flex:1">
          <div style="font-weight:600">Ship To</div>
          <div style="margin-top:8px">${inv.shipping?.name ?? inv.customer.name}</div>
          <div style="margin-top:4px;color:#444">${inv.shipping?.address ?? inv.customer.address}</div>
        </div>
      </div>

      <table>
        <thead>
          <tr>
            <th style="text-align:left;padding:10px;border-bottom:1px solid #eee">Description</th>
            <th style="padding:10px;border-bottom:1px solid #eee">Qty</th>
            <th style="text-align:right;padding:10px;border-bottom:1px solid #eee">Unit</th>
            <th style="text-align:right;padding:10px;border-bottom:1px solid #eee">Total</th>
          </tr>
        </thead>
        <tbody>
          ${productsHtml}
        </tbody>
      </table>

      <div style="width:320px;margin-left:auto;margin-top:12px">
        <div style="display:flex;justify-content:space-between;padding:6px 0">Subtotal <span>${rupee(inv.subtotal)}</span></div>
        ${inv.discount ? `<div style="display:flex;justify-content:space-between;padding:6px 0">Discount <span>- ${rupee(inv.discount)}</span></div>` : ''}
        <div style="display:flex;justify-content:space-between;font-weight:700;padding:6px 0">Grand Total <span>${rupee(inv.grandTotal)}</span></div>
      </div>

      <div style="margin-top:18px;color:#666;font-size:12px">This is a computer generated invoice.</div>
    </div>
  </body>
  </html>`;
}

export async function POST(request: Request) {
  try {
    const body = await request.json();
    const invoice = body.invoice as Invoice | undefined;
    if (!invoice) {
      return NextResponse.json({ error: 'Missing invoice in request body' }, { status: 400 });
    }

    const html = buildHtml(invoice);
    return new Response(html, { headers: { 'Content-Type': 'text/html; charset=utf-8' } });
  } catch (err: any) {
    return NextResponse.json({ error: err.message || String(err) }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { permanentlyDeleteMedia } from '@/lib/mediaStorage';
import dbConnect from '@/lib/mongodb';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/auth';
import mongoose from 'mongoose';

export async function DELETE(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions);
    if (session?.user?.role !== 'admin') return NextResponse.json({ error: 'Forbidden' }, { status: 403 });

    const { metadataId } = await req.json();
    if (!metadataId) return NextResponse.json({ error: 'metadataId required' }, { status: 400 });

