}

import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/auth';
import dbConnect from '@/lib/mongodb';
import Notification from '@/models/Notification';
import User from '@/models/User';

const validNotificationTypes = [
  'order-status',
  'bargain',
  'outbid',
  'auction',
  'admin-message',
  'new-order',
  'cancellation-request',
  'modification-request',
  'user-action',
];

const preferenceTypeMapping: Record<string, string> = {
  orderUpdates: 'order-status',
  bargain: 'bargain',
  outbid: 'outbid',
  auction: 'auction',
  adminMessages: 'admin-message',
};

function getAllowedTypes(preferences: any) {
  const enabledTypes: string[] = [];
  if (!preferences) {
    return ['order-status', 'bargain', 'outbid', 'auction', 'admin-message'];
  }

  Object.entries(preferenceTypeMapping).forEach(([prefKey, type]) => {
    if (preferences[prefKey] !== false) {
      enabledTypes.push(type);
    }
  });

  return enabledTypes;
}

export async function GET(request: NextRequest) {
  try {
    const session = await getServerSession(authOptions);
    await dbConnect();

    const url = request.nextUrl;
    const limitParam = url.searchParams.get('limit');
    const limit = Math.min(100, Math.max(1, parseInt(limitParam || '20', 10)));
    const adminView = url.searchParams.get('admin') === 'true';

    // Admin/staff can request full list when admin=true
    if (session && (session.user.role === 'admin' || session.user.role === 'staff') && adminView) {
      const notifications = await Notification.find().sort({ createdAt: -1 }).limit(limit).lean();
      const unreadCount = await Notification.countDocuments({ isRead: false });
      return NextResponse.json({ notifications, unreadCount }, { status: 200 });
    }

    // Anonymous: only public notifications (user === null)
    if (!session) {
      const notifications = await Notification.find({ user: null }).sort({ createdAt: -1 }).limit(limit).lean();
      const unreadCount = await Notification.countDocuments({ user: null, isRead: false });
      return NextResponse.json({ notifications, unreadCount }, { status: 200 });
    }

    // Authenticated user: return notifications addressed to user or global ones, filtered by user preferences
    const user = await User.findById(session.user.id).select('notificationPreferences');
    const enabledTypes = getAllowedTypes(user?.notificationPreferences);

    const query: any = {
      $and: [
        { $or: [{ user: session.user.id }, { user: null }] },
        { type: { $in: enabledTypes } },
      ],
    };

    const notifications = await Notification.find(query).sort({ createdAt: -1 }).limit(limit).lean();
    const unreadCount = await Notification.countDocuments({ ...query, isRead: false });
    return NextResponse.json({ notifications, unreadCount }, { status: 200 });
  } catch (error) {
    console.error('GET /api/notifications error:', error);
    return NextResponse.json({ notifications: [], unreadCount: 0 }, { status: 500 });
  }
}

export async function POST(request: NextRequest) {
  const session = await getServerSession(authOptions);
  if (!session || (session.user.role !== 'admin' && session.user.role !== 'staff')) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const body = await request.json();
  const { userId, type, message, meta } = body;
  if (!type || !validNotificationTypes.includes(type)) {
    return NextResponse.json({ error: 'Invalid notification type' }, { status: 400 });
  }
  if (!message || String(message).trim().length === 0) {
    return NextResponse.json({ error: 'Message is required' }, { status: 400 });
  }

  try {
    await dbConnect();
    const notification = await Notification.create({
      user: userId || null,
      type,
      message: String(message).trim(),
      meta: meta || {},
    });
    return NextResponse.json({ notification, message: 'Notification created' }, { status: 201 });
  } catch (error) {
    console.error('POST /api/notifications error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

export async function PATCH(request: NextRequest) {
  const session = await getServerSession(authOptions);
  if (!session) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const markAllAction = request.nextUrl.searchParams.get('action') === 'markAll';
  const notificationId = request.nextUrl.searchParams.get('id');

  const body = await request.json();
  const { isRead } = body;
  if (typeof isRead !== 'boolean') {
    return NextResponse.json({ error: 'isRead boolean is required' }, { status: 400 });
  }

  await dbConnect();

  try {
    if (markAllAction) {
      if (session.user.role === 'admin' || session.user.role === 'staff') {
        await Notification.updateMany({ isRead: false }, { isRead });
      } else {
        const user = await User.findById(session.user.id).select('notificationPreferences');
        if (!user) {
          return NextResponse.json({ error: 'User not found' }, { status: 404 });
        }
        const enabledTypes = getAllowedTypes(user.notificationPreferences);
        await Notification.updateMany(
          {
            $and: [
              { $or: [{ user: session.user.id }, { user: null }] },
              { type: { $in: enabledTypes } },
              { isRead: false },
            ],
          },
          { isRead },
        );
      }
      return NextResponse.json({ message: 'All notifications updated' }, { status: 200 });
    }

    if (!notificationId) {
      return NextResponse.json({ error: 'Notification id is required' }, { status: 400 });
    }

    const notification = await Notification.findById(notificationId);
    if (!notification) {
      return NextResponse.json({ error: 'Notification not found' }, { status: 404 });
    }

    if (session.user.role !== 'admin' && session.user.role !== 'staff') {
      if (!notification.user || notification.user.toString() !== session.user.id) {
        return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
      }
    }

    notification.isRead = isRead;
    await notification.save();
    return NextResponse.json({ notification, message: 'Notification updated' }, { status: 200 });
  } catch (error) {
    console.error('PATCH /api/notifications error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

export async function DELETE(request: NextRequest) {
  const session = await getServerSession(authOptions);
  if (!session) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const notificationId = request.nextUrl.searchParams.get('id');
  if (!notificationId) {
    return NextResponse.json({ error: 'Notification id is required' }, { status: 400 });
  }

  await dbConnect();

  try {
    const notification = await Notification.findById(notificationId);
    if (!notification) {
      return NextResponse.json({ error: 'Notification not found' }, { status: 404 });
    }

    if (session.user.role !== 'admin' && session.user.role !== 'staff') {
      if (!notification.user || notification.user.toString() !== session.user.id) {
        return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
      }
    }

    await notification.deleteOne();
    return NextResponse.json({ message: 'Notification deleted' }, { status: 200 });
  } catch (error) {
    console.error('DELETE /api/notifications error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/auth';
import dbConnect from '@/lib/mongodb';
import Order from '@/models/Order';
import Product from '@/models/Product';
import User from '@/models/User';
import Coupon from '@/models/Coupon';
import BusinessSettings from '@/models/BusinessSettings';
import { releaseExpiredReservations } from '@/lib/reservationCleanup';
import { createNotificationAndPush } from '@/lib/notifications';
import { notifyAdminsNewOrder } from '@/telegramBot/helpers';
import mongoose from 'mongoose';

export async function GET() {
  try {
    const session = await getServerSession(authOptions);

    if (!session) {
      console.warn('GET /api/orders - No session found');
      return NextResponse.json({ error: 'Unauthorized - No session' }, { status: 401 });
    }

    if (!session.user?.id) {
      console.warn('GET /api/orders - Session missing user.id', { userKeys: Object.keys(session.user || {}) });
      return NextResponse.json({ error: 'Unauthorized - Invalid session' }, { status: 401 });
    }

    await dbConnect();
    await releaseExpiredReservations();

    let orders;

    if (session.user.role === 'customer') {
      orders = await Order.find({ customer: session.user.id }).populate('products.product').sort({ createdAt: -1 });
    } else if (session.user.role === 'admin' || session.user.role === 'staff') {
      orders = await Order.find({}).populate('customer', 'name email mobile customerId').populate('products.product').sort({ createdAt: -1 });
    } else {
      console.warn('GET /api/orders - Unauthorized role', { role: session.user.role });
      return NextResponse.json({ error: 'Unauthorized - Invalid role' }, { status: 401 });
    }

    return NextResponse.json(orders, { status: 200 });
  } catch (err) {
    console.error('GET /api/orders - Error:', err instanceof Error ? err.message : String(err));
    return NextResponse.json({ error: 'Internal server error', details: err instanceof Error ? err.message : 'Unknown error' }, { status: 500 });
  }
}

export async function POST(request: NextRequest) {
  try {
    const session = await getServerSession(authOptions);

    if (!session || session.user.role !== 'customer') {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    await dbConnect();
    await releaseExpiredReservations();

    const user = await User.findById(session.user.id);
    if (!user || user.blocked) {
      return NextResponse.json({ error: 'Account blocked' }, { status: 403 });
    }

    const {
      cart,
      name,
      email,
      address,
      city,
      state,
      postalCode,
      country,
      mobile,
      paymentScreenshot,
      transactionId,
      discountCoupon,
      shippingCharges = 0,
      shippingState,
    } = await request.json();

    const shippingChargesNumber = Number(shippingCharges) || 0;
    const cleanDiscountCoupon = discountCoupon ? String(discountCoupon).trim().toUpperCase() : undefined;

    let coupon = null;
    if (cleanDiscountCoupon) {
      coupon = await Coupon.findOne({ code: cleanDiscountCoupon });
      if (!coupon) {
        return NextResponse.json({ error: 'Invalid coupon code' }, { status: 400 });
      }
      if (coupon.user && coupon.user.toString() !== session.user.id) {
        return NextResponse.json({ error: 'This coupon is not available for your account' }, { status: 403 });
      }
    }

    if (!cart || !Array.isArray(cart) || cart.length === 0) {
      return NextResponse.json({ error: 'Cart is required' }, { status: 400 });
    }

    if (
      !name ||
      !email ||
      !address ||
      !city ||
      !state ||
      !postalCode ||
      !country ||
      !mobile ||
      !paymentScreenshot ||
      !transactionId
    ) {
      return NextResponse.json({ error: 'Please provide all required fields including state' }, { status: 400 });
    }

    const cartItems = Array.isArray(cart)
      ? cart.map((item: any) => ({
          productId: item.productId,
          quantity: item.quantity,
          price: item.price,
        }))
      : [];

    let total = 0;
    const orderProducts: Array<{ product: string; productName: string; quantity: number; price: number; gstPercent: number; discountPercent: number }> = [];

    for (const item of cart) {
      // validate item structure
      if (
        !item?.productId ||
        typeof item.quantity !== 'number' ||
        item.quantity <= 0
      ) {
        return NextResponse.json({ error: 'Invalid cart item' }, { status: 400 });
      }

      if (!mongoose.Types.ObjectId.isValid(item.productId)) {
        return NextResponse.json({ error: 'Invalid product ID' }, { status: 400 });
      }

      const product = await Product.findById(item.productId);
      if (!product) {
        return NextResponse.json({ error: `Product ${item.productId} not found` }, { status: 400 });
      }

      if (product.quantity < item.quantity) {
        return NextResponse.json({ error: `Insufficient quantity for ${product.name}. Available: ${product.quantity}` }, { status: 400 });
      }

      const price = product.originalPrice * (1 - product.discountPercent / 100);
      const gstPercent = product.gstPercent || 0;
      const gstAmount = price * gstPercent / 100;
      const lineTotal = (price + gstAmount) * item.quantity;
      total += lineTotal;
      orderProducts.push({
        product: item.productId,
        productName: product.name,
        quantity: item.quantity,
        price,
        gstPercent,
        discountPercent: product.discountPercent || 0,
      });
    }

    // Get business settings for referral amounts
    const settings = await BusinessSettings.findOne({});

    // Validate coupon server-side and compute coupon discount, do not trust client-provided discountAmount
    let couponDiscount = 0;
    let _couponProducts: string[] = [];
    let _couponDiscountType = 'fixed';
    let _couponDiscountValue = 0;

    if (coupon) {
      if (coupon.type === 'referral' && (!settings || !settings.referralEnabled)) {
        return NextResponse.json({ error: 'Referral program is currently disabled' }, { status: 400 });
      }

      if (!Array.isArray(cartItems) || cartItems.length === 0) {
        return NextResponse.json({ error: 'Cart is required to validate coupon' }, { status: 400 });
      }

      const productIds = cartItems.map((item: any) => item.productId);
      if (coupon.products && coupon.products.length > 0) {
        const allowedProductIds = coupon.products.map((couponProductId: any) => couponProductId.toString());
        const hasAnyValidProduct = productIds.some((cartProductId) => allowedProductIds.includes(cartProductId));
        const hasOnlyValidProducts = productIds.every((cartProductId) => allowedProductIds.includes(cartProductId));
        if (!hasAnyValidProduct) {
          return NextResponse.json({ error: 'This coupon is not valid for the products in your cart' }, { status: 400 });
        }
        if (!hasOnlyValidProducts) {
          return NextResponse.json({ error: 'This coupon can only be used with the selected products' }, { status: 400 });
        }
      }

      const now = new Date();
      const createdAt = new Date(coupon.createdAt);
      if (coupon.expirationDays) {
        const expiryDate = new Date(createdAt.getTime() + coupon.expirationDays * 24 * 60 * 60 * 1000);
        if (now > expiryDate) {
          return NextResponse.json({ error: 'Coupon expired' }, { status: 400 });
        }
      }
      if (coupon.expirationHours) {
        const expiryTime = new Date(createdAt.getTime() + coupon.expirationHours * 60 * 60 * 1000);
        if (now > expiryTime) {
          return NextResponse.json({ error: 'Coupon expired' }, { status: 400 });
        }
      }
      if (coupon.startHour !== null && coupon.endHour !== null) {
        const currentHour = now.getHours();
        if (currentHour < coupon.startHour || currentHour > coupon.endHour) {
          return NextResponse.json({ error: 'Coupon not valid at this time' }, { status: 400 });
        }
      }
      if (coupon.usageLimit && coupon.usedCount >= coupon.usageLimit) {
        return NextResponse.json({ error: 'Coupon usage limit exceeded' }, { status: 400 });
      }

      if (coupon.type === 'bargain' || coupon.type === 'bidding') {
        if (!coupon.targetPrice || !coupon.products || coupon.products.length === 0) {
          return NextResponse.json({ error: 'Invalid coupon details' }, { status: 400 });
        }
        const eligibleItem = cartItems.find((item: any) =>
          coupon.products.some((couponProductId: any) => couponProductId.toString() === item.productId)
        );
        if (!eligibleItem) {
          return NextResponse.json({ error: 'This coupon is not valid for the products in your cart' }, { status: 400 });
        }
        couponDiscount = Math.max(0, eligibleItem.price - coupon.targetPrice);
      } else {
        const discountBase = coupon.products && coupon.products.length > 0
          ? cartItems.reduce((sum: number, item: any) => {
              const matchingCouponProduct = coupon.products.some((couponProdId: any) =>
                couponProdId.toString() === item.productId
              );
              if (matchingCouponProduct) {
                return sum + item.price * item.quantity;
              }
              return sum;
            }, 0)
          : total;

        if (coupon.discountType === 'percentage') {
          couponDiscount = (discountBase * coupon.discountValue) / 100;
        } else {
          couponDiscount = Math.min(coupon.discountValue, discountBase);
        }
      }

      _couponProducts = coupon.products ? coupon.products.map((p: any) => p.toString()) : [];
      _couponDiscountType = coupon.discountType;
      _couponDiscountValue = coupon.discountValue;
    }

    // Discount breakdown for tracking
    const manualCouponDiscount = couponDiscount;
    let referralDiscount = 0;
    let firstOrderDiscount = 0;

    // Check for referral bonuses
    const customer = await User.findById(session.user.id);
    const allOrders = await Order.find({ customer: session.user.id });

    // If this is customer's first order and they were referred, apply invitee discount
    if (customer.referredBy && allOrders.length === 0 && settings?.inviteeDiscountAmount) {
      firstOrderDiscount = settings.inviteeDiscountAmount;
    }

    // If customer has pending referral bonus, apply it
    if (customer.pendingReferralBonus > 0 && !customer.usedReferralBonus) {
      referralDiscount = customer.pendingReferralBonus;
    }

    const subtotalAfterDiscount = Math.max(0, total - couponDiscount - firstOrderDiscount - referralDiscount);
    const finalTotal = subtotalAfterDiscount + shippingChargesNumber; // Include shipping in final total

    if (!Number.isFinite(finalTotal)) {
      return NextResponse.json({ error: 'Invalid order total' }, { status: 400 });
    }

    const order = new Order({
      customer: session.user.id,
      orderNumber: `${Date.now()}${Math.floor(Math.random() * 900 + 100)}`,
      products: orderProducts,
      total: finalTotal,
      shipping: { name, email, address, city, postalCode, country, mobile },
      paymentMethod: 'manual',
      paymentScreenshot,
      transactionId,
      discountCoupon: cleanDiscountCoupon,
      discountAmount: couponDiscount + referralDiscount + firstOrderDiscount,
      discountBreakdown: {
        manualCoupon: manualCouponDiscount,
        referralDiscount,
        firstOrderDiscount,
      },
      shippingCharges: shippingCharges || 0,
      shippingState: shippingState || state,
      status: 'Payment Pending',
    });

    await order.save();

    await notifyAdminsNewOrder(order);

    await createNotificationAndPush({
      type: 'new-order',
      message: `New order ${order.orderNumber} placed by ${user.name}`,
      userId: null,
      meta: { orderId: order._id.toString(), customerId: session.user.id },
    });

    // Update user if referral bonus was used
    if (customer.pendingReferralBonus > 0 && !customer.usedReferralBonus) {
      await User.findByIdAndUpdate(session.user.id, {
        usedReferralBonus: true,
        pendingReferralBonus: 0
      });
    }

    // If this was first order with referral, give referrer pending bonus
    if (customer.referredBy && allOrders.length === 0 && settings?.referralCouponAmount) {
      await User.findByIdAndUpdate(customer.referredBy, {
        pendingReferralBonus: settings.referralCouponAmount
      });
    }

    // Decrease product quantities
    for (const item of cart) {
      await Product.findByIdAndUpdate(item.productId, { $inc: { quantity: -item.quantity } });
    }

    // Mark the reserved offer/bid as redeemed when the coupon is used
    if (cleanDiscountCoupon && coupon && coupon.user && coupon.user.toString() === session.user.id) {
      await Product.updateOne(
        { 'bargainOffers.couponCode': cleanDiscountCoupon, 'bargainOffers.user': session.user.id },
        { $set: { 'bargainOffers.$.reservationUsed': true, 'bargainOffers.$.reservedUntil': undefined } }
      );
      await Product.updateOne(
        { 'bids.couponCode': cleanDiscountCoupon, 'bids.user': session.user.id },
        { $set: { 'bids.$.reservationUsed': true, 'bids.$.reservedUntil': undefined } }
      );
    }

    // Mark coupon as used if one was applied manually
    if (cleanDiscountCoupon) {
      await Coupon.findOneAndUpdate(
        { code: cleanDiscountCoupon },
        { $inc: { usedCount: 1 } }
      );
    }

    return NextResponse.json(order, { status: 201 });
  } catch (error: unknown) {
    console.error('Order POST error', error);
    const message = error instanceof Error ? error.message : 'Internal server error';
    return NextResponse.json(
      { error: message },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/auth';
import dbConnect from '@/lib/mongodb';
import Order from '@/models/Order';
import Product from '@/models/Product';
import User from '@/models/User';
import Coupon from '@/models/Coupon';
import { releaseExpiredReservations } from '@/lib/reservationCleanup';
import { notifyOrderLifecycle } from '@/lib/notificationService';
import { notifyAdminsNewOrder } from '@/telegramBot/helpers';
import mongoose from 'mongoose';

export async function POST(request: NextRequest) {
  try {
    const session = await getServerSession(authOptions);

    if (!session || session.user.role !== 'customer') {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    await dbConnect();
    await releaseExpiredReservations();

    const user = await User.findById(session.user.id);
    if (!user || user.blocked) {
      return NextResponse.json({ error: 'Account blocked' }, { status: 403 });
    }

    const body = await request.json();
    const {
      cart,
      name,
      email,
      address,
      city,
      state,
      postalCode,
      country,
      mobile,
      paymentMethod,
      cfOrderId,
      cfPaymentId,
      razorpayOrderId,
      razorpayPaymentId,
      discountCoupon,
      shippingCharges = 0,
      shippingState,
    } = body;

    const shippingChargesNumber = Number(shippingCharges) || 0;
    const cleanDiscountCoupon = discountCoupon ? String(discountCoupon).trim().toUpperCase() : undefined;

    let coupon = null;
    if (cleanDiscountCoupon) {
      coupon = await Coupon.findOne({ code: cleanDiscountCoupon });
      if (!coupon) {
        return NextResponse.json({ error: 'Invalid coupon code' }, { status: 400 });
      }
      if (coupon.user && coupon.user.toString() !== session.user.id) {
        return NextResponse.json({ error: 'This coupon is not available for your account' }, { status: 403 });
      }
    }

    if (!cart || !Array.isArray(cart) || cart.length === 0) {
      return NextResponse.json({ error: 'Cart is required' }, { status: 400 });
    }

    // For online payments (Cashfree/Razorpay), we don't require screenshot/transactionId upfront
    // They will be provided via webhook after payment
    if (paymentMethod === 'manual') {
      if (!body.paymentScreenshot || !body.transactionId) {
        return NextResponse.json({ error: 'Please provide payment screenshot and transaction ID' }, { status: 400 });
      }
    }

    if (!name || !email || !address || !city || !state || !postalCode || !country || !mobile) {
      return NextResponse.json({ error: 'Please provide all shipping details' }, { status: 400 });
    }

    const cartItems = Array.isArray(cart)
      ? cart.map((item: any) => ({
          productId: item.productId,
          quantity: item.quantity,
          price: item.price,
        }))
      : [];

    let total = 0;
    const orderProducts: Array<{ product: string; productName: string; quantity: number; price: number; gstPercent: number; discountPercent: number }> = [];

    const reserveStockImmediately = paymentMethod !== 'cashfree' && paymentMethod !== 'razorpay';

    for (const item of cart) {
      if (!item?.productId || typeof item.quantity !== 'number' || item.quantity <= 0) {
        return NextResponse.json({ error: 'Invalid cart item' }, { status: 400 });
      }

      if (!mongoose.Types.ObjectId.isValid(item.productId)) {
        return NextResponse.json({ error: 'Invalid product ID' }, { status: 400 });
      }

      const product = await Product.findById(item.productId);
      if (!product) {
        return NextResponse.json({ error: `Product ${item.productId} not found` }, { status: 400 });
      }

      if (product.quantity < item.quantity) {
        return NextResponse.json({ error: `Insufficient quantity for ${product.name}. Available: ${product.quantity}` }, { status: 400 });
      }

      const price = product.originalPrice * (1 - product.discountPercent / 100);
      const gstPercent = product.gstPercent || 0;
      const itemTotal = price * item.quantity;
      const gstAmount = itemTotal * (gstPercent / 100);
      total += itemTotal + gstAmount;

      orderProducts.push({
        product: product._id as string,
        productName: product.name,
        quantity: item.quantity,
        price: price,
        gstPercent: gstPercent,
        discountPercent: product.discountPercent,
      });

      if (reserveStockImmediately) {
        // Reserve stock only for manual payments; for online orders (Cashfree/Razorpay) we wait until payment succeeds.
        product.quantity -= item.quantity;
        await product.save();
      }
    }

    // Apply coupon discount
    let discountAmount = 0;
    if (coupon) {
      if (coupon.discountType === 'percentage') {
        discountAmount = (total * coupon.discountValue) / 100;
      } else {
        discountAmount = coupon.discountValue;
      }
      total -= discountAmount;
    }

    total += shippingChargesNumber;

    // Determine initial status based on payment method
    let initialStatus = 'Payment Pending';
    if (paymentMethod === 'cashfree' || paymentMethod === 'razorpay') {
      // For online payments, order will be updated via webhook
      initialStatus = 'Payment Processing';
    }

    const order = new Order({
      customer: session.user.id,
      products: orderProducts,
      total: Math.round(total * 100) / 100,
      status: initialStatus,
      shipping: { name, email, address, city, postalCode, country, mobile },
      discountCoupon: cleanDiscountCoupon,
      discountAmount: Math.round(discountAmount * 100) / 100,
      shippingCharges: shippingChargesNumber,
      shippingState,
      
      // Payment fields
      cfOrderId: cfOrderId || undefined,
      cfPaymentId: cfPaymentId || undefined,
      razorpayOrderId: razorpayOrderId || undefined,
      razorpayPaymentId: razorpayPaymentId || undefined,
      paymentMethod: paymentMethod || 'manual',
      
      // Manual payment fields
      paymentScreenshot: body.paymentScreenshot || undefined,
      transactionId: body.transactionId || undefined,
    });

    await order.save();

    await notifyAdminsNewOrder(order);

    // Update coupon usage
    if (coupon) {
      coupon.usedBy = (coupon.usedBy || 0) + 1;
      await coupon.save();
    }

    const shippingInfo = order.shipping
      ? {
          name: order.shipping.name ?? undefined,
          email: order.shipping.email ?? undefined,
          mobile: order.shipping.mobile ?? undefined,
        }
      : undefined;

    try {
      await notifyOrderLifecycle({
        _id: order._id?.toString(),
        customerId: session.user.id,
        orderNumber: order.orderNumber ?? undefined,
        shipping: shippingInfo,
      }, 'order-placed');
    } catch (notifError) {
      console.error('Failed to send order lifecycle notification:', notifError);
    }

    return NextResponse.json({
      _id: order._id,
      orderNumber: order.orderNumber,
      total: order.total,
      status: order.status,
      message: (paymentMethod === 'cashfree' || paymentMethod === 'razorpay') 
        ? 'Order created. Please complete payment.'
        : 'Order placed successfully! Please complete payment.',
    });

  } catch (err) {
    console.error('POST /api/payments/create-order - Error:', err instanceof Error ? err.message : String(err));
    return NextResponse.json({ error: 'Internal server error', details: err instanceof Error ? err.message : 'Unknown error' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/auth';
import crypto from 'crypto';

interface CashfreeOrder {
  order_id: string;
  order_amount: number;
  order_currency: string;
  customer_details: {
    customer_id: string;
    customer_name: string;
    customer_email: string;
    customer_phone: string;
  };
  order_meta: {
    return_url: string;
    notify_url: string;
  };
  order_note?: string;
}

export async function POST(request: NextRequest) {
  try {
    const session = await getServerSession(authOptions);

    if (!session || session.user.role !== 'customer') {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const body = await request.json();
    const { amount, orderId: providedOrderId } = body;

    if (!amount || amount <= 0) {
      return NextResponse.json({ error: 'Invalid amount' }, { status: 400 });
    }

    const appId = process.env.CASHFREE_APP_ID;
    const secretKey = process.env.CASHFREE_SECRET_KEY;
    const isTestCredential = appId?.startsWith('TEST') || secretKey?.includes('_test_');
    const defaultEnv = isTestCredential ? 'sandbox' : 'production';
    let environment = process.env.CASHFREE_ENV || defaultEnv;

    if (!appId || !secretKey) {
      console.error('Cashfree credentials not configured');
      return NextResponse.json({ 
        error: 'Payment system not configured. Please contact support.',
        code: 'PAYMENT_NOT_CONFIGURED'
      }, { status: 503 });
    }

    if (environment === 'production' && isTestCredential) {
      console.warn('Cashfree env mismatch: test credentials present while CASHFREE_ENV is production. Forcing sandbox endpoint.');
      environment = 'sandbox';
    }

    // Generate unique order ID
    const orderId = providedOrderId || `ORD-${Date.now()}-${Math.random().toString(36).substr(2, 9).toUpperCase()}`;

    // Get customer details from session
    const customerId = session.user.customerId || session.user.id || 'CUST-' + session.user.email;
    const customerName = session.user.name || 'Customer';
    const customerEmail = session.user.email || '';
    // Mobile will be passed in the request body or we can get it from user data
    const customerPhone = body.customerPhone || '';

    const hostHeader = request.headers.get('host');
    let baseUrl = process.env.NEXTAUTH_URL || `http://${hostHeader || 'localhost:3000'}`;

    // Cashfree requires HTTPS URLs for return and notify callbacks.
    // For local sandbox development, force https on localhost/127.0.0.1.
    if (hostHeader?.startsWith('localhost') || hostHeader?.startsWith('127.0.0.1')) {
      baseUrl = `https://${hostHeader}`;
    } else if (baseUrl.startsWith('http://localhost')) {
      baseUrl = baseUrl.replace('http://localhost', 'https://localhost');
    } else if (baseUrl.startsWith('http://127.0.0.1')) {
      baseUrl = baseUrl.replace('http://127.0.0.1', 'https://127.0.0.1');
    }

    const cashfreeOrder: CashfreeOrder = {
      order_id: orderId,
      order_amount: Number(amount),
      order_currency: 'INR',
      customer_details: {
        customer_id: customerId,
        customer_name: customerName,
        customer_email: customerEmail,
        customer_phone: customerPhone,
      },
      order_meta: {
        return_url: `${baseUrl}/payment-return?order_id=${orderId}`,
        notify_url: `${baseUrl}/api/payments/webhook`,
      },
      order_note: 'Pc Studio Order Payment',
    };

    const apiUrl = environment === 'production'
      ? 'https://api.cashfree.com/pg/orders'
      : 'https://sandbox.cashfree.com/pg/orders';

    console.log('Cashfree create payload:', {
      apiUrl,
      environment,
      baseUrl,
      hostHeader,
      cashfreeOrder,
    });

    const response = await fetch(apiUrl, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-api-version': '2023-08-01',
        'x-client-id': appId,
        'x-client-secret': secretKey,
      },
      body: JSON.stringify(cashfreeOrder),
    });

    const responseData = await response.json();

    // DEBUG: Log full Cashfree response for troubleshooting
    console.log('Cashfree API response:', JSON.stringify(responseData, null, 2));

    if (!response.ok) {
      const message = responseData?.message || responseData?.error || 'Failed to create payment order';
      const isLocalHttpsIssue = baseUrl.includes('localhost') && /https|return_url|notify_url|url should be https|invalid return_url/i.test(message);

      if (isLocalHttpsIssue) {
        console.error('Cashfree HTTPS requirement issue on localhost. For local testing, use: ngrok or Razorpay', { message, responseData });
        return NextResponse.json({
          error: 'Cashfree requires HTTPS URLs for return/notification callbacks when using local development.',
          details: responseData,
          suggestion: 'Use Razorpay payment method locally or expose localhost over HTTPS via ngrok or a similar tunnel.',
        }, { status: 400 });
      }
      
      return NextResponse.json({
        error: message,
        details: responseData,
      }, { status: response.status });
    }

    // Construct payment link ourselves if not returned
    const paymentLink = responseData.payment_link || (
      environment === 'production'
        ? `https://www.cashfree.com/checkout/page?token=${responseData.payment_session_id}`
        : `https://sandbox.cashfree.com/checkout/page?token=${responseData.payment_session_id}`
    );

    // Return payment session details to frontend
    return NextResponse.json({
      orderId: orderId,
      paymentSessionId: responseData.payment_session_id,
      cfOrderId: responseData.order_id,
      amount: amount,
      paymentLink: paymentLink,
      orderStatus: responseData.order_status,
      checkoutRedirect: `/payment-redirect?sessionId=${encodeURIComponent(responseData.payment_session_id)}&orderId=${encodeURIComponent(orderId)}`,
    });

  } catch (error) {
    console.error('Payment creation error:', error);
    return NextResponse.json(
      { error: 'Failed to create payment session' },
      { status: 500 }
    );
  }
}

// Verify payment status from Cashfree
export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url);
    const orderId = searchParams.get('orderId');

    if (!orderId) {
      return NextResponse.json({ error: 'Order ID required' }, { status: 400 });
    }

    const appId = process.env.CASHFREE_APP_ID;
    const secretKey = process.env.CASHFREE_SECRET_KEY;
    const isTestCredential = appId?.startsWith('TEST') || secretKey?.includes('_test_');
    const defaultEnv = isTestCredential ? 'sandbox' : 'production';
    let environment = process.env.CASHFREE_ENV || defaultEnv;

    if (!appId || !secretKey) {
      return NextResponse.json({ error: 'Payment not configured' }, { status: 503 });
    }

    if (environment === 'production' && isTestCredential) {
      console.warn('Cashfree env mismatch: test credentials present while CASHFREE_ENV is production. Forcing sandbox endpoint.');
      environment = 'sandbox';
    }

    const apiUrl = environment === 'production'
      ? 'https://api.cashfree.com/pg/orders'
      : 'https://sandbox.cashfree.com/pg/orders';

    const response = await fetch(`${apiUrl}/${orderId}`, {
      method: 'GET',
      headers: {
        'Content-Type': 'application/json',
        'x-api-version': '2023-08-01',
        'x-client-id': appId,
        'x-client-secret': secretKey,
      },
    });

    const data = await response.json();

    if (!response.ok) {
      return NextResponse.json({ error: data.message || 'Failed to get order status' }, { status: response.status });
    }

    return NextResponse.json({
      orderId: data.order_id,
      orderStatus: data.order_status,
      orderAmount: data.order_amount,
      payments: data.payments,
    });

  } catch (error) {
    console.error('Payment status check error:', error);
    return NextResponse.json(
      { error: 'Failed to check payment status' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import crypto from 'crypto';
import dbConnect from '@/lib/mongodb';
import Order from '@/models/Order';
import Shipment from '@/models/Shipment';
import Product from '@/models/Product';
import { createNotificationAndPush } from '@/lib/notifications';
import { notifyOrderLifecycle } from '@/lib/notificationService';

interface CashfreePaymentWebhook {
  order_id: string;
  order_amount: string;
  order_currency: string;
  order_status: string;
  payment: {
    cf_payment_id: string;
    payment_status: string;
    payment_message: string;
    payment_method: {
      type: string;
      utr?: string;
      vpa?: string;
      card?: {
        last_4_digits?: string;
        network?: string;
      };
      netbanking?: {
        bank_name?: string;
      };
    };
    amount: string;
    date: string;
  };
  event: string;
}

interface RazorpayPaymentWebhook {
  event: string;
  data: {
    payment: {
      entity: {
        id: string;
        order_id: string;
        amount: number;
        currency: string;
        status: string;
        method: string;
        card_id?: string;
        bank?: string;
        wallet?: string;
        vpa?: string;
        email?: string;
        contact?: string;
        fee?: number;
        tax?: number;
        error_code?: string;
        error_description?: string;
        created_at: number;
      };
    };
  };
}

export async function POST(request: NextRequest) {
  try {
    const rawBody = await request.text();
    let body: any;
    try {
      body = JSON.parse(rawBody);
    } catch (parseError) {
      console.error('Webhook JSON parse error:', parseError);
      return NextResponse.json({ error: 'Invalid JSON payload' }, { status: 400 });
    }

    // Determine webhook type based on payload structure
    const isRazorpay = body.event && body.data && body.data.payment;
    const isCashfree = body.order_id && body.order_status;

    if (!isRazorpay && !isCashfree) {
      console.error('Unknown webhook format');
      return NextResponse.json({ error: 'Unknown webhook format' }, { status: 400 });
    }

    let orderId: string;
    let paymentStatus: string;
    let paymentProvider: string;
    let paymentDetails: any = {};

    if (isRazorpay) {
      // Handle Razorpay webhook
      const razorpayData = body as RazorpayPaymentWebhook;
      const signature = request.headers.get('x-razorpay-signature');
      const secretKey = process.env.RAZORPAY_WEBHOOK_SECRET;

      // Verify Razorpay webhook signature
      if (process.env.NODE_ENV === 'production') {
        if (!signature || !secretKey) {
          console.warn('Razorpay webhook signature missing or secret not configured');
          return NextResponse.json({ error: 'Invalid signature' }, { status: 401 });
        }

        const isValid = verifyRazorpaySignature(rawBody, signature, secretKey);
        if (!isValid) {
          console.warn('Invalid Razorpay webhook signature');
          return NextResponse.json({ error: 'Invalid signature' }, { status: 401 });
        }
      }

      const payment = razorpayData.data.payment.entity;
      orderId = payment.order_id;
      paymentStatus = payment.status;
      paymentProvider = 'razorpay';
      paymentDetails = {
        razorpayPaymentId: payment.id,
        paymentStatus: payment.status,
        paymentMethod: payment.method,
        amount: payment.amount,
        currency: payment.currency,
        created_at: payment.created_at,
      };

      console.log('Razorpay webhook received:', {
        orderId: orderId,
        event: razorpayData.event,
        status: paymentStatus,
      });

    } else {
      // Handle Cashfree webhook
      const signature = request.headers.get('x-cf-signature');
      const secretKey = process.env.CASHFREE_SECRET_KEY;

      console.log('Cashfree webhook received:', {
        orderId: body.order_id,
        event: body.event,
        status: body.order_status,
      });

      // Verify webhook signature for security
      if (process.env.CASHFREE_ENV === 'production') {
        if (!signature || !secretKey) {
          console.warn('Webhook signature missing or secret not configured');
          return NextResponse.json({ error: 'Invalid signature' }, { status: 401 });
        }

        const isValid = verifyWebhookSignature(rawBody, signature, secretKey);
        if (!isValid) {
          console.warn('Invalid webhook signature');
          return NextResponse.json({ error: 'Invalid signature' }, { status: 401 });
        }
      } else if (signature && secretKey) {
        const isValid = verifyWebhookSignature(rawBody, signature, secretKey);
        if (!isValid) {
          console.warn('Invalid webhook signature in non-production mode; continuing because env is not production');
        }
      }

      const webhookData = body as CashfreePaymentWebhook;
      orderId = webhookData.order_id;
      paymentStatus = webhookData.payment?.payment_status || webhookData.order_status;
      paymentProvider = 'cashfree';
      paymentDetails = {
        cfPaymentId: webhookData.payment?.cf_payment_id,
        paymentStatus: webhookData.payment?.payment_status,
        paymentMessage: webhookData.payment?.payment_message,
        utr: webhookData.payment?.payment_method?.utr,
        vpa: webhookData.payment?.payment_method?.vpa,
      };
    }

    if (!orderId) {
      return NextResponse.json({ error: 'Order ID required' }, { status: 400 });
    }

    await dbConnect();

    // Find the order by orderId, cfOrderId, razorpayOrderId, or orderNumber
    const order = await Order.findOne({
      $or: [
        { _id: orderId },
        { cfOrderId: orderId },
        { razorpayOrderId: orderId },
        { orderNumber: orderId },
      ],
    }).populate('customer');

    if (!order) {
      console.error('Order not found for webhook:', orderId);
      return NextResponse.json({ error: 'Order not found' }, { status: 404 });
    }

    // Update order based on payment status
    switch (paymentStatus.toLowerCase()) {
      case 'captured':
      case 'success':
      case 'paid':
        if (order.status === 'Payment Pending' || order.status === 'Payment Completed' || order.status === 'Payment Processing') {
          const shouldReserveStock = paymentProvider === 'cashfree' || paymentProvider === 'razorpay';
          
          order.status = 'Payment Verified';
          order.paymentVerifiedAt = new Date();
          order.paymentMethod = 'online';

          if (paymentProvider === 'cashfree') {
            if (!order.cfOrderId && orderId) {
              order.cfOrderId = orderId;
            }
            order.cfPaymentId = paymentDetails.cfPaymentId;
            order.transactionId = paymentDetails.cfPaymentId || paymentDetails.utr || '';
          } else if (paymentProvider === 'razorpay') {
            if (!order.razorpayOrderId && orderId) {
              order.razorpayOrderId = orderId;
            }
            order.razorpayPaymentId = paymentDetails.razorpayPaymentId;
            order.transactionId = paymentDetails.razorpayPaymentId || '';
          }

          order.paymentDetails = paymentDetails;

          if (shouldReserveStock) {
            for (const item of order.products) {
              try {
                const product = await Product.findById(item.product);
                if (product) {
                  if (product.quantity >= item.quantity) {
                    product.quantity -= item.quantity;
                    await product.save();
                  } else {
                    console.warn(`Low stock when confirming ${paymentProvider} order ${order._id}: ${item.product}`);
                  }
                }
              } catch (productError) {
                console.error(`Failed to reserve stock on ${paymentProvider} payment success:`, productError);
              }
            }
          }

          await order.save();

          const shippingInfo = order.shipping
            ? {
                name: order.shipping.name ?? undefined,
                email: order.shipping.email ?? undefined,
                mobile: order.shipping.mobile ?? undefined,
              }
            : undefined;

          // Send notification to customer
          try {
            await notifyOrderLifecycle({
              _id: order._id?.toString(),
              customerId: order.customer?.toString(),
              orderNumber: order.orderNumber ?? undefined,
              shipping: shippingInfo,
            }, 'payment-success');
          } catch (notifError) {
            console.error('Failed to send payment success notification:', notifError);
          }
          
          console.log(`Payment verified for ${paymentProvider} order ${order.orderNumber || order._id}`);
        }
        break;

      case 'failed':
      case 'failure':
        order.status = 'Payment Failed';
        order.paymentFailureReason = paymentDetails.paymentMessage || paymentDetails.error_description || 'Payment failed';
        await order.save();
        
        try {
          const customerId = order.customer?._id || order.customer;
          if (customerId) {
            await createNotificationAndPush({
              userId: customerId.toString(),
              type: 'order-status',
              message: `Payment failed for order ${order.orderNumber || order._id}. Please try again.`,
              meta: { orderId: order._id.toString() },
            });
          }
        } catch (notifError) {
          console.error('Failed to create notification:', notifError);
        }
        
        console.log(`Payment failed for ${paymentProvider} order ${order.orderNumber || order._id}`);
        break;

      case 'pending':
      case 'processing':
        if (order.status === 'Payment Pending') {
          order.status = 'Payment Processing';
          await order.save();
        }
        break;

      default:
        console.log('Unhandled payment status:', paymentStatus);
    }

    return NextResponse.json({ 
      success: true, 
      message: 'Webhook processed',
      orderId: orderId,
      status: paymentStatus,
      provider: paymentProvider,
    });

  } catch (error) {
    console.error('Webhook processing error:', error);
    return NextResponse.json(
      { error: 'Webhook processing failed' },
      { status: 500 }
    );
  }
}

// Verify Cashfree webhook signature
function verifyWebhookSignature(
  payload: string,
  signature: string,
  secretKey: string
): boolean {
  try {
    const expectedSignature = crypto
      .createHmac('sha256', secretKey)
      .update(payload)
      .digest('base64');

    const signatureBuffer = Buffer.from(signature, 'utf8');
    const expectedBuffer = Buffer.from(expectedSignature, 'utf8');

    if (signatureBuffer.length !== expectedBuffer.length) {
      return false;
    }

    return crypto.timingSafeEqual(signatureBuffer, expectedBuffer);
  } catch (error) {
    console.error('Signature verification error:', error);
    return false;
  }
}

// Verify Razorpay webhook signature
function verifyRazorpaySignature(
  payload: string,
  signature: string,
  secretKey: string
): boolean {
  try {
    const expectedSignature = crypto
      .createHmac('sha256', secretKey)
      .update(payload)
      .digest('hex');

    return signature === expectedSignature;
  } catch (error) {
    console.error('Razorpay signature verification error:', error);
    return false;
  }
}

