import { NextRequest, NextResponse } from 'next/server';
import bcrypt from 'bcryptjs';
import dbConnect from '@/lib/mongodb';
import User from '@/models/User';
import Token from '@/models/Token';
import Coupon from '@/models/Coupon';
import BusinessSettings from '@/models/BusinessSettings';
import { generateUniqueReferralCode, generateCouponCode, generateUniqueCustomerId } from '@/lib/referral';
import { verifyFirebaseIdToken } from '@/lib/firebaseAdmin';

export async function POST(request: NextRequest) {
  try {
    await dbConnect();

    const { name, email, mobile, password, passwordHint, invitationCode, registerToken, firebaseIdToken } = await request.json();

    const normalizedEmail = typeof email === 'string' ? email.trim().toLowerCase() : '';
    const normalizedMobile = typeof mobile === 'string' ? mobile.trim().replace(/^\+91/, '').replace(/\D/g, '') : '';

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    const mobileRegex = /^[6-9]\d{9}$/;

    if (!name || !normalizedEmail || !password || !passwordHint) {
      return NextResponse.json({ error: 'Name, email, password, and password hint are required' }, { status: 400 });
    }

    if (!emailRegex.test(normalizedEmail)) {
      return NextResponse.json({ error: 'Invalid email address' }, { status: 400 });
    }

    if (normalizedMobile && !mobileRegex.test(normalizedMobile)) {
      return NextResponse.json({ error: 'Invalid mobile number' }, { status: 400 });
    }

    if (firebaseIdToken) {
      try {
        const decodedToken = await verifyFirebaseIdToken(firebaseIdToken);
        const tokenPhone = typeof decodedToken.phone_number === 'string' ? decodedToken.phone_number.replace(/^\+/, '') : '';
        const normalizedTokenPhone = tokenPhone.startsWith('91') ? tokenPhone.slice(2) : tokenPhone;
        if (normalizedMobile && normalizedTokenPhone !== normalizedMobile) {
          return NextResponse.json({ error: 'Firebase phone number does not match the provided mobile number' }, { status: 400 });
        }
      } catch (err) {
        console.error('Firebase ID token verification failed:', err);
        return NextResponse.json({ error: 'Invalid Firebase phone verification token' }, { status: 400 });
      }
    } else if (registerToken) {
      const registerInfo = await Token.findOne({ token: registerToken, type: 'register' });
      if (!registerInfo || registerInfo.email !== normalizedEmail || registerInfo.expiresAt < new Date()) {
        return NextResponse.json({ error: 'Invalid or expired registration token. Please verify your OTP again.' }, { status: 400 });
      }
    } else {
      return NextResponse.json({ error: 'Firebase verification token or register token is required' }, { status: 400 });
    }

    const existingUser = await User.findOne({
      $or: [{ email: normalizedEmail }, ...(normalizedMobile ? [{ mobile: normalizedMobile }] : [])],
    });

    if (existingUser) {
      return NextResponse.json({ error: 'User already exists' }, { status: 400 });
    }

    // Get business settings for referral bonus amounts
    const settings = await BusinessSettings.findOne();
    const referralEnabled = settings?.referralEnabled ?? true;
    const referralCouponAmount = settings?.referralCouponAmount || 100;
    const referralCouponDays = settings?.referralCouponDays || 30;
    const referralCouponUsageLimit = settings?.referralCouponUsageLimit || 1;
    const inviteeDiscountAmount = settings?.inviteeDiscountAmount || 50;
    const inviteeDiscountDays = settings?.inviteeDiscountDays || 30;
    const inviteeDiscountUsageLimit = settings?.inviteeDiscountUsageLimit || 1;

    // Handle invitation code if provided (only if referral program is enabled)
    let referredBy = null;
    let referrer = null;
    if (invitationCode && referralEnabled) {
      referrer = await User.findOne({ referralCode: invitationCode.toUpperCase() });
      if (referrer) {
        referredBy = referrer._id;
      }
    }

    // Generate unique referral code for new user using name and email/mobile
    const referralCode = await generateUniqueReferralCode(name, normalizedMobile || normalizedEmail);

    const hashedPassword = await bcrypt.hash(password, 12);

    const customerId = await generateUniqueCustomerId();

    const user = new User({
      name,
      email: normalizedEmail,
      mobile: normalizedMobile,
      password: hashedPassword,
      passwordHint,
      referralCode,
      referredBy,
      customerId,
    });

    await user.save();
    
    // Clean up registration tokens
    if (registerToken) {
      const tokenQuery: any = {
        type: 'register',
        email: normalizedEmail,
      };
      await Token.deleteMany(tokenQuery);
    }

    // If referred and referral program is enabled, create coupons for both inviter and invitee
    let inviteeCouponCode = null;
    let inviteeCouponAmount = null;
    if (referrer && referralEnabled) {
      const today = new Date();
      const referrerExpirationDate = new Date(today.getTime() + referralCouponDays * 24 * 60 * 60 * 1000);
      const inviteeExpirationDate = new Date(today.getTime() + inviteeDiscountDays * 24 * 60 * 60 * 1000);

      // Coupon for the one who invited (referrer)
      const referrerCouponCode = generateCouponCode();
      const referrerCoupon = new Coupon({
        code: referrerCouponCode,
        discountType: 'fixed',
        discountValue: referralCouponAmount,
        user: referrer._id,
        type: 'referral',
        expirationDays: referralCouponDays,
        expirationDate: referrerExpirationDate,
        usageLimit: referralCouponUsageLimit,
      });
      await referrerCoupon.save();

      // Coupon for the new user (invitee)
      inviteeCouponCode = generateCouponCode();
      inviteeCouponAmount = inviteeDiscountAmount;
      const inviteeCoupon = new Coupon({
        code: inviteeCouponCode,
        discountType: 'fixed',
        discountValue: inviteeDiscountAmount,
        user: user._id,
        type: 'referral',
        expirationDays: inviteeDiscountDays,
        expirationDate: inviteeExpirationDate,
        usageLimit: inviteeDiscountUsageLimit,
      });
      await inviteeCoupon.save();
    }

    return NextResponse.json({
      message: 'User registered successfully',
      referralCode,
      inviteeCouponCode,
      inviteeCouponAmount,
      inviteeDiscountReceived: !!inviteeCouponCode,
    }, { status: 201 });
  } catch (error) {
    console.error('Registration error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/auth';
import dbConnect from '@/lib/mongodb';
import Order from '@/models/Order';
import Product from '@/models/Product';
import Review from '@/models/Review';

const sanitizeComment = (value: string) => {
  return String(value || '').trim().replace(/<[^>]*>/g, '');
};

const sanitizeReply = (value: string) => {
  return String(value || '').trim().replace(/<[^>]*>/g, '');
};

export async function GET(request: NextRequest) {
  const session = await getServerSession(authOptions);
  const productId = request.nextUrl.searchParams.get('productId');
  const adminRequest = request.nextUrl.searchParams.get('admin');

  await dbConnect();

  if (!productId && !(session && (session.user.role === 'admin' || session.user.role === 'staff'))) {
    return NextResponse.json({ error: 'productId is required' }, { status: 400 });
  }

  const query: any = {};
  if (productId) {
    query.product = productId;
  }

  if (!adminRequest || adminRequest !== 'true') {
    if (!productId) {
      return NextResponse.json({ error: 'productId is required' }, { status: 400 });
    }
  }

  try {
    const reviews = await Review.find(query)
      .sort({ createdAt: -1 })
      .populate('user', 'name')
      .populate('product', 'name')
      .populate('replyBy', 'name');

    const totalReviews = reviews.length;
    const averageRating = totalReviews > 0 ? Number((reviews.reduce((sum, review) => sum + (review.rating || 0), 0) / totalReviews).toFixed(2)) : 0;

    let canReview = false;
    let hasReviewed = false;

    if (session?.user?.id && productId) {
      const existingReview = await Review.findOne({ user: session.user.id, product: productId });
      hasReviewed = !!existingReview;

      if (!hasReviewed) {
        const deliveredOrder = await Order.findOne({
          customer: session.user.id,
          status: 'Delivered',
          'products.product': productId,
        });
        canReview = !!deliveredOrder;
      }
    }

    return NextResponse.json({
      reviews,
      totalReviews,
      averageRating,
      canReview,
      hasReviewed,
    }, { status: 200 });
  } catch (error) {
    console.error('GET /api/reviews error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

export async function POST(request: NextRequest) {
  const session = await getServerSession(authOptions);
  if (!session?.user?.id || session.user.role !== 'customer') {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const body = await request.json();
  const productId = String(body.productId || '').trim();
  const rating = Number(body.rating);
  const comment = sanitizeComment(body.comment);

  if (!productId) {
    return NextResponse.json({ error: 'Product ID is required' }, { status: 400 });
  }

  if (!rating || rating < 1 || rating > 5) {
    return NextResponse.json({ error: 'Rating must be between 1 and 5' }, { status: 400 });
  }

  if (!comment || comment.length < 10 || comment.length > 1000) {
    return NextResponse.json({ error: 'Comment must be between 10 and 1000 characters' }, { status: 400 });
  }

  await dbConnect();

  try {
    const product = await Product.findById(productId);
    if (!product) {
      return NextResponse.json({ error: 'Product not found' }, { status: 404 });
    }

    const deliveredOrder = await Order.findOne({
      customer: session.user.id,
      status: 'Delivered',
      'products.product': productId,
    });

    if (!deliveredOrder) {
      return NextResponse.json({ error: 'Review allowed only after you receive a delivered product' }, { status: 403 });
    }

    const existingReview = await Review.findOne({ user: session.user.id, product: productId });
    if (existingReview) {
      return NextResponse.json({ error: 'You have already reviewed this product' }, { status: 400 });
    }

    const review = await Review.create({
      user: session.user.id,
      product: productId,
      rating,
      comment,
    });

    return NextResponse.json({ message: 'Review submitted successfully', review }, { status: 201 });
  } catch (error: unknown) {
    console.error('POST /api/reviews error:', error);
    if (error instanceof Error && error.message.includes('duplicate key')) {
      return NextResponse.json({ error: 'You have already reviewed this product' }, { status: 400 });
    }
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

export async function PATCH(request: NextRequest) {
  const session = await getServerSession(authOptions);
  if (!session?.user?.id || (session.user.role !== 'admin' && session.user.role !== 'staff')) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const reviewId = request.nextUrl.searchParams.get('id');
  if (!reviewId) {
    return NextResponse.json({ error: 'Review ID is required' }, { status: 400 });
  }

  const body = await request.json();
  const reply = sanitizeReply(body.reply || '');

  if (reply.length > 1000) {
    return NextResponse.json({ error: 'Reply must be 1000 characters or fewer' }, { status: 400 });
  }

  await dbConnect();

  try {
    const updateData: any = {};
    if (reply) {
      updateData.reply = reply;
      updateData.replyAt = new Date();
      updateData.replyBy = session.user.id;
    } else {
      updateData.$unset = { reply: '', replyAt: '', replyBy: '' };
    }

    const review = await Review.findByIdAndUpdate(reviewId, updateData, { new: true })
      .populate('user', 'name')
      .populate('product', 'name')
      .populate('replyBy', 'name');

    if (!review) {
      return NextResponse.json({ error: 'Review not found' }, { status: 404 });
    }

    return NextResponse.json({ message: 'Reply saved successfully', review }, { status: 200 });
  } catch (error) {
    console.error('PATCH /api/reviews error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

export async function DELETE(request: NextRequest) {
  const session = await getServerSession(authOptions);
  if (!session?.user?.id || (session.user.role !== 'admin' && session.user.role !== 'staff')) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const reviewId = request.nextUrl.searchParams.get('id');
  if (!reviewId) {
    return NextResponse.json({ error: 'Review ID is required' }, { status: 400 });
  }

  await dbConnect();

  try {
    const review = await Review.findByIdAndDelete(reviewId);
    if (!review) {
      return NextResponse.json({ error: 'Review not found' }, { status: 404 });
    }
    return NextResponse.json({ message: 'Review deleted successfully' }, { status: 200 });
  } catch (error) {
    console.error('DELETE /api/reviews error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/auth';
import mongoose from 'mongoose';
import connectDB from '../../../lib/mongodb';
import Order from '../../../models/Order';
import Shipment from '../../../models/Shipment';
import CourierPartner from '../../../models/CourierPartner';
import { createShipmentForOrder } from '../../../lib/shipmentHelper';

export async function GET(request: NextRequest) {
  try {
    const session = await getServerSession(authOptions);
    if (!session || session.user.role !== 'admin') {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    await connectDB();

    const { searchParams } = new URL(request.url);
    const status = searchParams.get('status');
    const courier = searchParams.get('courier');
    const limit = parseInt(searchParams.get('limit') || '50');
    const skip = parseInt(searchParams.get('skip') || '0');

    const query: any = {};
    if (status) query.status = status;
    if (courier) query.courierCode = courier;

    const shipments = await Shipment.find(query)
      .populate('order')
      .populate('courierPartner')
      .sort({ createdAt: -1 })
      .limit(limit)
      .skip(skip);

    const total = await Shipment.countDocuments(query);

    return NextResponse.json({
      shipments,
      total,
      pagination: {
        limit,
        skip,
        hasMore: skip + limit < total
      }
    });

  } catch (error) {
    console.error('Error fetching shipments:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

export async function POST(request: NextRequest) {
  try {
    const session = await getServerSession(authOptions);
    if (!session || session.user.role !== 'admin') {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    await connectDB();

    const body = await request.json();
    const { orderId, priority = 'balance', manualCourierId } = body;

    if (!orderId || typeof orderId !== 'string') {
      return NextResponse.json({ error: 'Order ID is required' }, { status: 400 });
    }

    // Find by ObjectId or orderNumber to support both admin input methods
    let order = null;
    if (mongoose.Types.ObjectId.isValid(orderId)) {
      order = await Order.findById(orderId).populate('customer');
    }

    if (!order) {
      order = await Order.findOne({ orderNumber: orderId }).populate('customer');
    }

    if (!order) {
      return NextResponse.json({ error: 'Order not found' }, { status: 404 });
    }

    // Check if shipment already exists
    const existingShipment = await Shipment.findOne({ order: order._id });
    if (existingShipment) {
      return NextResponse.json({ error: 'Shipment already exists for this order' }, { status: 400 });
    }

    // Create shipment with courier
    const shipment = await createShipmentForOrder(order, { priority, manualCourierId });

    return NextResponse.json({
      shipment,
      message: 'Shipment created successfully'
    });

  } catch (error) {
    console.error('Error creating shipment:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/auth';
import dbConnect from '@/lib/mongodb';
import mongoose from 'mongoose';

export const runtime = 'nodejs';

export async function GET(request: NextRequest): Promise<NextResponse> {
  try {
    const session = await getServerSession(authOptions);

    if (!session || (session.user.role !== 'admin' && session.user.role !== 'staff')) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    await dbConnect();
    const db = mongoose.connection.db;
    if (!db) {
      console.error('storage-status: mongoose.connection.db is undefined');
      return NextResponse.json({ error: 'Database not connected' }, { status: 500 });
    }
    const filesColl = db.collection('uploads.files');
    const chunksColl = db.collection('uploads.chunks');

    // Get storage stats
    const filesStats = await filesColl.aggregate([
      {
        $group: {
          _id: null,
          totalSize: { $sum: '$length' },
          totalFiles: { $sum: 1 },
          avgSize: { $avg: '$length' }
        }
      }
    ]).toArray();

    const chunksStats = await chunksColl.aggregate([
      {
        $group: {
          _id: null,
          totalChunks: { $sum: 1 },
          totalChunkSize: { $sum: '$data' } // Approximate
        }
      }
    ]).toArray();

    const fileStats = filesStats[0] || { totalSize: 0, totalFiles: 0, avgSize: 0 };
    const chunkStats = chunksStats[0] || { totalChunks: 0 };

    // Get breakdown by type
    const typeBreakdown = await filesColl.aggregate([
      {
        $group: {
          _id: {
            type: {
              $cond: [
                { $regexMatch: { input: '$contentType', regex: '^image' } },
                'image',
                {
                  $cond: [
                    { $regexMatch: { input: '$contentType', regex: '^video' } },
                    'video',
                    {
                      $cond: [
                        { $regexMatch: { input: '$contentType', regex: '^audio' } },
                        'audio',
                        'other'
                      ]
                    }
                  ]
                }
              ]
            }
          },
          count: { $sum: 1 },
          size: { $sum: '$length' }
        }
      },
      { $sort: { size: -1 } }
    ]).toArray();

    // Get orphaned chunks count
    const pipeline = [
      {
        $group: {
          _id: '$files_id'
        }
      }
    ];
    const fileIds = await chunksColl.aggregate(pipeline).toArray();
    const validFileIds = new Set(fileIds.map(doc => doc._id.toString()));
    
    const allChunks = await chunksColl.find({}).toArray();
    const orphanedCount = allChunks.filter(c => !validFileIds.has(c.files_id.toString())).length;

    // Get old files count
    const cutoff6h = new Date(Date.now() - 6 * 60 * 60 * 1000);
    const oldChunkFiles = await filesColl.countDocuments({
      'metadata.isChunk': true,
      uploadDate: { $lt: cutoff6h }
    });

    const cutoff90d = new Date(Date.now() - 90 * 24 * 60 * 60 * 1000);
    const veryOldFiles = await filesColl.countDocuments({
      uploadDate: { $lt: cutoff90d },
      'metadata.isChunk': { $ne: true }
    });

    const totalSizeMB = (fileStats.totalSize / (1024 * 1024)).toFixed(2);
    const usagePercent = ((fileStats.totalSize / (512 * 1024 * 1024)) * 100).toFixed(2);
    
    // Alert threshold (>80% usage)
    const isAlert = parseFloat(usagePercent) > 80;
    const isCritical = parseFloat(usagePercent) > 95;

    return NextResponse.json({
      status: isCritical ? 'critical' : isAlert ? 'warning' : 'ok',
      storage: {
        usedMB: parseFloat(totalSizeMB),
        limitMB: 512,
        usagePercent: parseFloat(usagePercent),
        totalFiles: fileStats.totalFiles,
        avgFileSizeMB: (fileStats.avgSize / (1024 * 1024)).toFixed(2)
      },
      breakdown: {
        byType: typeBreakdown.map((t: any) => ({
          type: t._id.type,
          count: t.count,
          sizeMB: (t.size / (1024 * 1024)).toFixed(2)
        })),
        totalChunks: chunkStats.totalChunks,
        orphanedChunks: orphanedCount,
        incompleteUploads: oldChunkFiles,
        filesOlderThan90Days: veryOldFiles
      },
      cleanup: {
        canCleanupOrphaned: orphanedCount > 0,
        canCleanupIncomplete: oldChunkFiles > 0,
        canCleanupOld: veryOldFiles > 0,
        estimatedSpaceFreeable: 'Run emergency-cleanup.js to estimate'
      },
      recommendations: isCritical ? [
        '🚨 CRITICAL: Storage is 95%+ full. Uploads will fail soon.',
        'Run: node scripts/emergency-cleanup.js --aggressive',
        'Or upgrade cluster tier immediately'
      ] : isAlert ? [
        '⚠️ WARNING: Storage is 80%+ full.',
        'Run: node scripts/emergency-cleanup.js',
        'Consider upgrading cluster tier'
      ] : []
    });
  } catch (error) {
    console.error('Storage status error:', error);
    return NextResponse.json({ error: 'Failed to get storage status' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/auth';
import dbConnect from '@/lib/mongodb';
import mongoose from 'mongoose';

export const runtime = 'nodejs';

function getGridFSBucket() {
  const db = mongoose.connection.db;
  if (!db) {
    throw new Error('MongoDB connection is not initialized');
  }
  return new mongoose.mongo.GridFSBucket(db, { bucketName: 'uploads' });
}

export async function GET(request: NextRequest): Promise<NextResponse> {
  try {
    const session = await getServerSession(authOptions);

    if (!session || (session.user.role !== 'admin' && session.user.role !== 'staff')) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    await dbConnect();

    const bucket = getGridFSBucket();
    const url = new URL(request.url);
    const typeFilter = url.searchParams.get('type') || 'all';
    const folderFilter = url.searchParams.get('folder') || '';
    const search = url.searchParams.get('search') || '';
    const page = parseInt(url.searchParams.get('page') || '1');
    const limit = parseInt(url.searchParams.get('limit') || '50');

    // Build query - exclude chunk files
    const query: any = {
      'metadata.isChunk': { $ne: true },
    };

    if (typeFilter === 'image') {
      query.contentType = { $regex: /^image/ };
    } else if (typeFilter === 'video') {
      query.contentType = { $regex: /^video/ };
    } else if (typeFilter === 'audio') {
      query.contentType = { $regex: /^audio/ };
    }

    if (folderFilter) {
      query['metadata.folder'] = folderFilter;
    }

    if (search) {
      query.$or = [
        { filename: { $regex: search, $options: 'i' } },
        { 'metadata.originalName': { $regex: search, $options: 'i' } },
      ];
    }

    // Get total count using find and count
    const allFiles = await bucket.find(query).toArray();
    const total = allFiles.length;

    const files = await bucket
      .find(query)
      .sort({ uploadDate: -1 })
      .skip((page - 1) * limit)
      .limit(limit)
      .toArray();

    const filesWithUrl = files.map((file: any) => ({
      _id: file._id,
      filename: file.filename,
      length: file.length,
      contentType: file.contentType,
      uploadDate: file.uploadDate,
      metadata: file.metadata,
      url: `/api/upload?file=${encodeURIComponent(file.filename)}`,
    }));

    return NextResponse.json({
      files: filesWithUrl,
      pagination: {
        total,
        page,
        limit,
        totalPages: Math.ceil(total / limit),
        hasMore: page * limit < total,
      },
    });
  } catch (error) {
    console.error('List files error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

export async function DELETE(request: NextRequest): Promise<NextResponse> {
  try {
    const session = await getServerSession(authOptions);

    if (!session || (session.user.role !== 'admin' && session.user.role !== 'staff')) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    await dbConnect();

    const url = new URL(request.url);
    const fileName = url.searchParams.get('file');

    if (!fileName) {
      return NextResponse.json({ error: 'Missing file parameter' }, { status: 400 });
    }

    const bucket = getGridFSBucket();
    const files = await bucket
      .find({
        $or: [
          { filename: fileName },
          { 'metadata.originalName': fileName },
        ],
      })
      .toArray();

    if (!files || files.length === 0) {
      return NextResponse.json({ error: 'File not found' }, { status: 404 });
    }

    // Delete all matching files
    for (const file of files) {
      await bucket.delete(file._id);
    }

    return NextResponse.json({ message: 'File deleted successfully' });
  } catch (error) {
    console.error('Delete file error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/auth';
import dbConnect from '@/lib/mongodb';
import mongoose from 'mongoose';
import path from 'path';

export const runtime = 'nodejs';

const ALLOWED_IMAGE_TYPES = ['image/png', 'image/jpeg', 'image/jpg', 'image/gif', 'image/webp'];
const ALLOWED_VIDEO_TYPES = ['video/mp4', 'video/quicktime', 'video/x-msvideo', 'video/webm', 'video/x-matroska', 'video/mkv', 'video/3gpp', 'video/3gp'];
const ALLOWED_AUDIO_TYPES = ['audio/webm', 'audio/mpeg', 'audio/ogg', 'audio/wav'];
const MAX_IMAGE_SIZE = 5 * 1024 * 1024; // 5MB
const MAX_VIDEO_SIZE = 100 * 1024 * 1024; // 100MB
const MAX_AUDIO_SIZE = 25 * 1024 * 1024; // 25MB

const MIME_BY_EXTENSION: Record<string, string> = {
  png: 'image/png',
  jpg: 'image/jpeg',
  jpeg: 'image/jpeg',
  gif: 'image/gif',
  webp: 'image/webp',
  mp4: 'video/mp4',
  mov: 'video/quicktime',
  avi: 'video/x-msvideo',
  webm: 'video/webm',
  mkv: 'video/x-matroska',
  '3gp': 'video/3gpp',
  mpeg: 'audio/mpeg',
  mp3: 'audio/mpeg',
  ogg: 'audio/ogg',
  wav: 'audio/wav',
};

function sanitizeFileName(fileName: string) {
  return fileName.replace(/[^a-zA-Z0-9._-]/g, '');
}

function getContentType(extension: string) {
  return MIME_BY_EXTENSION[extension.toLowerCase()] || 'application/octet-stream';
}

function getGridFSBucket() {
  const db = mongoose.connection.db;
  if (!db) {
    console.error('[UPLOAD] MongoDB connection.db is not available');
    throw new Error('MongoDB connection is not initialized');
  }
  console.log('[UPLOAD] Creating GridFSBucket for MongoDB');
  return new mongoose.mongo.GridFSBucket(db, { bucketName: 'uploads' });
}

export async function GET(request: NextRequest): Promise<NextResponse> {
  try {
    await dbConnect();

    const url = new URL(request.url);
    const fileName = sanitizeFileName(url.searchParams.get('file') || '');

    if (!fileName) {
      return NextResponse.json({ error: 'Missing file parameter' }, { status: 400 });
    }

    const bucket = getGridFSBucket();
    const files = await bucket
      .find({
        $or: [
          { filename: fileName },
          { 'metadata.originalName': fileName },
        ],
      })
      .toArray();
    if (!files || files.length === 0) {
      return NextResponse.json({ error: 'File not found' }, { status: 404 });
    }

    const fileDoc = files[0] as any;
    const downloadStream = bucket.openDownloadStream(fileDoc._id);
    const chunks: Buffer[] = [];

    for await (const chunk of downloadStream) {
      chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk));
    }

    const fileBuffer = Buffer.concat(chunks);
    const ext = path.extname(fileName).slice(1).toLowerCase();
    const contentType = fileDoc.metadata?.contentType || getContentType(ext);

    return new NextResponse(fileBuffer, {
      status: 200,
      headers: { 
        'Content-Type': contentType,
        'Cache-Control': 'public, max-age=31536000, immutable' // Cache for 1 year
      },
    });
  } catch (error) {
    console.error('Upload GET error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

export async function POST(request: NextRequest): Promise<NextResponse> {
  try {
    console.log('[UPLOAD] Starting POST request');

    const contentTypeHeader = request.headers.get('content-type') || '';
    const isMultipart = contentTypeHeader.startsWith('multipart/form-data');

    if (!isMultipart) {
      console.log('[UPLOAD] Invalid content type:', contentTypeHeader);
      return NextResponse.json({ error: 'Upload must use multipart/form-data' }, { status: 400 });
    }

    // Parse form data first before connecting to DB
    console.log('[UPLOAD] Parsing FormData...');
    const formData = await request.formData();
    const fileEntry = formData.get('file');
    const file = fileEntry instanceof File ? fileEntry : null;
    if (!file) {
      console.log('[UPLOAD] File entry type:', fileEntry?.constructor?.name, 'Is File?', fileEntry instanceof File);
      return NextResponse.json({ error: 'No file uploaded or invalid multipart form data' }, { status: 400 });
    }

    console.log('[UPLOAD] File received:', file.name, 'Size:', file.size, 'Type:', file.type);

    const originalName = formData.get('originalName')?.toString() || file.name || '';
    const contentType = file.type || getContentType(path.extname(originalName).slice(1).toLowerCase());
    const isImage = ALLOWED_IMAGE_TYPES.includes(contentType);

    console.log('[UPLOAD] Content type:', contentType, 'Is image:', isImage);

    // Check authentication (only for non-image uploads)
    const session = await getServerSession(authOptions);
    console.log('[UPLOAD] Session:', session ? 'authenticated' : 'not authenticated');
    
    if (!session && !isImage) {
      console.log('[UPLOAD] Rejecting: not authenticated and not image');
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    // Now connect to database for GridFS storage
    console.log('[UPLOAD] Connecting to database...');
    await dbConnect();
    console.log('[UPLOAD] Database connected');

    const uploadId = formData.get('uploadId')?.toString() || '';
    const chunkIndexRaw = formData.get('chunkIndex');
    const totalChunksRaw = formData.get('totalChunks');
    const chunkIndex = chunkIndexRaw !== null ? Number(chunkIndexRaw.toString()) : undefined;
    const totalChunks = totalChunksRaw !== null ? Number(totalChunksRaw.toString()) : undefined;

    const isVideo = ALLOWED_VIDEO_TYPES.includes(contentType);
    const isAudio = ALLOWED_AUDIO_TYPES.includes(contentType);

    console.log('[UPLOAD] Is video:', isVideo, 'Is audio:', isAudio);

    if (!isVideo && !isImage && !isAudio) {
      console.log('[UPLOAD] Invalid file type:', contentType);
      return NextResponse.json({ error: 'Invalid file type. Allowed: PNG, JPEG, GIF, WEBP, MP4, MOV, AVI, WEBM, MKV, 3GP, WEBM audio, MP3, OGG, WAV' }, { status: 400 });
    }

    const arrayBuffer = await file.arrayBuffer();
    const buffer = Buffer.from(arrayBuffer);
    const maxSize = isVideo ? MAX_VIDEO_SIZE : isAudio ? MAX_AUDIO_SIZE : MAX_IMAGE_SIZE;
    if (buffer.length > maxSize) {
      const maxMB = isVideo ? 100 : isAudio ? 25 : 5;
      console.log('[UPLOAD] File too large:', buffer.length, 'Max:', maxSize);
      return NextResponse.json({ error: `File too large. Max ${maxMB}MB allowed` }, { status: 400 });
    }

    const ext = (() => {
      let fileExt = contentType.split('/').pop() || 'bin';
      if (fileExt === 'quicktime') fileExt = 'mov';
      if (fileExt === 'x-msvideo') fileExt = 'avi';
      if (fileExt === 'mpeg') fileExt = 'mp3';
      return fileExt;
    })();

    console.log('[UPLOAD] File extension:', ext);

    const bucket = getGridFSBucket();
    console.log('[UPLOAD] GridFS bucket created');

    if (typeof chunkIndex === 'number' && !Number.isNaN(chunkIndex) && typeof totalChunks === 'number' && !Number.isNaN(totalChunks) && totalChunks > 1) {
      const chunkFileName = `${uploadId}-chunk-${chunkIndex}`;
      await new Promise<void>((resolve, reject) => {
        const uploadStream = bucket.openUploadStream(chunkFileName, {
          metadata: {
            originalName,
            contentType,
            uploadId,
            chunkIndex,
            totalChunks,
            isChunk: true,
          },
        });
        uploadStream.on('error', (err) => reject(err));
        uploadStream.on('finish', () => resolve());
        uploadStream.end(buffer);
      });

      if (chunkIndex < totalChunks - 1) {
        return NextResponse.json({ uploadId, chunkIndex, totalChunks, message: 'Chunk uploaded' }, { status: 200 });
      }

      const chunkFiles = await bucket
        .find({ 'metadata.uploadId': uploadId, 'metadata.isChunk': true })
        .sort({ 'metadata.chunkIndex': 1 })
        .toArray();

      if (!chunkFiles || chunkFiles.length !== totalChunks) {
        return NextResponse.json({ error: 'Uploaded chunks are missing or incomplete' }, { status: 400 });
      }

      const finalFileName = `${Date.now()}-${Math.random().toString(36).slice(2, 8)}.${ext}`;
      await new Promise<void>(async (resolve, reject) => {
        const uploadStream = bucket.openUploadStream(finalFileName, {
          metadata: { originalName, contentType, uploadId, isChunkedFile: true },
        });

        uploadStream.on('error', (err) => reject(err));
        uploadStream.on('finish', () => resolve());

        try {
          for (const chunkFile of chunkFiles) {
            const downloadStream = bucket.openDownloadStream(chunkFile._id);
            for await (const chunk of downloadStream) {
              uploadStream.write(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk));
            }
            await bucket.delete(chunkFile._id);
          }
          uploadStream.end();
        } catch (error) {
          reject(error);
        }
      });

      return NextResponse.json({ url: `/api/upload?file=${encodeURIComponent(finalFileName)}` }, { status: 200 });
    }

    const folder = formData.get('folder')?.toString() || undefined;
    const finalFileName = `${Date.now()}-${Math.random().toString(36).slice(2, 8)}.${ext}`;
    await new Promise<void>((resolve, reject) => {
      const metadata: Record<string, any> = { originalName, contentType };
      if (folder) metadata.folder = folder;
      const uploadStream = bucket.openUploadStream(finalFileName, {
        metadata,
      });
      uploadStream.on('error', (err) => reject(err));
      uploadStream.on('finish', () => resolve());
      uploadStream.end(buffer);
    });

    return NextResponse.json({ url: `/api/upload?file=${encodeURIComponent(finalFileName)}` }, { status: 200 });
  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : String(error);
    console.error('[UPLOAD] POST error:', errorMessage);
    console.error('[UPLOAD] Stack:', error instanceof Error ? error.stack : '');
    
    // Check for MongoDB storage quota errors
    if (errorMessage.includes('space quota') || 
        errorMessage.includes('over your space quota') ||
        errorMessage.includes('Writes are blocked') ||
        errorMessage.includes('12561') || // MongoDB error code for storage exceeded
        errorMessage.includes('$err')) {
      return NextResponse.json({ 
        error: 'Storage quota exceeded', 
        details: 'MongoDB cluster has reached storage limit. Admin must delete old files or upgrade the cluster tier.',
        suggestions: [
          'Run: node scripts/emergency-cleanup.js',
          'Or upgrade cluster at: https://cloud.mongodb.com/v2/69d9108265a5889f54fd820d#/clusters',
          'Free up storage by deleting unnecessary media files'
        ]
      }, { status: 507 }); // 507 Insufficient Storage
    }
    
    return NextResponse.json({ error: 'Internal server error', details: errorMessage }, { status: 500 });
  }
}

export async function DELETE(request: NextRequest): Promise<NextResponse> {
  try {
    console.log('DELETE request received');

    const session = await getServerSession(authOptions);
    console.log('Session:', session ? 'authenticated' : 'not authenticated');

    if (!session || (session.user.role !== 'admin' && session.user.role !== 'staff')) {
      console.log('Unauthorized access attempt');
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    console.log('Connecting to database...');
    await dbConnect();
    console.log('Database connected');

    const url = new URL(request.url);
    const fileName = url.searchParams.get('file');
    console.log('File to delete:', fileName);

    if (!fileName) {
      console.log('Missing file parameter');
      return NextResponse.json({ error: 'Missing file parameter' }, { status: 400 });
    }

    console.log('Getting GridFS bucket...');
    const bucket = getGridFSBucket();
    console.log('GridFS bucket obtained');

    console.log('Searching for files...');
    const files = await bucket
      .find({
        $or: [
          { filename: fileName },
          { 'metadata.originalName': fileName },
        ],
      })
      .toArray();

    console.log('Files found:', files.length);

    if (!files || files.length === 0) {
      console.log('File not found');
      return NextResponse.json({ error: 'File not found' }, { status: 404 });
    }

    // Delete all matching files
    console.log('Deleting files...');
    for (const file of files) {
      console.log('Deleting file:', file._id);
      await bucket.delete(file._id);
    }

    console.log('File deletion successful');
    return NextResponse.json({ message: 'File deleted successfully' });
  } catch (error) {
    console.error('Delete file error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/auth';
import dbConnect from '@/lib/mongodb';
import Product from '@/models/Product';
import { resolveEndedAuction } from '@/lib/auctionHelper';

export async function GET() {
  try {
    const session = await getServerSession(authOptions);
    if (!session) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    await dbConnect();

    const products = await Product.find({
      $or: [
        { 'bargainOffers.user': session.user.id },
        { 'bids.user': session.user.id },
      ],
    }).select('name images bargainOffers bids');

    const offers: Array<any> = [];
    const bids: Array<any> = [];
    const now = new Date();

    for (const product of products) {
      await resolveEndedAuction(product);
      product.bargainOffers?.forEach((offer: any) => {
        if (offer.user?.toString() === session.user.id) {
          offers.push({
            productId: product._id,
            productName: product.name,
            productImage: product.images?.[0] || '',
            price: offer.price,
            status: offer.status,
            couponCode: offer.couponCode,
            reservedUntil: offer.reservedUntil,
            reservationExpired: offer.reservedUntil ? offer.reservedUntil <= now : false,
            createdAt: offer.createdAt,
            type: 'bargain',
          });
        }
      });
      product.bids?.forEach((bid: any) => {
        if (bid.user?.toString() === session.user.id) {
          bids.push({
            productId: product._id,
            productName: product.name,
            productImage: product.images?.[0] || '',
            price: bid.price,
            status: bid.status,
            couponCode: bid.couponCode,
            reservedUntil: bid.reservedUntil,
            reservationExpired: bid.reservedUntil ? bid.reservedUntil <= now : false,
            createdAt: bid.createdAt,
            type: 'bidding',
          });
        }
      });
    }

    return NextResponse.json({ offers, bids }, { status: 200 });
  } catch (error) {
    console.error('Error fetching market activity:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/auth';
import dbConnect from '@/lib/mongodb';
import User from '@/models/User';

export async function GET() {
  const session = await getServerSession(authOptions);
  if (!session) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  await dbConnect();
  const user = await User.findById(session.user.id).select('notificationPreferences');
  if (!user) {
    return NextResponse.json({ error: 'User not found' }, { status: 404 });
  }

  return NextResponse.json({ notificationPreferences: user.notificationPreferences || {} }, { status: 200 });
}

export async function PUT(request: NextRequest) {
  const session = await getServerSession(authOptions);
  if (!session) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  await dbConnect();
  const body = await request.json();
  const preferences = body.notificationPreferences;

  if (!preferences || typeof preferences !== 'object') {
    return NextResponse.json({ error: 'Notification preferences must be provided' }, { status: 400 });
  }

  const allowedKeys = ['orderUpdates', 'bargain', 'outbid', 'auction', 'adminMessages'];
  const updatePayload: any = {};

  Object.entries(preferences).forEach(([key, value]) => {
    if (allowedKeys.includes(key) && typeof value === 'boolean') {
      updatePayload[`notificationPreferences.${key}`] = value;
    }
  });

  if (Object.keys(updatePayload).length === 0) {
    return NextResponse.json({ error: 'No valid notification preferences provided' }, { status: 400 });
  }

  const user = await User.findByIdAndUpdate(session.user.id, { $set: updatePayload }, { new: true }).select('notificationPreferences');
  if (!user) {
    return NextResponse.json({ error: 'User not found' }, { status: 404 });
  }

  return NextResponse.json({ notificationPreferences: user.notificationPreferences || {}, message: 'Notification preferences updated' }, { status: 200 });
}

import { getServerSession } from 'next-auth';
import connectDB from '@/lib/mongodb';
import User from '@/models/User';

export async function GET(req: Request) {
  try {
    await connectDB();

    const { searchParams } = new URL(req.url);
    const userId = searchParams.get('userId');

    if (!userId) {
      return Response.json({ error: 'userId required' }, { status: 400 });
    }

    // Get user and their session info
    const user = await User.findById(userId).select('lastActive email name mobile customerId');
    
    if (!user) {
      return Response.json({ online: false }, { status: 200 });
    }

    // Check if user was active in the last 60 seconds
    const lastActiveTime = new Date(user.lastActive || 0);
    const now = new Date();
    const diffSeconds = (now.getTime() - lastActiveTime.getTime()) / 1000;
    
    const isOnline = diffSeconds <= 120; // Consider active if active in the last 2 minutes (120 seconds) for more reliable presence

    return Response.json({
      online: isOnline,
      user: {
        _id: user._id,
        name: user.name,
        email: user.email,
        mobile: user.mobile,
        customerId: user.customerId,
      },
    });
  } catch (err) {
    console.error('Error checking online status:', err);
    return Response.json({ error: 'Server error' }, { status: 500 });
  }
}

export async function POST(req: Request) {
  try {
    const session = await getServerSession();
    if (!session?.user?.email) {
      return Response.json({ error: 'Unauthorized' }, { status: 401 });
    }

    await connectDB();

    // Update user's lastActive timestamp
    const user = await User.findByIdAndUpdate(
      session.user.id,
      { lastActive: new Date() },
      { new: true }
    );

    return Response.json({ success: true, online: true });
  } catch (err) {
    console.error('Error updating online status:', err);
    return Response.json({ error: 'Server error' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/auth';
import * as bcrypt from 'bcryptjs';
import dbConnect from '@/lib/mongodb';
import User from '@/models/User';

export async function PUT(request: NextRequest, { params }: { params: Promise<{ id: string }> }) {
  const { id } = await params;
  try {
    const session = await getServerSession(authOptions);

    if (!session || session.user.role !== 'admin') {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    await dbConnect();

    const { password } = await request.json();

    if (!password) {
      return NextResponse.json({ error: 'Password is required' }, { status: 400 });
    }

    const user = await User.findById(id);
    if (!user) {
      return NextResponse.json({ error: 'User not found' }, { status: 404 });
    }

    if (user.adminEmail) {
      return NextResponse.json({ error: 'Default admin account cannot be modified' }, { status: 403 });
    }

    const hashedPassword = await bcrypt.hash(password, 12);
    await User.findByIdAndUpdate(id, { password: hashedPassword });

    if (!user) {
      return NextResponse.json({ error: 'User not found' }, { status: 404 });
    }

    return NextResponse.json({ message: 'Password reset successfully' }, { status: 200 });
  } catch (error) {
    console.error('User password reset failed:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

export async function PATCH(request: NextRequest, { params }: { params: Promise<{ id: string }> }) {
  const { id } = await params;
  try {
    const session = await getServerSession(authOptions);

    if (!session || session.user.role !== 'admin') {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    await dbConnect();

    const body: Record<string, unknown> = await request.json();
    const { blocked, role } = body;

    const user = await User.findById(id);

    if (!user) {
      return NextResponse.json({ error: 'User not found' }, { status: 404 });
    }

    if (user.adminEmail) {
      return NextResponse.json({ error: 'Default admin account cannot be modified' }, { status: 403 });
    }

    const updateData: { blocked?: boolean; name?: string; email?: string; mobile?: string; role?: string; importantConsumer?: boolean } = {};

    if (typeof blocked === 'boolean') {
      if (user.adminEmail) {
        return NextResponse.json({ error: 'Cannot block default admin account' }, { status: 400 });
      }
      updateData.blocked = blocked;
    }

    if (typeof role === 'string' && ['customer', 'staff', 'admin'].includes(role)) {
      if (user.adminEmail) {
        return NextResponse.json({ error: 'Cannot change role of default admin account' }, { status: 400 });
      }
      // allow main admin to demote secondary admins from admin -> staff/customer
      updateData.role = role;
    }

    if (typeof body.importantConsumer === 'boolean') {
      if (user.adminEmail) {
        return NextResponse.json({ error: 'Cannot update default admin account' }, { status: 400 });
      }
      updateData.importantConsumer = body.importantConsumer;
    }

    // Allow name/email/mobile/importantConsumer updates from admin.
    const { name, email, mobile, importantConsumer } = body as { name?: unknown; email?: unknown; mobile?: unknown; importantConsumer?: unknown };

    if (typeof name === 'string' && name.trim()) {
      updateData.name = name.trim();
    }

    if (typeof email === 'string' && email.trim()) {
      const normalizedEmail = email.trim().toLowerCase();
      if (normalizedEmail) {
        // Ensure uniqueness (excluding self)
        const existingByEmail = await User.findOne({ email: normalizedEmail, _id: { $ne: id } });
        if (existingByEmail) {
          return NextResponse.json({ error: 'Email is already in use' }, { status: 400 });
        }
        updateData.email = normalizedEmail;
      }
    }

    if (typeof mobile === 'string' && mobile.trim()) {
      const normalizedMobile = mobile.trim();
      const existingByMobile = await User.findOne({ mobile: normalizedMobile, _id: { $ne: id } });
      if (existingByMobile) {
        return NextResponse.json({ error: 'Mobile number is already in use' }, { status: 400 });
      }
      updateData.mobile = normalizedMobile;
    }

    if (Object.keys(updateData).length === 0) {
      return NextResponse.json({ error: 'No valid updates provided' }, { status: 400 });
    }

    await User.findByIdAndUpdate(id, updateData);

    return NextResponse.json({ message: 'User updated successfully' }, { status: 200 });
  } catch (error) {
    console.error('User update failed:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

export async function DELETE(request: NextRequest, { params }: { params: Promise<{ id: string }> }) {
  const { id } = await params;
  try {
    const session = await getServerSession(authOptions);

    if (!session || session.user.role !== 'admin') {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    await dbConnect();

    const user = await User.findById(id);

    if (!user) {
      return NextResponse.json({ error: 'User not found' }, { status: 404 });
    }

    if (user.adminEmail) {
      return NextResponse.json({ error: 'Default admin account cannot be deleted' }, { status: 403 });
    }

    if (user.role === 'admin') {
      return NextResponse.json({ error: 'Cannot delete admin' }, { status: 400 });
    }

    await User.findByIdAndDelete(id);

    return NextResponse.json({ message: 'User deleted' }, { status: 200 });
  } catch (error) {
    console.error('User deletion failed:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/auth';
import dbConnect from '@/lib/mongodb';
import Wishlist from '@/models/Wishlist';
import Product from '@/models/Product';

export async function GET(request: NextRequest) {
  const session = await getServerSession(authOptions);
  if (!session?.user?.id) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }
  await dbConnect();
  const wishlist = await Wishlist.findOne({ user: session.user.id }).populate('products');
  return NextResponse.json({ wishlist: wishlist || { products: [] } });
}

export async function POST(request: NextRequest) {
  const session = await getServerSession(authOptions);
  if (!session?.user?.id) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }
  const { productId } = await request.json();
  if (!productId) {
    return NextResponse.json({ error: 'Product ID required' }, { status: 400 });
  }
  await dbConnect();
  let wishlist = await Wishlist.findOne({ user: session.user.id });
  if (!wishlist) {
    wishlist = await Wishlist.create({ user: session.user.id, products: [productId] });
  } else {
    const exists = wishlist.products.some((p: any) => p.toString() === productId);
    if (!exists) {
      wishlist.products.push(productId);
      wishlist.updatedAt = new Date();
      await wishlist.save();
    }
  }
  return NextResponse.json({ success: true });
}

export async function DELETE(request: NextRequest) {
  const session = await getServerSession(authOptions);
  if (!session?.user?.id) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }
  const productId = request.nextUrl.searchParams.get('productId');
  if (!productId) {
    return NextResponse.json({ error: 'Product ID required' }, { status: 400 });
  }
  await dbConnect();
  const wishlist = await Wishlist.findOne({ user: session.user.id });
  if (wishlist) {
    const exists = wishlist.products.some((p: any) => p.toString() === productId);
    if (exists) {
      wishlist.products = wishlist.products.filter((id: any) => id.toString() !== productId);
      wishlist.updatedAt = new Date();
      await wishlist.save();
    }
  }
  return NextResponse.json({ success: true });
}

