  const [transactionId, setTransactionId] = useState('');
  const [uploadError, setUploadError] = useState('');
  const [placingOrder, setPlacingOrder] = useState(false);
  const [message, setMessage] = useState('');
  const [settings, setSettings] = useState<BusinessSettings>({});
  const [step, setStep] = useState(1); // 1=shipping, 2=payment, 3=password
  
  // Cashfree Payment State
  const [paymentMethod, setPaymentMethod] = useState<'cashfree' | 'razorpay' | 'manual'>('manual');
  const [cashfreeLoading, setCashfreeLoading] = useState(false);
  const [cashfreeError, setCashfreeError] = useState('');
  const [pendingOrderId, setPendingOrderId] = useState<string | null>(null);
  const [couponCode, setCouponCode] = useState('');
  const [appliedDiscount, setAppliedDiscount] = useState(0);
  const [couponError, setCouponError] = useState('');
  const [password, setPassword] = useState('');
  const [passwordError, setPasswordError] = useState('');
  const [passwordLoading, setPasswordLoading] = useState(false);
  const [orderPlaced, setOrderPlaced] = useState(false);
  const [stockMap, setStockMap] = useState<Record<string, number>>({});
  const [stockWarning, setStockWarning] = useState('');
  const [canPlaceOrder, setCanPlaceOrder] = useState(true);
  const [isHydrated, setIsHydrated] = useState(false);

  useEffect(() => {
    setIsHydrated(true);
  }, []);

  const getSupportWhatsapp = () => {
    if (settings.contactInfoEnabled === false) return '';
    if (settings.contactWhatsapp?.trim()) return settings.contactWhatsapp.trim();
    if (settings.staffWhatsapp?.trim()) return settings.staffWhatsapp.trim();
    if (settings.adminWhatsapp?.trim()) return settings.adminWhatsapp.trim();
    if (settings.whatsapp?.trim()) return settings.whatsapp.trim();
    return '';
  };

  const getSupportEmail = () => {
    if (settings.contactInfoEnabled === false) return '';
    if (settings.contactEmail?.trim()) return settings.contactEmail.trim();
    return '';
  };

  const [couponProducts, setCouponProducts] = useState<string[]>([]);
  const [stateSearch, setStateSearch] = useState('');
  const [discountType, setDiscountType] = useState<'percentage' | 'fixed'>('percentage');
  const [discountValue, setDiscountValue] = useState(0);

  const total = items.reduce((acc, item) => acc + item.price * item.quantity, 0);
  const gstTotal = items.reduce((acc, item) => {
    const gstPercent = item.gstPercent || 0;
    return acc + item.price * item.quantity * gstPercent / 100;
  }, 0);
  
  // Calculate eligible items total for product-specific coupons
  const eligibleTotal = couponProducts.length > 0 
    ? items.reduce((acc, item) => {
        if (couponProducts.includes(item.productId)) {
          return acc + item.price * item.quantity;
        }
        return acc;
      }, 0)
    : total;

  // Calculate shipping charges based on state
  const calculateShippingCharge = () => {
    const freeThreshold = settings.freeShippingThreshold || 0;
    if (freeThreshold > 0 && total >= freeThreshold) {
      return 0;
    }
    const stateCharges = settings.stateShippingCharges || {};
    const charge = stateCharges[state];
    if (charge !== undefined && charge !== null) {
      return charge;
    }
    return settings.defaultShippingCharge || 0;
  };

  const shippingCharges = state ? calculateShippingCharge() : 0;
  const subtotalAfterDiscount = total - appliedDiscount;
  const finalTotal = subtotalAfterDiscount + gstTotal + shippingCharges; // Include GST and shipping in final total
  const filteredStates = indianStates.filter(s => 
    s.toLowerCase().includes(stateSearch.toLowerCase())
  );

  useEffect(() => {
    fetch('/api/business-settings')
      .then(res => res.json())
      .then(data => setSettings(data));
  }, []);

  // If admin disables online payments, ensure paymentMethod falls back to manual
  useEffect(() => {
    if (settings && settings.onlinePaymentsEnabled === false && (paymentMethod === 'cashfree' || paymentMethod === 'razorpay')) {
      setPaymentMethod('manual');
    }
  }, [settings?.onlinePaymentsEnabled]);

  useEffect(() => {
    async function refreshCartStock() {
      if (items.length === 0) {
        setStockMap({});
        setStockWarning('');
        setCanPlaceOrder(true);
        return;
      }

      const uniqueIds = Array.from(new Set(items.map(item => item.productId)));
      const stockResults: Record<string, number> = {};
      const issues: string[] = [];

      await Promise.all(uniqueIds.map(async (productId) => {
        try {
          const res = await fetch(`/api/products/${productId}`);
          if (!res.ok) {
            stockResults[productId] = 0;
            return;
          }
          const product = await res.json();
          stockResults[productId] = Number(product.quantity) || 0;
        } catch (_) {
          stockResults[productId] = 0;
        }
      }));

      items.forEach(item => {
        const available = stockResults[item.productId] ?? 0;
        if (available <= 0) {
          issues.push(`${item.name} is out of stock.`);
        } else if (item.quantity > available) {
          issues.push(`${item.name} only has ${available} available.`);
        }
      });

      setStockMap(stockResults);
      setStockWarning(issues.join(' '));
      setCanPlaceOrder(issues.length === 0);
    }

    refreshCartStock();
  }, [items]);

  if (!isHydrated) {
    return <div className="flex items-center justify-center min-h-screen">Loading cart...</div>;
  }

  async function validateCoupon() {
    if (!couponCode.trim()) {
      setCouponError('Please enter a coupon code');
      return;
    }
    try {
      const productIds = items.map(item => item.productId);
      const cartItems = items.map(item => ({
        productId: item.productId,
        price: item.price,
        quantity: item.quantity
      }));
      const res = await fetch('/api/coupons/validate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ code: couponCode.trim(), total, productIds, cartItems }),
      });
      const data = await res.json();
      if (res.ok) {
        setAppliedDiscount(data.discount);
        setCouponProducts(data.couponProducts || []);
        setDiscountType(data.discountType || 'percentage');
        setDiscountValue(data.discountValue || 0);
        setCouponError('');
      } else {
        setAppliedDiscount(0);
        setCouponProducts([]);
        setDiscountType('percentage');
        setDiscountValue(0);
        setCouponError(data.error || 'Invalid coupon');
      }
    } catch (error) {
      console.error('Coupon validation failed:', error);
      setAppliedDiscount(0);
      setCouponError('Failed to validate coupon');
    }
  }

  async function loadRazorpayCheckoutScript() {
    if (typeof window === 'undefined') {
      return false;
    }

    if ((window as any).Razorpay) {
      return true;
    }

    return new Promise<boolean>((resolve) => {
      const script = document.createElement('script');
      script.src = 'https://checkout.razorpay.com/v1/checkout.js';
      script.onload = () => resolve(true);
      script.onerror = () => resolve(false);
      document.body.appendChild(script);
    });
  }

  async function handleRazorpayVerification(orderId: string, paymentId: string, razorpayOrderId: string, razorpaySignature: string) {
    const verifyResponse = await fetch('/api/verify-payment', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        orderId,
        razorpay_payment_id: paymentId,
        razorpay_order_id: razorpayOrderId,
        razorpay_signature: razorpaySignature,
      }),
    });
    return verifyResponse.json();
  }

  async function handleFileChange(e: React.ChangeEvent<HTMLInputElement>) {
    setUploadError('');
    const file = e.target.files?.[0];
    if (!file) return;
    const formData = new FormData();
    formData.append('file', file);

    try {
      const res = await fetch('/api/upload', { method: 'POST', body: formData, credentials: 'include' });
      const data = await res.json();
      if (data.url) {
        setPaymentScreenshot(data.url);
      } else {
        setUploadError(data.error || 'Upload failed');
      }
    } catch (error) {
      console.error('File upload failed:', error);
      setUploadError('Upload failed');
    }
  }

  async function verifyPasswordAndPlaceOrder() {
    if (!password.trim()) {
      setPasswordError('Please enter your account password to verify');
      return;
    }

    setPasswordLoading(true);
    setPasswordError('');
    setMessage('');

    try {
      const res = await fetch('/api/auth/verify-password', {
        method: 'POST',
        credentials: 'include',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ password: password.trim() }),
      });

      const data = await res.json();

      if (!res.ok || !data.verified) {
        setPasswordError(data.error || 'Password verification failed');
      } else {
        await finalizePlaceOrder();
      }
    } catch (error) {
      console.error('Password verification request failed:', error);
      setPasswordError('Verification request failed. Please try again.');
    } finally {
      setPasswordLoading(false);
    }
  }

  async function finalizePlaceOrder() {
    setPlacingOrder(true);
    setMessage('');

    try {
      const res = await fetch('/api/orders', {
        method: 'POST',
        credentials: 'include',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          cart: items,
          name,
          email,
          address,
          city,
          state,
          postalCode,
          country,
          mobile,
          paymentScreenshot,
          transactionId,
          discountCoupon: couponCode.trim() || undefined,
          discountAmount: appliedDiscount,
          shippingCharges,
          shippingState: state,
        }),
      });

      const data = await res.json();
      if (res.ok) {
        clear();
        setMessage('Order placed successfully!');
        setStep(1);
        setPassword('');
        setPasswordError('');
        // reset payment fields
        setPaymentScreenshot('');
        setTransactionId('');
        setCouponCode('');
        setAppliedDiscount(0);
        setCouponProducts([]);
        setDiscountType('percentage');
        setDiscountValue(0);
        setState('');
        // Refresh products to show updated quantities
        window.dispatchEvent(new Event('productsUpdated'));

        const customerId = session?.user?.customerId || '';
        router.push(`/order-success?orderId=${data._id}&customerId=${encodeURIComponent(customerId)}`);
        return;
      } else {
        setMessage(data.error || data.message || 'Failed to place order');
      }
    } catch (error) {
      console.error('Place order failed:', error);
      setMessage('Failed to place order');
    } finally {
      setPlacingOrder(false);
    }
  }

  // Cashfree Online Payment Function
  async function initiateCashfreePayment() {
    if (!session) {
      router.push('/login');
      return;
    }

    if (settings.onlinePaymentsEnabled === false) {
      setCashfreeError('Online payments are currently disabled. Please use Bank Transfer.');
      return;
    }

    if (items.length === 0) {
      setCashfreeError('Cart is empty');
      return;
    }

    if (typeof window !== 'undefined' && window.location.protocol === 'http:' && ['localhost', '127.0.0.1'].includes(window.location.hostname)) {
      setCashfreeError('Cashfree checkout requires HTTPS on localhost. Use Razorpay/manual payment locally or expose your app over HTTPS using ngrok.');
      return;
    }

    if (!canPlaceOrder) {
      setCashfreeError('Some cart items are out of stock or exceed available quantity.');
      return;
    }

    if (!name || !email || !address || !city || !state || !postalCode || !country || !mobile) {
      setCashfreeError('Please fill all shipping details first');
      return;
    }

    setCashfreeLoading(true);
    setCashfreeError('');
    setMessage('');

    try {
      // First, create order in our system with "Payment Processing" status
      const orderRes = await fetch('/api/payments/create-order', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          cart: items,
          name,
          email,
          address,
          city,
          state,
          postalCode,
          country,
          mobile,
          paymentMethod: 'cashfree',
          discountCoupon: couponCode.trim() || undefined,
          appliedDiscount,
          shippingCharges,
        }),
      });

      const orderData = await orderRes.json();

      if (!orderRes.ok) {
        setCashfreeError(orderData.error || 'Failed to create order');
        setCashfreeLoading(false);
        return;
      }

      // Now create payment session with Cashfree
      const paymentRes = await fetch('/api/payments/create', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          amount: finalTotal,
          orderId: orderData.orderNumber || orderData._id,
          customerId: session.user?.customerId || session.user?.id,
          customerEmail: email,
          customerPhone: mobile,
        }),
      });

      const paymentData = await paymentRes.json();

      if (!paymentRes.ok) {
        if (paymentData.code === 'PAYMENT_NOT_CONFIGURED') {
          // Fallback to manual payment if Cashfree not configured
          setPaymentMethod('manual');
          setCashfreeError('Online payment not available. Please use manual payment method.');
        } else {
          setCashfreeError(paymentData.error || 'Failed to initiate payment');
        }
        setCashfreeLoading(false);
        return;
      }

      // If we got a payment link, redirect to Cashfree
      if (paymentData.paymentLink) {
        sessionStorage.setItem('pendingCashfreeOrder', JSON.stringify({
          orderId: orderData._id,
          cfOrderId: paymentData.cfOrderId,
          paymentLink: paymentData.paymentLink,
        }));
        window.location.href = paymentData.paymentLink;
        return;
      }

      // If the gateway returned a redirect path for checkout, use it
      if (paymentData.checkoutRedirect) {
        sessionStorage.setItem('pendingCashfreeOrder', JSON.stringify({
          orderId: orderData._id,
          cfOrderId: paymentData.cfOrderId,
        }));
        router.push(paymentData.checkoutRedirect);
        return;
      }

      // If no payment link but session created, and no checkout redirect, fallback to return page
      if (paymentData.paymentSessionId) {
        sessionStorage.setItem('pendingCashfreeOrder', JSON.stringify({
          orderId: orderData._id,
          cfOrderId: paymentData.cfOrderId,
        }));
        router.push(`/payment-return?order_id=${orderData.orderNumber || orderData._id}&cf_order_id=${paymentData.cfOrderId}`);
        return;
      }

      setCashfreeError('Unable to create payment session');
    } catch (error) {
      console.error('Cashfree payment error:', error);
      setCashfreeError('Payment failed. Please try again or use manual payment.');
    } finally {
      setCashfreeLoading(false);
    }
  }

  async function initiateRazorpayPayment() {
    if (!session) {
      router.push('/login');
      return;
    }

    if (settings.onlinePaymentsEnabled === false) {
      setCashfreeError('Online payments are currently disabled. Please use Bank Transfer.');
      return;
    }

    if (items.length === 0) {
      setCashfreeError('Cart is empty');
      return;
    }

    if (!canPlaceOrder) {
      setCashfreeError('Some cart items are out of stock or exceed available quantity.');
      return;
    }

    if (!name || !email || !address || !city || !state || !postalCode || !country || !mobile) {
      setCashfreeError('Please fill all shipping details first');
      return;
    }

    setCashfreeLoading(true);
    setCashfreeError('');
    setMessage('');

    try {
      const scriptLoaded = await loadRazorpayCheckoutScript();
      if (!scriptLoaded) {
        setCashfreeError('Unable to load Razorpay checkout. Please try again.');
        return;
      }

      const orderRes = await fetch('/api/payments/create-order', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          cart: items,
          name,
          email,
          address,
          city,
          state,
          postalCode,
          country,
          mobile,
          paymentMethod: 'razorpay',
          discountCoupon: couponCode.trim() || undefined,
          appliedDiscount,
          shippingCharges,
        }),
      });

      const orderData = await orderRes.json();
      if (!orderRes.ok) {
        setCashfreeError(orderData.error || 'Failed to create order');
        return;
      }

      const payableAmount = Math.round(finalTotal * 100);
      if (payableAmount < 100) {
        setCashfreeError('Order amount must be at least ₹1 for Razorpay. Please review your cart.');
        return;
      }

      const razorpayPublicKey = process.env.NEXT_PUBLIC_RAZORPAY_KEY_ID || '';
      if (!razorpayPublicKey) {
        setCashfreeError('Razorpay public key is not configured. Please contact support.');
        return;
      }

      const razorpayOrderRes = await fetch('/api/create-order', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          amount: payableAmount,
          currency: 'INR',
          receipt: orderData.orderNumber || orderData._id,
        }),
      });

      const razorpayOrderData = await razorpayOrderRes.json();
      if (!razorpayOrderRes.ok) {
        const message = razorpayOrderData.error || razorpayOrderData.details || 'Failed to create Razorpay order';
        setCashfreeError(message);
        console.error('Razorpay order create failed:', razorpayOrderData);
        return;
      }

      if (!razorpayOrderData.order_id || !razorpayOrderData.amount) {
        setCashfreeError('Invalid Razorpay order response. Please contact support.');
        console.error('Invalid Razorpay order response:', razorpayOrderData);
        return;
      }

      const options = {
        key: razorpayPublicKey,
        amount: razorpayOrderData.amount,
        currency: razorpayOrderData.currency,
        name: 'Refurbished PC Studio',
        description: 'Order payment',
        order_id: razorpayOrderData.order_id,
        prefill: {
          name,
          email,
          contact: mobile,
        },
        notes: {
          internalOrderId: orderData._id,
        },
        handler: async (response: any) => {
          try {
            const verification = await handleRazorpayVerification(
              orderData._id,
              response.razorpay_payment_id,
              response.razorpay_order_id,
              response.razorpay_signature
            );

            if (!verification || !verification.success) {
              setCashfreeError(verification?.error || 'Payment verification failed');
              return;
            }

            clear();
            router.push(`/order-success?orderId=${orderData._id}`);
          } catch (verifyError) {
            console.error('Razorpay verification failed:', verifyError);
            setCashfreeError('Payment verification failed. Please contact support.');
          }
        },
        modal: {
          ondismiss: function () {
            setCashfreeError('Payment cancelled. Please try again.');
          },
        },
      };

      const razorpayCheckout = new (window as any).Razorpay(options);
      razorpayCheckout.open();
    } catch (error) {
      console.error('Razorpay payment error:', error);
      setCashfreeError('Payment failed. Please try again or use manual payment.');
    } finally {
      setCashfreeLoading(false);
    }
  }

  async function placeOrder() {
    if (!session) {
      router.push('/login');
      return;
    }

    if (items.length === 0) {
      setMessage('Cart is empty');
      return;
    }

    if (!canPlaceOrder) {
      setMessage('Some cart items are out of stock or exceed available quantity. Please update your cart.');
      return;
    }

    // Check payment method
    if (paymentMethod === 'cashfree') {
      // For Cashfree, initiate payment instead
      await initiateCashfreePayment();
      return;
    }

    if (paymentMethod === 'razorpay') {
      // For Razorpay, initiate payment instead
      await initiateRazorpayPayment();
      return;
    }

    // Manual payment requires screenshot and transaction ID
    if (!paymentScreenshot || !transactionId.trim()) {
      setMessage('Please upload payment screenshot and enter transaction ID');
      return;
    }

    setMessage('');
    setPassword('');
    setPasswordError('');
    setOrderPlaced(false);
    setStep(3);
  }

  return (
    <div className="px-4 py-10 bg-slate-50 sm:px-6 lg:px-8">
      <div className="mx-auto max-w-7xl">
        <div className="rounded-[32px] border border-slate-200 bg-white p-8 shadow-sm">
          <div className="flex flex-col gap-4 lg:flex-row lg:items-end lg:justify-between">
            <div>
              <p className="text-xs font-semibold uppercase tracking-[0.3em] text-blue-600">Checkout</p>
              <h1 className="mt-3 text-3xl font-semibold tracking-tight text-slate-900 sm:text-4xl">Shopping cart</h1>
              <p className="mt-2 max-w-2xl text-sm leading-7 text-slate-600">Review your selected items, confirm shipping details, and choose a secure payment option.</p>
            </div>
            <div className="rounded-full border border-slate-200 bg-slate-100 px-4 py-3 text-sm font-semibold text-slate-700">
              {items.length} item{items.length !== 1 ? 's' : ''}
            </div>
          </div>
        </div>

        <div className="mt-8 space-y-6">
      {items.length === 0 ? (
        <p className="text-gray-700">Your cart is empty.</p>
      ) : (
        <div className="grid gap-4">
          {items.map(item => (
            <div key={item.productId} className="rounded-[28px] border border-slate-200 bg-slate-50 p-5 shadow-sm sm:flex sm:items-center sm:justify-between">
              <div className="sm:flex-1">
                <p className="text-base font-semibold text-slate-900">{item.name}</p>
                <p className="mt-2 text-sm text-slate-600">₹{item.price.toFixed(2)} each</p>
                <p className="mt-2 text-sm text-slate-500">
                  {stockMap[item.productId] === 0
                    ? 'Out of stock'
                    : stockMap[item.productId] !== undefined
                    ? `${stockMap[item.productId]} available`
                    : 'Checking stock...'}
                </p>
              </div>
              <div className="mt-4 grid gap-3 sm:mt-0 sm:w-[220px]">
                <div className="flex items-center justify-between rounded-3xl border border-slate-200 bg-white px-3 py-2">
                  <button
                    onClick={() => updateQuantity(item.productId, item.quantity - 1)}
                    disabled={item.quantity <= 1}
                    className="rounded-full bg-slate-100 px-3 py-1 text-slate-700 transition hover:bg-slate-200 disabled:cursor-not-allowed disabled:opacity-50"
                  >
                    −
                  </button>
                  <span className="text-sm font-semibold text-slate-900">{item.quantity}</span>
                  <button
                    onClick={() => {
                      const available = stockMap[item.productId] ?? item.quantity + 1;
                      if (item.quantity + 1 > available) {
                        setMessage(`Cannot increase ${item.name} beyond available stock.`);
                        return;
                      }
                      updateQuantity(item.productId, item.quantity + 1);
                    }}
                    disabled={stockMap[item.productId] !== undefined && item.quantity >= (stockMap[item.productId] || 0)}
                    className="rounded-full bg-slate-100 px-3 py-1 text-slate-700 transition hover:bg-slate-200 disabled:cursor-not-allowed disabled:opacity-50"
                  >
                    +
                  </button>
                </div>
                <div className="rounded-3xl border border-slate-200 bg-white px-4 py-3 text-sm text-slate-700">
                  <div className="flex items-center justify-between">
                    <span>Subtotal</span>
                    <span className="font-semibold text-slate-900">₹{(item.price * item.quantity).toFixed(2)}</span>
                  </div>
                </div>
                <button
                  onClick={() => removeItem(item.productId)}
                  className="rounded-3xl bg-red-600 px-4 py-2 text-sm font-semibold text-white transition hover:bg-red-700"
                >
                  Remove
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      <div className="mb-6 rounded-[28px] bg-white p-6 shadow-sm ring-1 ring-slate-200">
        <p className="text-lg font-semibold text-slate-900">Subtotal (before GST): ₹{total.toFixed(2)}</p>
        {stockWarning && (
          <p className="text-sm text-red-600 mt-2">{stockWarning}</p>
        )}
        {!canPlaceOrder && (
          <p className="text-sm text-red-600 mt-2 font-semibold">Your cart contains unavailable items or too many quantities. Please update before placing the order.</p>
        )}
        {appliedDiscount > 0 && (
          <p className="text-lg font-semibold text-green-700">Discount: -₹{appliedDiscount.toFixed(2)}</p>
        )}
        {gstTotal > 0 && (
          <p className="text-lg font-semibold text-purple-700">GST: ₹{gstTotal.toFixed(2)}</p>
        )}
        {state && (
          <p className="text-lg font-semibold text-blue-700">
            Shipping: {shippingCharges === 0 ? 'FREE' : `₹${shippingCharges.toFixed(2)}`}
            {shippingCharges === 0 && (settings.freeShippingThreshold || 0) > 0 && total >= (settings.freeShippingThreshold || 0) && (
              <span className="text-sm text-green-600 ml-2">(Free above ₹{(settings.freeShippingThreshold || 0).toFixed(2)})</span>
            )}
          </p>
        )}
        <p className="text-lg font-bold text-gray-900">Total payable: ₹{finalTotal.toFixed(2)}</p>
        <p className="text-sm text-gray-600 mt-1">Total includes product price, GST, and shipping charges.</p>
      </div>

      {step === 1 && (
        <div className="rounded-[28px] border border-slate-200 bg-white p-6 shadow-sm ring-1 ring-slate-200 max-w-3xl">
          <h2 className="text-xl font-semibold mb-2 text-slate-900">Shipping details</h2>
          <div className="space-y-3">
            <input
              type="text"
              placeholder="Name"
              value={name}
              onChange={e => setName(e.target.value)}
              className="w-full rounded-3xl border border-slate-300 bg-slate-50 px-4 py-3 text-slate-900 focus:border-blue-500 focus:ring-blue-100"
            />
            <input
              type="email"
              placeholder="Email"
              value={email}
              onChange={e => setEmail(e.target.value)}
              className="w-full rounded-3xl border border-slate-300 bg-slate-50 px-4 py-3 text-slate-900 focus:border-blue-500 focus:ring-blue-100"
              disabled={!!session?.user?.email}
            />
            <input
              type="text"
              placeholder="Address"
              value={address}
              onChange={e => setAddress(e.target.value)}
              className="w-full border border-gray-300 px-3 py-2 rounded text-gray-900 bg-white focus:outline-none focus:ring-2 focus:ring-indigo-300"
            />
            <div className="grid grid-cols-2 gap-2">
              <input
                type="text"
                placeholder="City"
                value={city}
                onChange={e => setCity(e.target.value)}
                className="w-full rounded-3xl border border-slate-300 bg-slate-50 px-4 py-3 text-slate-900 focus:border-blue-500 focus:ring-blue-100"
              />
              <div className="relative">
                <input
                  type="text"
                  placeholder="Search State..."
                  value={stateSearch}
                  onChange={e => setStateSearch(e.target.value)}
                  className="w-full rounded-3xl border border-slate-300 bg-slate-50 px-4 py-3 text-slate-900 focus:border-blue-500 focus:ring-blue-100"
                />
                {stateSearch && (
                  <div className="absolute z-10 w-full mt-1 bg-white border border-gray-300 rounded-lg shadow-lg max-h-48 overflow-y-auto">
                    {filteredStates.length > 0 ? (
                      filteredStates.map(s => (
                        <div
                          key={s}
                          onClick={() => {
                            setState(s);
                            setStateSearch('');
                          }}
                          className="px-3 py-2 cursor-pointer hover:bg-indigo-100 text-gray-900"
                        >
                          {s}
                        </div>
                      ))
                    ) : (
                      <div className="px-3 py-2 text-gray-500">No state found</div>
                    )}
                  </div>
                )}
              </div>
              {state && (
                <div className="text-sm text-green-700 mt-1">
                  Selected: <strong>{state}</strong>
                  <button
                    type="button"
                    onClick={() => setState('')}
                    className="ml-2 text-red-500 hover:text-red-700 underline"
                  >
                    Change
                  </button>
                </div>
              )}
            </div>
            <input
              type="text"
              placeholder="Postal Code"
              value={postalCode}
              onChange={e => setPostalCode(e.target.value)}
              className="w-full rounded-3xl border border-slate-300 bg-slate-50 px-4 py-3 text-slate-900 focus:border-blue-500 focus:ring-blue-100"
            />
            <input
              type="text"
              placeholder="Country"
              value={country}
              onChange={e => setCountry(e.target.value)}
              className="w-full rounded-3xl border border-slate-300 bg-slate-50 px-4 py-3 text-slate-900 focus:border-blue-500 focus:ring-blue-100"
              disabled
            />
            <input
              type="text"
              placeholder="Mobile"
              value={mobile}
              onChange={e => setMobile(e.target.value)}
              className="w-full rounded-3xl border border-slate-300 bg-slate-50 px-4 py-3 text-slate-900 focus:border-blue-500 focus:ring-blue-100"
            />
          </div>
          {state && (
            <div className="mt-3 p-3 bg-blue-50 border border-blue-200 rounded-lg">
              <p className="text-sm text-blue-800">
                Shipping Charge: <strong>{shippingCharges === 0 ? 'FREE' : `₹${shippingCharges.toFixed(2)}`}</strong>
                {shippingCharges === 0 && (settings.freeShippingThreshold || 0) > 0 && total >= (settings.freeShippingThreshold || 0) && (
                  <span className="text-green-600 ml-1">(Free shipping above ₹{(settings.freeShippingThreshold || 0).toFixed(2)})</span>
                )}
              </p>
            </div>
          )}
          <button
            onClick={() => {
              if (!name || !email || !address || !city || !state || !postalCode || !country || !mobile) {
                setMessage('Please fill all shipping details including state');
                return;
              }
              setMessage('');
              setStep(2);
            }}
            className="mt-4 px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700"
          >
            Continue to Payment
          </button>
        </div>
      )}

      {step === 2 && (
        <>
          {/* Payment Method Selection */}
          <div className="mb-4 md:mb-6 rounded-[28px] bg-white p-4 md:p-6 shadow-sm ring-1 ring-slate-200">
            <h3 className="text-lg font-semibold mb-3 md:mb-4 text-slate-900">Select Payment Method</h3>
            
            <div className="grid grid-cols-1 gap-3 md:gap-4">
              {/* Cashfree Online Payment (show only if enabled in admin settings) */}
              {settings.onlinePaymentsEnabled !== false && settings.cashfreeEnabled !== false && (
                <div
                  onClick={() => {
                    if (settings.onlinePaymentsEnabled === false || settings.cashfreeEnabled === false) return;
                    setPaymentMethod('cashfree');
                  }}
                  className={`p-3 md:p-4 border-2 rounded-lg cursor-pointer transition-all min-h-[80px] ${
                    paymentMethod === 'cashfree'
                      ? 'border-green-500 bg-green-50'
                      : 'border-gray-200 hover:border-gray-300'
                  }`}
                >
                  <div className="flex items-center gap-3">
                    <div className={`w-5 h-5 md:w-6 md:h-6 rounded-full border-2 flex items-center justify-center flex-shrink-0 ${
                      paymentMethod === 'cashfree' ? 'border-green-500 bg-green-500' : 'border-gray-300'
                    }`}>
                      {paymentMethod === 'cashfree' && (
                        <svg className="w-3 h-3 md:w-4 md:h-4 text-white" fill="currentColor" viewBox="0 0 20 20">
                          <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                        </svg>
                      )}
                    </div>
                    <div>
                      <h4 className="font-semibold text-gray-900 text-sm md:text-base">💳 Pay with Cashfree</h4>
                      <p className="text-xs md:text-sm text-gray-600">UPI, Debit/Credit Card, Net Banking</p>
                    </div>
                  </div>
                </div>
              )}

              {/* Razorpay Online Payment (show only if enabled in admin settings) */}
              {settings.onlinePaymentsEnabled !== false && settings.razorpayEnabled === true && (
                <div
                  onClick={() => {
                    if (settings.onlinePaymentsEnabled === false || settings.razorpayEnabled !== true) return;
                    setPaymentMethod('razorpay');
                  }}
                  className={`p-3 md:p-4 border-2 rounded-lg cursor-pointer transition-all min-h-[80px] ${
                    paymentMethod === 'razorpay'
                      ? 'border-purple-500 bg-purple-50'
                      : 'border-gray-200 hover:border-gray-300'
                  }`}
                >
                  <div className="flex items-center gap-3">
                    <div className={`w-5 h-5 md:w-6 md:h-6 rounded-full border-2 flex items-center justify-center flex-shrink-0 ${
                      paymentMethod === 'razorpay' ? 'border-purple-500 bg-purple-500' : 'border-gray-300'
                    }`}>
                      {paymentMethod === 'razorpay' && (
                        <svg className="w-3 h-3 md:w-4 md:h-4 text-white" fill="currentColor" viewBox="0 0 20 20">
                          <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                        </svg>
                      )}
                    </div>
                    <div>
                      <h4 className="font-semibold text-gray-900 text-sm md:text-base">💜 Pay with Razorpay</h4>
                      <p className="text-xs md:text-sm text-gray-600">UPI, Cards, Wallets, Net Banking</p>
                    </div>
                  </div>
                </div>
              )}

              {/* Manual Bank Transfer */}
              <div
                onClick={() => setPaymentMethod('manual')}
                className={`p-3 md:p-4 border-2 rounded-lg cursor-pointer transition-all min-h-[80px] ${
                  paymentMethod === 'manual'
                    ? 'border-blue-500 bg-blue-50'
                    : 'border-gray-200 hover:border-gray-300'
                }`}
              >
                <div className="flex items-center gap-3">
                  <div className={`w-5 h-5 md:w-6 md:h-6 rounded-full border-2 flex items-center justify-center flex-shrink-0 ${
                    paymentMethod === 'manual' ? 'border-blue-500 bg-blue-500' : 'border-gray-300'
                  }`}>
                    {paymentMethod === 'manual' && (
                      <svg className="w-3 h-3 md:w-4 md:h-4 text-white" fill="currentColor" viewBox="0 0 20 20">
                        <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                      </svg>
                    )}
                  </div>
                  <div>
                    <h4 className="font-semibold text-gray-900 text-sm md:text-base">🏦 Bank Transfer</h4>
                    <p className="text-xs md:text-sm text-gray-600">Transfer manually & upload screenshot</p>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* Cashfree Payment Option */}
          {paymentMethod === 'cashfree' && (
            <div className="mb-4 md:mb-6 bg-gradient-to-r from-green-50 to-blue-50 border border-green-300 p-4 md:p-6 rounded-lg">
              <div className="text-center">
                <div className="text-3xl md:text-4xl mb-2 md:mb-3">💳</div>
                <h3 className="text-lg md:text-xl font-bold text-green-800 mb-1 md:mb-2">Online Payment via Cashfree</h3>
                <p className="text-gray-700 mb-3 md:mb-4 text-sm md:text-base">
                  Pay securely using UPI, Debit/Credit Card, or Net Banking.<br/>
                  <span className="text-green-700 font-semibold">Instant payment confirmation!</span>
                </p>
                
                <div className="bg-white p-3 md:p-4 rounded-lg mb-3 md:mb-4">
                  <p className="text-xl md:text-2xl font-bold text-gray-900">Total: ₹{finalTotal.toFixed(2)}</p>
                  <p className="text-xs md:text-sm text-gray-500">Including GST & Shipping</p>
                </div>

                {cashfreeError && (
                  <div className="mb-3 md:mb-4 p-3 bg-red-100 border border-red-300 rounded-lg">
                    <p className="text-red-700 text-sm">{cashfreeError}</p>
                  </div>
                )}

                <button
                  onClick={placeOrder}
                  disabled={cashfreeLoading || !canPlaceOrder}
                  className="w-full px-4 md:px-6 py-3 md:py-3 bg-gradient-to-r from-green-600 to-blue-600 text-white rounded-lg font-semibold hover:from-green-700 hover:to-blue-700 disabled:opacity-50 flex items-center justify-center gap-2 min-h-[48px]"
                >
                  {cashfreeLoading ? (
                    <>
                      <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                      </svg>
                      Processing Payment...
                    </>
                  ) : (
                    <>Pay ₹{finalTotal.toFixed(2)} with Cashfree →</>
                  )}
                </button>

                <p className="text-xs text-gray-500 mt-3">
                  🔒 Secure payment powered by Cashfree | Supported: UPI, Cards, Net Banking
                </p>
              </div>
            </div>
          )}

          {/* Razorpay Payment Option */}
          {paymentMethod === 'razorpay' && (
            <div className="mb-4 md:mb-6 bg-gradient-to-r from-purple-50 to-pink-50 border border-purple-300 p-4 md:p-6 rounded-lg">
              <div className="text-center">
                <div className="text-3xl md:text-4xl mb-2 md:mb-3">💜</div>
                <h3 className="text-lg md:text-xl font-bold text-purple-800 mb-1 md:mb-2">Online Payment via Razorpay</h3>
                <p className="text-gray-700 mb-3 md:mb-4 text-sm md:text-base">
                  Pay securely using UPI, Debit/Credit Card, Wallets, or Net Banking.<br/>
                  <span className="text-purple-700 font-semibold">Instant payment confirmation!</span>
                </p>
                
                <div className="bg-white p-3 md:p-4 rounded-lg mb-3 md:mb-4">
                  <p className="text-xl md:text-2xl font-bold text-gray-900">Total: ₹{finalTotal.toFixed(2)}</p>
                  <p className="text-xs md:text-sm text-gray-500">Including GST & Shipping</p>
                </div>

                {cashfreeError && (
                  <div className="mb-3 md:mb-4 p-3 bg-red-100 border border-red-300 rounded-lg">
                    <p className="text-red-700 text-sm">{cashfreeError}</p>
                  </div>
                )}

                <button
                  onClick={placeOrder}
                  disabled={cashfreeLoading || !canPlaceOrder}
                  className="w-full px-4 md:px-6 py-3 md:py-3 bg-gradient-to-r from-purple-600 to-pink-600 text-white rounded-lg font-semibold hover:from-purple-700 hover:to-pink-700 disabled:opacity-50 flex items-center justify-center gap-2 min-h-[48px]"
                >
                  {cashfreeLoading ? (
                    <>
                      <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                      </svg>
                      Processing Payment...
                    </>
                  ) : (
                    <>Pay ₹{finalTotal.toFixed(2)} with Razorpay →</>
                  )}
                </button>

                <p className="text-xs text-gray-500 mt-3">
                  🔒 Secure payment powered by Razorpay | Supported: UPI, Cards, Wallets, Net Banking
                </p>
              </div>
            </div>
          )}

          {/* Manual Payment Option */}
          {paymentMethod === 'manual' && (
            <>
              <div className="mb-6 bg-white border border-gray-200 p-4 rounded-lg text-gray-900">
                <h3 className="text-lg font-semibold mb-2">Payment Details</h3>
                <p className="text-sm text-gray-700 mb-3">Use यह जानकारी बैंक ट्रांसफर के लिए; payment screenshot और transaction ID दें।</p>
                {settings.bankAccountNumber ? (
                  <p className="text-gray-900"><strong>Bank Account:</strong> {settings.bankAccountNumber}</p>
                ) : (
                  <p className="text-gray-600">Bank account details not available yet. Please contact support.</p>
                )}
                {settings.upiId ? (
                  <p className="text-gray-900"><strong>UPI ID:</strong> {settings.upiId}</p>
                ) : (
                  <p className="text-gray-600">UPI ID not available yet. Please contact support.</p>
                )}
              </div>

              <div className="mb-6 p-4 bg-blue-50 border border-blue-300 rounded-lg">
                <h3 className="text-lg font-semibold mb-2 text-blue-900">ℹ️ Payment Verification</h3>
                <p className="text-sm text-blue-800 mb-2">Your payment will be verified during admin working hours:</p>
                <p className="text-lg font-bold text-blue-900">{settings.paymentVerificationStartTime || '09:00'} to {settings.paymentVerificationEndTime || '17:00'}</p>
                <p className="text-xs text-blue-700 mt-2">आपके भुगतान का सत्यापन इन कार्य घंटों के दौरान किया जाएगा</p>
              </div>

              <div className="max-w-md">
                <input
                  type="file"
                  accept="image/*"
                  onChange={handleFileChange}
                  className="mb-2"
                />
                {uploadError && <p className="text-red-600">{uploadError}</p>}
                <input
                  type="text"
                  placeholder="Transaction ID"
                  value={transactionId}
                  onChange={e => setTransactionId(e.target.value)}
                  className="w-full border px-3 py-2 rounded mb-2"
                />
                <div className="mb-2">
                  <div className="flex gap-2">
                    <input
                      type="text"
                      placeholder="Discount Coupon Code (optional)"
                      value={couponCode}
                      onChange={e => setCouponCode(e.target.value)}
                      className="flex-1 border px-3 py-2 rounded"
                    />
                    <button
                      onClick={validateCoupon}
                      className="px-3 py-2 bg-blue-600 text-white rounded hover:bg-blue-700"
                    >
                      Apply
                    </button>
                  </div>
                  {couponError && <p className="text-red-600 text-sm mt-1">{couponError}</p>}
                </div>
                <button
                  onClick={placeOrder}
                  disabled={placingOrder || !canPlaceOrder}
                  className="mt-2 px-4 py-2 bg-green-600 text-white rounded hover:bg-green-700 disabled:opacity-50"
                >
                  Place Order
                </button>
                <button
                  onClick={() => setStep(1)}
                  className="mt-2 ml-2 px-4 py-2 bg-gray-400 text-white rounded hover:bg-gray-500"
                >
                  Back to Shipping
                </button>
              </div>
            </>
          )}
        </>
      )}

      {step === 3 && (
        <div className="max-w-md">
          <h2 className="text-xl font-bold mb-4">Password Verification</h2>
          <p className="mb-4">अपना एकाउंट पासवर्ड दर्ज करें ताकि ऑर्डर सुनिश्चित हो सके।</p>

          <input
            type="password"
            placeholder="Enter your account password"
            value={password}
            onChange={e => setPassword(e.target.value)}
            className="w-full border px-3 py-2 rounded mb-2"
          />
          {passwordError && <p className="text-red-600 text-sm mb-2">{passwordError}</p>}

          <button
            onClick={verifyPasswordAndPlaceOrder}
            disabled={passwordLoading || !password.trim()}
            className="w-full px-4 py-2 bg-green-600 text-white rounded hover:bg-green-700 disabled:opacity-50"
          >
            {passwordLoading ? 'Verifying...' : 'Verify Password & Place Order'}
          </button>

          <button
            onClick={() => {
              setStep(2);
              setPassword('');
              setPasswordError('');
            }}
            className="w-full mt-2 px-4 py-2 bg-gray-400 text-white rounded hover:bg-gray-500"
          >
            Back to Payment
          </button>
        </div>
      )}

      {orderPlaced ? (
        <div className="mt-4 p-4 bg-green-50 border border-green-300 rounded-lg">
          <h3 className="font-bold text-green-800">✅ Order placed successfully!</h3>
          <p className="text-green-700">Thank you for your order. It will be processed shortly.</p>
          
          <div className="mt-4 p-3 bg-orange-50 border border-orange-300 rounded">
            <p className="text-sm font-semibold text-orange-800">⏱️ Payment Verification Schedule</p>
            <p className="text-sm text-orange-700 mt-1">Your payment will be verified during admin working hours:</p>
            <p className="text-sm font-bold text-orange-800 mt-1">{settings.paymentVerificationStartTime || '09:00'} to {settings.paymentVerificationEndTime || '17:00'}</p>
            <p className="text-xs text-orange-700 mt-2">आपके भुगतान का सत्यापन admin के कार्य समय के दौरान किया जाएगा</p>
          </div>
          
          <div className="mt-3 flex flex-wrap gap-2">
            <button
              onClick={() => {
                setOrderPlaced(false);
                router.push('/');
              }}
              className="px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700"
            >
              Go to Home
            </button>
            {settings.contactInfoEnabled !== false && getSupportWhatsapp() && (
              <a
                href={`https://wa.me/${getSupportWhatsapp().replace(/\D/g, '')}`}
                target="_blank"
                rel="noopener noreferrer"
                className="px-4 py-2 bg-green-600 text-white rounded hover:bg-green-700"
              >
                Contact on WhatsApp
              </a>
            )}
          </div>
          {settings.contactInfoEnabled !== false && getSupportWhatsapp() ? (
            <p className="mt-2 text-sm" style={{ color: settings.contactWhatsappColor || '#16a34a' }}>Support WhatsApp: {getSupportWhatsapp()}</p>
          ) : settings.contactInfoEnabled !== false ? (
            <p className="mt-2 text-sm text-gray-700">Whatsapp support number is not set yet.</p>
          ) : null}
          {settings.contactInfoEnabled !== false && getSupportEmail() && (
            <p className="mt-2 text-sm" style={{ color: settings.contactEmailColor || '#1d4ed8' }}>Support Email: {getSupportEmail()}</p>
          )}
          {settings.contactInfoEnabled !== false && !getSupportWhatsapp() && !getSupportEmail() && (
            <p className="mt-2 text-sm text-gray-700">Contact details not set yet.</p>
          )}
        </div>
      ) : (
        message && (
          <div className="mt-4 rounded-[28px] bg-white p-5 shadow-sm ring-1 ring-slate-200">
            <p className="text-sm text-slate-700">{message}</p>
          </div>
        )
      )}
      </div>
    </div>
  </div>
  );
}

'use client';

import Image from 'next/image';
import React, { useEffect, useState } from 'react';
import { useSearchParams, useRouter } from 'next/navigation';

type OrderProduct = {
  product: {
    _id: string;
    name: string;
    price: number;
    gstPercent?: number;
  } | null;
  quantity: number;
  price?: number;
  gstPercent?: number;
};

type Order = {
  _id: string;
  orderNumber?: string;
  total: number;
  status: string;
  discountAmount?: number;
  discountCoupon?: string;
  transactionId?: string;
  createdAt: string;
  customer?: {
    _id: string;
    name: string;
    email: string;
    mobile: string;
  };
  products: OrderProduct[];
  shipping: {
    name: string;
    email: string;
    address: string;
    city: string;
    postalCode: string;
    country: string;
    mobile: string;
  };
  shippingCharges?: number;
};

export default function OrderSuccessPage() {
  const searchParams = useSearchParams();
  const router = useRouter();
  const orderId = searchParams?.get('orderId') || '';
  const customerId = searchParams?.get('customerId') || '';

  const [order, setOrder] = useState<Order | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [supportNumber, setSupportNumber] = useState('');
  const [orderImageUrl, setOrderImageUrl] = useState('');
  const [settings, setSettings] = useState<{ paymentVerificationStartTime?: string; paymentVerificationEndTime?: string; contactWhatsapp?: string; contactEmail?: string; contactWhatsappColor?: string; contactEmailColor?: string; contactInfoEnabled?: boolean }>({});

  const getVerificationTimeSlotString = () => {
    try {
      const startTime = settings.paymentVerificationStartTime || '09:00';
      const endTime = settings.paymentVerificationEndTime || '17:00';
      return `${startTime} to ${endTime}`;
    } catch {
      return '09:00 to 17:00';
    }
  };

  useEffect(() => {
    async function fetchOrder() {
      if (!orderId) {
        setError('Order ID is missing');
        setLoading(false);
        return;
      }
      try {
        const res = await fetch(`/api/orders/${orderId}`);
        if (!res.ok) {
          const data = await res.json();
          setError(data.error || 'Order not found');
          setLoading(false);
          return;
        }
        const data = await res.json();
        setOrder(data);
      } catch (err) {
        console.error('Failed to fetch order', err);
        setError('Failed to load order details');
      } finally {
        setLoading(false);
      }
    }

    async function fetchSettings() {
      try {
        const res = await fetch('/api/business-settings');
        if (res.ok) {
          const data = await res.json();
          const contactInfoEnabled = data.contactInfoEnabled !== false;
          if (contactInfoEnabled) {
            if (data.contactWhatsapp) {
              setSupportNumber(data.contactWhatsapp);
            } else if (data.staffWhatsapp) {
              setSupportNumber(data.staffWhatsapp);
            } else if (data.adminWhatsapp) {
              setSupportNumber(data.adminWhatsapp);
            } else if (data.whatsapp) {
              setSupportNumber(data.whatsapp);
            }
          } else {
            setSupportNumber('');
          }
          setSettings({
            paymentVerificationStartTime: data.paymentVerificationStartTime || '09:00',
            paymentVerificationEndTime: data.paymentVerificationEndTime || '17:00',
            contactWhatsapp: data.contactWhatsapp || '',
            contactEmail: data.contactEmail || '',
            contactWhatsappColor: data.contactWhatsappColor || '#16a34a',
            contactEmailColor: data.contactEmailColor || '#1d4ed8',
            contactInfoEnabled,
          });
        }
      } catch (err) {
        console.error('Failed to fetch settings', err);
      }
    }

    fetchOrder();
    fetchSettings();
  }, [orderId]);

  const makeWhatsAppLink = () => {
    const number = supportNumber.replace(/\D/g, '') || '';
    const textLines = [
      `Order confirmation received!`,
      order ? `Order ID: ${order.orderNumber || order._id}` : `Order ID: ${orderId}`,
      customerId ? `Customer ID: ${customerId}` : '',
      order ? `Total: ₹${order.total.toFixed(2)}` : '',
      `Please assist me with order tracking.`,
    ].filter(Boolean);
    const encoded = encodeURIComponent(textLines.join(' '));
    if (!number) return '#';
    return `https://wa.me/${number}?text=${encoded}`;
  };

  const drawOrderImageUrl = (order: Order) => {
    const width = 1080;
    const lineHeight = 36;
    const padding = 48;
    const headerHeight = 100;
    const productsHeight = order.products.length * 30;
    const shippingHeight = 120;
    const rows = 10 + order.products.length;
    const height = headerHeight + 20 + (rows * lineHeight) + productsHeight + shippingHeight + 40;

    const canvas = document.createElement('canvas');
    canvas.width = width;
    canvas.height = height;
    const ctx = canvas.getContext('2d');
    if (!ctx) return '';

    ctx.fillStyle = '#f8fafc';
    ctx.fillRect(0, 0, width, height);

    ctx.fillStyle = '#0f172a';
    ctx.font = 'bold 32px Inter, sans-serif';
    ctx.fillText('Order Placed Successfully ✅', padding, 52);

    ctx.font = '600 24px Inter, sans-serif';
    ctx.fillStyle = '#1f2937';
    const orderNumber = order.orderNumber || order._id;
    const lines = [
      `Order ID: ${orderNumber}`,
      `Customer ID: ${customerId ?? 'N/A'}`,
      `Status: ${order.status === 'Payment Completed' ? 'Payment Completed (पेमेंट पूरा, admin सत्यापन बाकी)' : order.status}`,
      `Total: ₹${order.total.toFixed(2)}`,
      `Discount: ₹${order.discountAmount ?? 0}`,
      `Payment ID: ${order.transactionId ?? 'N/A'}`,
      `Placed on: ${new Date(order.createdAt).toLocaleString()}`,
      'Products:',
      ...order.products.map(p => {
        const itemPrice = p.price ?? p.product?.price ?? 0;
        const gstPercent = p.gstPercent ?? p.product?.gstPercent ?? 0;
        const lineTotal = itemPrice * p.quantity * (1 + gstPercent / 100);
        return `  • ${p.product?.name ?? 'Unknown'} x ${p.quantity} @ ₹${itemPrice.toFixed(2)}${gstPercent > 0 ? ` + GST ${gstPercent}%` : ''} = ₹${lineTotal.toFixed(2)}`;
      }),
      'Shipping:',
      `  ${order.shipping.name}`,
      `  ${order.shipping.address}, ${order.shipping.city}, ${order.shipping.postalCode}, ${order.shipping.country}`,
      `  ${order.shipping.mobile}`,
    ];

    let ypos = 100;
    for (const line of lines) {
      ctx.fillText(line, padding, ypos + lineHeight);
      ypos += lineHeight;
    }

    return canvas.toDataURL('image/png');
  };

  const generateOrderImage = () => {
    if (!order) return;
    const imageUrl = drawOrderImageUrl(order);
    if (imageUrl) {
      setOrderImageUrl(imageUrl);
    }
  };

  const downloadOrderImage = () => {
    if (!order) return;
    if (!orderImageUrl) {
      generateOrderImage();
    }
    const url = orderImageUrl || drawOrderImageUrl(order);
    if (!url) return;

    const a = document.createElement('a');
    a.href = url;
    a.download = `order-${order.orderNumber || order._id}.png`;
    a.click();
  };

  const shareOrderImage = async () => {
    if (!order) return;

    const imageUrl = orderImageUrl || drawOrderImageUrl(order);
    if (!imageUrl) {
      alert('Failed to generate image for sharing.');
      return;
    }

    try {
      const res = await fetch(imageUrl);
      const blob = await res.blob();
      const file = new File([blob], `order-${order._id}.png`, { type: 'image/png' });

      if (navigator.share && navigator.canShare && navigator.canShare({ files: [file] })) {
        await navigator.share({
          title: 'Order Placed: ' + order._id,
          text: 'Order Placed Successfully - see invoice image.',
          files: [file],
        });
      } else {
        alert('Sharing images is not supported on this device/browser. Please download the image first.');
      }
    } catch (err) {
      console.error('Image share failed', err);
      alert('Failed to share image. Please use download.');
    }
  };

  const downloadOrder = () => {
    if (!order) return;
    const orderText = [
      `Order ID: ${order.orderNumber || order._id}`,
      `Customer ID: ${customerId || 'N/A'}`,
      `Order Status: ${order.status}`,
      `Payment ID: ${order.transactionId ?? 'N/A'}`,
      `Total: ₹${order.total.toFixed(2)}`,
      `Discount Coupon: ${order.discountCoupon ?? 'None'}`,
      `Discount Amount: ₹${order.discountAmount ?? 0}`,
      'Products:',
      ...order.products.map(p => `- ${p.product?.name ?? 'Unknown'} (Qty: ${p.quantity})`),
      'Shipping details:',
      `- ${order.shipping.name}`,
      `- ${order.shipping.address}, ${order.shipping.city}, ${order.shipping.postalCode}, ${order.shipping.country}`,
      `- Mobile: ${order.shipping.mobile}`,
    ].join('\n');

    const blob = new Blob([orderText], { type: 'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `order-${order.orderNumber || order._id}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  if (loading) {
    return <div className="p-8">Loading order details...</div>;
  }

  if (error) {
    return (
      <div className="p-8">
        <h1 className="text-2xl font-bold mb-4">Order Details</h1>
        <p className="text-red-600">{error}</p>
        <button className="mt-4 px-4 py-2 bg-blue-600 text-white rounded" onClick={() => router.push('/')}>Go to Home</button>
      </div>
    );
  }

  if (!order) {
    return (
      <div className="p-8">
        <h1 className="text-2xl font-bold mb-4">Order Details</h1>
        <p>No order data available.</p>
        <button className="mt-4 px-4 py-2 bg-blue-600 text-white rounded" onClick={() => router.push('/')}>Go to Home</button>
      </div>
    );
  }

  const supportNumberDigits = supportNumber.replace(/\D/g, '');
  const whatsappUrl = supportNumberDigits ? `https://wa.me/${supportNumberDigits}` : undefined;

  return (
    <div className="p-8 bg-gray-50 min-h-[70vh]">
      <h1 className="text-2xl font-bold mb-4">✅ Order Placed Successfully</h1>
      <p className="mb-2">Thank you for your purchase! Your order is under review and will be confirmed soon.</p>

      <div className="bg-white p-4 shadow rounded mb-4">
        <div className="mb-2"><strong>Order ID:</strong> {order.orderNumber || order._id}</div>
        <div className="mb-2"><strong>Customer ID:</strong> {customerId ?? 'N/A'}</div>
        <div className="mb-2"><strong>Status:</strong> {order.status}</div>
        {order.status === 'Payment Completed' && (
          <div className="mb-2 text-orange-700">
            <strong>Note:</strong> Payment completed but not verified by admin.
            <br />
            पेमेंट पूरा, लेकिन admin द्वारा अभी तक सत्यापित नहीं हुआ है।
            <br />
            Admin सत्यापन समय: {getVerificationTimeSlotString()}
            (Admin सेट समय स्लॉट)
          </div>
        )}
        <div className="mb-2"><strong>Subtotal (before GST):</strong> ₹{order.products.reduce((sum, item) => sum + (((item.price ?? item.product?.price ?? 0) * item.quantity) || 0), 0).toFixed(2)}</div>
        <div className="mb-2"><strong>GST:</strong> ₹{order.products.reduce((sum, item) => sum + (((item.price ?? item.product?.price ?? 0) * (item.gstPercent ?? item.product?.gstPercent ?? 0) / 100) * item.quantity || 0), 0).toFixed(2)}</div>
        {order.shipping && (
          <div className="mb-2"><strong>Shipping:</strong> ₹{(order as any).shippingCharges?.toFixed(2) ?? 0}</div>
        )}
        <div className="mb-2"><strong>Discount:</strong> -₹{order.discountAmount ?? 0}</div>
        <div className="mb-2"><strong>Total payable:</strong> ₹{order.total.toFixed(2)}</div>
        <div className="mb-2"><strong>Order Date:</strong> {new Date(order.createdAt).toLocaleString()}</div>
      </div>

      <div className="bg-white p-4 shadow rounded mb-4">
        <h2 className="text-lg font-semibold mb-2">Products</h2>
        <ul className="space-y-1">
          {order.products.map((item, idx) => (
            <li key={idx} className="border-b pb-2 mb-2">
              {item.product?.name || 'Item'} x {item.quantity} (price: ₹{((item.price ?? item.product?.price) ?? 0).toFixed(2)}{(item.gstPercent ?? item.product?.gstPercent) ? ` + GST ${(item.gstPercent ?? item.product?.gstPercent) ?? 0}%` : ''})
            </li>
          ))}
        </ul>
      </div>

      <div className="bg-white p-4 shadow rounded mb-4">
        <h2 className="text-lg font-semibold mb-2">Shipping</h2>
        <p>{order.shipping.name}</p>
        <p>{order.shipping.address}, {order.shipping.city}, {order.shipping.postalCode}, {order.shipping.country}</p>
        <p>Mobile: {order.shipping.mobile}</p>
      </div>

      {orderImageUrl && (
        <div className="mb-4">
          <h2 className="text-lg font-semibold mb-2">Generated Image Preview</h2>
          <div className="w-full max-w-xl border rounded overflow-hidden">
            <Image src={orderImageUrl} alt="Order summary image" width={800} height={450} className="w-full h-auto" />
          </div>
        </div>
      )}

      {settings.contactInfoEnabled !== false && (settings.contactWhatsapp || supportNumber || settings.contactEmail) && (
        <div className="bg-green-50 p-4 rounded-lg shadow mb-4 border border-green-300">
          <h3 className="text-lg font-semibold text-green-800 mb-1">Contact Support</h3>
          {(settings.contactWhatsapp || supportNumber) && (
            <p style={{ color: settings.contactWhatsappColor || '#16a34a' }}>WhatsApp: {settings.contactWhatsapp || supportNumber}</p>
          )}
          {settings.contactEmail && (
            <p style={{ color: settings.contactEmailColor || '#1d4ed8' }}>Email: {settings.contactEmail}</p>
          )}
          {(settings.contactWhatsapp || supportNumber) && (
            <a
              href={`https://wa.me/${(settings.contactWhatsapp || supportNumber || '').replace(/\D/g, '')}`}
              target="_blank"
              rel="noreferrer"
              className="text-green-700 hover:underline"
            >
              Click here to message on WhatsApp
            </a>
          )}
        </div>
      )}

      <div className="flex flex-wrap gap-2 mt-4">
        <button onClick={generateOrderImage} className="px-4 py-2 bg-slate-600 text-white rounded hover:bg-slate-700">Generate Image</button>
        <button onClick={downloadOrderImage} className="px-4 py-2 bg-indigo-600 text-white rounded hover:bg-indigo-700">Download Image</button>
        <button onClick={shareOrderImage} className="px-4 py-2 bg-cyan-600 text-white rounded hover:bg-cyan-700">Share Image</button>
        <button onClick={downloadOrder} className="px-4 py-2 bg-indigo-600/90 text-white rounded hover:bg-indigo-700">Download Text (fallback)</button>

        <button
          onClick={async () => {
            if (!order) return;
            // Build invoice payload from order
            const invoice = {
              invoiceNumber: order.orderNumber || order._id,
              invoiceDate: new Date(order.createdAt).toLocaleDateString(),
              status: order.status,
              company: { name: 'PC Studio', address: '123 Main Street, Mumbai, MH 400001', gst: '' },
              order: { id: order._id, date: order.createdAt, paymentMethod: order.transactionId || 'N/A' },
              customer: { name: order.customer?.name || 'Customer', address: order.shipping.address, phone: order.customer?.mobile || order.shipping.mobile },
              shipping: { name: order.shipping.name, address: `${order.shipping.address}, ${order.shipping.city}, ${order.shipping.postalCode}`, courier: '' },
              products: order.products.map(p => ({ name: p.product?.name || 'Item', qty: p.quantity, price: p.price ?? p.product?.price ?? 0, total: (p.price ?? p.product?.price ?? 0) * p.quantity })),
              subtotal: order.products.reduce((sum, p) => sum + ((p.price ?? p.product?.price ?? 0) * p.quantity), 0),
              discount: order.discountAmount || 0,
              grandTotal: order.total,
            };

            try {
              const res = await fetch('/api/invoice', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ invoice }) });
              const html = await res.text();
              const w = window.open('', '_blank');
              if (!w) {
                alert('Please allow popups to open invoice in a new tab.');
                return;
              }
              w.document.open();
              w.document.write(html);
              w.document.close();
            } catch (err) {
              console.error('Failed to open invoice', err);
              alert('Failed to open invoice. See console for details.');
            }
          }}
          className="px-4 py-2 bg-emerald-600 text-white rounded hover:bg-emerald-700"
        >
          View / Print Invoice
        </button>

        {whatsappUrl && (
          <a
            href={makeWhatsAppLink()}
            target="_blank"
            rel="noreferrer"
            className="px-4 py-2 bg-green-600 text-white rounded hover:bg-green-700"
          >
            Share via WhatsApp
          </a>
        )}

        {whatsappUrl && (
          <a
            href={whatsappUrl}
            target="_blank"
            rel="noreferrer"
            className="px-4 py-2 bg-teal-600 text-white rounded hover:bg-teal-700"
          >
            Contact Support on WhatsApp
          </a>
        )}

        <button onClick={() => router.push('/orders')} className="px-4 py-2 bg-gray-600 text-white rounded hover:bg-gray-700">View My Orders</button>
      </div>
    </div>
  );
}

'use client';

import React, { useEffect, useState } from 'react';
import { useSession } from 'next-auth/react';
import { useRouter } from 'next/navigation';
import { jsPDF } from 'jspdf';

interface Order {
  _id: string;
  orderNumber?: string;
  total: number;
  discountAmount?: number;
  transactionId?: string;
  status: string;
  returnStatus: string;
  refundStatus: string;
  returnReason?: string;
  returnDeadline?: string;
  cancellationStatus: string;
  cancellationReason?: string;
  modificationRequest?: { status?: string; reason?: string };
  shipping?: {
    name: string;
    email: string;
    address: string;
    city: string;
    postalCode: string;
    country: string;
    mobile: string;
  };
  paymentScreenshot?: string;
  createdAt: string;
  deliveryCompanyName?: string;
  deliveryCompanyDetails?: string;
  trackingId?: string;
  products: { product: { _id: string; name: string; originalPrice: number; discountPercent: number } | null; productName?: string; quantity: number; price: number }[];
}

export default function OrdersPage() {
  const { data: session, status } = useSession();
  const router = useRouter();
  const [orders, setOrders] = useState<Order[]>([]);
  const [settings, setSettings] = useState<{ whatsapp?: string; contactWhatsapp?: string; contactEmail?: string; adminWhatsapp?: string; staffWhatsapp?: string; contactWhatsappColor?: string; contactEmailColor?: string; paymentVerificationStartTime?: string; paymentVerificationEndTime?: string; contactInfoEnabled?: boolean }>({});
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [changing, setChanging] = useState(false);
  const [currentPwd, setCurrentPwd] = useState('');
  const [newPwd, setNewPwd] = useState('');
  const [pwdMsg, setPwdMsg] = useState<string | null>(null);
  const [returnOrderId, setReturnOrderId] = useState<string | null>(null);
  const [returnReason, setReturnReason] = useState('');
  const [cancellationOrderId, setCancellationOrderId] = useState<string | null>(null);
  const [cancellationReason, setCancellationReason] = useState('');
  const [modificationOrderId, setModificationOrderId] = useState<string | null>(null);
  const [modificationReason, setModificationReason] = useState('');
  const [reviewProductId, setReviewProductId] = useState<string | null>(null);
  const [reviewProductName, setReviewProductName] = useState<string>('');
  const [reviewRating, setReviewRating] = useState<number>(5);
  const [reviewComment, setReviewComment] = useState('');
  const [reviewError, setReviewError] = useState('');
  const [reviewMessage, setReviewMessage] = useState('');
  const [reviewLoading, setReviewLoading] = useState(false);
  const [marketActivity, setMarketActivity] = useState<{ offers: Array<any>; bids: Array<any> }>({ offers: [], bids: [] });
  const [marketLoading, setMarketLoading] = useState(true);

  useEffect(() => {
    if (status === 'loading') return;
    if (!session) {
      router.push('/login');
      return;
    }

    fetch('/api/orders', { credentials: 'include' })
      .then(res => {
        if (!res.ok) {
          throw new Error(`HTTP error! status: ${res.status}`);
        }
        return res.json();
      })
      .then(data => {
        if (data.error) {
          setError(data.error);
          setOrders([]);
        } else {
          setError(null);
          setOrders(Array.isArray(data) ? data : []);
        }
      })
      .catch(err => {
        console.error('Error fetching orders:', err);
        setError(`Failed to load orders: ${err.message || 'Unknown error'}`);
        setOrders([]);
      })
      .finally(() => setLoading(false));

    const fetchMarketActivity = async () => {
      try {
        const res = await fetch('/api/user/market-activity');
        if (res.ok) {
          const data = await res.json();
          setMarketActivity({ offers: data.offers || [], bids: data.bids || [] });
        }
      } catch (error) {
        console.error('Market activity fetch failed:', error);
      } finally {
        setMarketLoading(false);
      }
    };
    fetchMarketActivity();

    fetch('/api/business-settings')
      .then(res => res.json())
      .then(data => {
        setSettings({
          whatsapp: data.whatsapp,
          contactWhatsapp: data.contactWhatsapp,
          contactEmail: data.contactEmail,
          adminWhatsapp: data.adminWhatsapp,
          staffWhatsapp: data.staffWhatsapp,
          contactWhatsappColor: data.contactWhatsappColor || '#16a34a',
          contactEmailColor: data.contactEmailColor || '#1d4ed8',
          paymentVerificationStartTime: data.paymentVerificationStartTime || '09:00',
          paymentVerificationEndTime: data.paymentVerificationEndTime || '17:00',
          contactInfoEnabled: data.contactInfoEnabled !== false,
        });
      })
      .catch(() => {
        setSettings({});
      });
  }, [session, status, router]);

  if (status === 'loading') return <div className="p-8"><p>Loading...</p></div>;
  if (!session) return null;

  const changePassword = async () => {
    setPwdMsg(null);
    try {
      const res = await fetch(`/api/users/${session.user.id}/password`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ currentPassword: currentPwd, newPassword: newPwd }),
      });
      const data = await res.json();
      if (!res.ok) {
        setPwdMsg(data.error || 'Failed');
      } else {
        setPwdMsg('Password changed');
        setCurrentPwd('');
        setNewPwd('');
        setChanging(false);
      }
    } catch (error) {
      console.error('Password change request failed:', error);
      setPwdMsg('Request failed');
    }
  };

  const requestReturn = async () => {
    if (!returnOrderId || !returnReason.trim()) return;

    try {
      const res = await fetch(`/api/orders/${returnOrderId}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ returnStatus: 'Return Requested', returnReason: returnReason.trim() }),
      });
      if (res.ok) {
        setReturnOrderId(null);
        setReturnReason('');
        // Refresh orders
        fetch('/api/orders')
          .then(res => res.json())
          .then(data => setOrders(data.error ? [] : data));
      }
    } catch (error) {
      console.error('Return request failed:', error);
    }
  };

  const requestCancellation = async () => {
    if (!cancellationOrderId || !cancellationReason.trim()) return;

    try {
      const res = await fetch(`/api/orders/${cancellationOrderId}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ cancellationStatus: 'Cancellation Requested', cancellationReason: cancellationReason.trim() }),
      });
      if (res.ok) {
        setCancellationOrderId(null);
        setCancellationReason('');
        // Refresh orders
        fetch('/api/orders')
          .then(res => res.json())
          .then(data => setOrders(data.error ? [] : data));
      }
    } catch (error) {
      console.error('Cancellation request failed:', error);
    }
  };

  const requestModification = async () => {
    if (!modificationOrderId || !modificationReason.trim()) return;

    try {
      const res = await fetch(`/api/orders/${modificationOrderId}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ modificationRequest: 'Requested', modificationReason: modificationReason.trim() }),
      });
      if (res.ok) {
        setModificationOrderId(null);
        setModificationReason('');
        fetch('/api/orders')
          .then(res => res.json())
          .then(data => setOrders(data.error ? [] : data));
      }
    } catch (error) {
      console.error('Modification request failed:', error);
    }
  };

  const openReviewForm = (productId: string, productName: string) => {
    setReviewProductId(productId);
    setReviewProductName(productName);
    setReviewRating(5);
    setReviewComment('');
    setReviewError('');
    setReviewMessage('');
  };

  const closeReviewForm = () => {
    setReviewProductId(null);
    setReviewProductName('');
    setReviewComment('');
    setReviewError('');
    setReviewMessage('');
  };

  const submitReview = async () => {
    if (!reviewProductId) return;
    setReviewError('');
    setReviewMessage('');
    if (!reviewRating || reviewRating < 1 || reviewRating > 5) {
      setReviewError('Please select a rating between 1 and 5 stars.');
      return;
    }
    if (!reviewComment.trim() || reviewComment.trim().length < 10) {
      setReviewError('Review must be at least 10 characters.');
      return;
    }

    setReviewLoading(true);
    try {
      const res = await fetch('/api/reviews', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ productId: reviewProductId, rating: reviewRating, comment: reviewComment.trim() }),
      });
      const data = await res.json();
      if (!res.ok) {
        setReviewError(data.error || 'Failed to submit review.');
      } else {
        setReviewMessage('Review submitted successfully.');
        setReviewComment('');
        setReviewProductId(null);
        setReviewProductName('');
      }
    } catch (error) {
      console.error('Review submission failed:', error);
      setReviewError('Review submission failed. Please try again.');
    } finally {
      setReviewLoading(false);
    }
  };

  const getVerificationTimeSlotString = () => {
    try {
      const startTime = settings.paymentVerificationStartTime || '09:00';
      const endTime = settings.paymentVerificationEndTime || '17:00';
      return `${startTime} to ${endTime}`;
    } catch {
      return '09:00 to 17:00';
    }
  };

  const sendOrderWhatsApp = (order: Order) => {
    const phone = settings.contactInfoEnabled === false ? '' : settings.contactWhatsapp || settings.whatsapp || settings.adminWhatsapp || settings.staffWhatsapp;
    if (!phone) {
      alert('No WhatsApp number configured or contact information is disabled. Please set a WhatsApp number in settings.');
      return;
    }

    const sanitizedPhone = phone.replace(/\D/g, '');
    if (!sanitizedPhone) {
      alert('Invalid WhatsApp number. Please enter a valid number in settings.');
      return;
    }

    const productLines = order.products
      .map(item => `${item.product ? item.product.name : 'Deleted Product'} x${item.quantity} @ ₹${item.product ? item.product.originalPrice : 0}`)
      .join('\n');

    const whatsappText = encodeURIComponent(
      `Order ID: ${order._id}\n` +
      `Date: ${new Date(order.createdAt).toLocaleString()}\n` +
      `Total: ₹${order.total.toFixed(2)}\n` +
      `Status: ${order.status}\n` +
      `Products:\n${productLines}\n` +
      `Shipping Name: ${order.shipping?.name || 'N/A'}\n` +
      `Contact: ${order.shipping?.mobile || 'N/A'}\n` +
      `Address: ${order.shipping?.address || 'N/A'}, ${order.shipping?.city || ''} ${order.shipping?.postalCode || ''}`
    );

    const whatsappUrl = `https://wa.me/${sanitizedPhone}?text=${whatsappText}`;
    window.open(whatsappUrl, '_blank');
  };

  const cleanInvoiceText = (value?: string) => {
    if (!value) return 'N/A';
    
    // Convert to string and handle basic cleaning
    let text = String(value);
    
    // Remove null bytes and control characters
    text = text.replace(/[\x00-\x1F\x7F]/g, ' ');
    
    // Normalize unicode characters
    text = text.normalize('NFKC');
    
    // Remove special characters that cause issues in PDF
    text = text.replace(/[&\uFF06]/g, ' and ');
    
    // Keep only valid characters: letters, numbers, spaces, and common punctuation
    text = text.replace(/[^\p{L}\p{N}\s.,:()\/\-@#]/gu, ' ');
    
    // Replace multiple spaces with single space
    text = text.replace(/\s+/g, ' ');
    
    // Trim and return
    return text.trim() || 'N/A';
  };

  // Helper function to create circular image for invoice
  const createCircularImage = async (imageUrl: string): Promise<string | null> => {
    return new Promise((resolve) => {
      const img = new Image();
      img.crossOrigin = 'anonymous';
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const size = 60;
        canvas.width = size;
        canvas.height = size;
        const ctx = canvas.getContext('2d');
        if (!ctx) {
          resolve(null);
          return;
        }
        // Create circular clipping path
        ctx.beginPath();
        ctx.arc(size / 2, size / 2, size / 2, 0, Math.PI * 2);
        ctx.closePath();
        ctx.clip();
        // Draw image scaled to fit
        const scale = Math.max(size / img.width, size / img.height);
        const w = img.width * scale;
        const h = img.height * scale;
        const x = (size - w) / 2;
        const y = (size - h) / 2;
        ctx.drawImage(img, x, y, w, h);
        resolve(canvas.toDataURL('image/png'));
      };
      img.onerror = () => resolve(null);
      img.src = imageUrl;
    });
  };

  const downloadInvoice = async (order: Order) => {
    const doc = new jsPDF({ unit: 'pt', format: 'a4' });
    let top = 40;
    const leftMargin = 40;
    const rightMargin = 555;
    
    // Fetch all business settings
    let businessSettings = {
      websiteName: 'REFURBISHED PC STUDIO',
      invoiceLogo: '',
      gstin: '',
      businessAddress: '',
      businessPhone: '',
      businessEmail: '',
      upiId: '',
      bankName: '',
      accountNumber: '',
      ifscCode: ''
    };
    
    try {
      const settingsRes = await fetch('/api/business-settings');
      if (settingsRes.ok) {
        const settings = await settingsRes.json();
        businessSettings = {
          websiteName: settings.websiteName || 'REFURBISHED PC STUDIO',
          invoiceLogo: settings.invoiceLogo || '',
          gstin: settings.gstin || '',
          businessAddress: settings.businessAddress || '',
          businessPhone: settings.businessPhone || '',
          businessEmail: settings.businessEmail || '',
          upiId: settings.upiId || '',
          bankName: settings.bankName || '',
          accountNumber: settings.accountNumber || '',
          ifscCode: settings.ifscCode || ''
        };
      }
    } catch (e) {
      console.error('Failed to fetch business settings:', e);
    }

    // Helper functions
    const addLine = (text: string, options: { size?: number; style?: 'normal' | 'bold'; align?: 'left' | 'center' | 'right' } = {}) => {
      const fontSize = options.size || 11;
      doc.setFontSize(fontSize);
      doc.setFont('helvetica', options.style === 'bold' ? 'bold' : 'normal');
      
      if (options.align === 'center') {
        doc.text(text, 297.5, top, { align: 'center' });
      } else if (options.align === 'right') {
        doc.text(text, rightMargin, top, { align: 'right' });
      } else {
        doc.text(text, leftMargin, top);
      }
      top += fontSize + 8;
    };

    const addHorizontalLine = (y: number) => {
      doc.setDrawColor(200);
      doc.setLineWidth(0.5);
      doc.line(leftMargin, y, rightMargin, y);
    };

    const addBox = (x: number, y: number, w: number, h: number) => {
      doc.setDrawColor(100);
      doc.setLineWidth(1);
      doc.rect(x, y, w, h);
    };

    // ===================== HEADER SECTION =====================
    // Add colored header background
    doc.setFillColor(30, 58, 138); // Dark blue
    doc.rect(0, 0, 595, 70, 'F');
    
    // Add invoice logo (circular) if available
    if (businessSettings.invoiceLogo) {
      try {
        const circularLogo = await createCircularImage(businessSettings.invoiceLogo);
        if (circularLogo) {
          doc.addImage(circularLogo, 'PNG', leftMargin + 5, 15, 40, 40);
        }
      } catch (e) {
        console.error('Failed to add invoice logo:', e);
      }
    }
    
    // Company Name
    doc.setTextColor(255, 255, 255);
    doc.setFontSize(22);
    doc.setFont('helvetica', 'bold');
    doc.text(businessSettings.websiteName, leftMargin + 55, 35);
    
    // Invoice Label
    doc.setFontSize(14);
    doc.setFont('helvetica', 'normal');
    doc.text('TAX INVOICE', leftMargin + 55, 52);
    
    // Invoice Number on right
    doc.setFontSize(12);
    doc.setFont('helvetica', 'bold');
    doc.text(`Invoice #: ${cleanInvoiceText(order.orderNumber || String(order._id).slice(-8))}`, rightMargin, 30, { align: 'right' });
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(10);
    doc.text(`Date: ${new Date(order.createdAt).toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' })}`, rightMargin, 45, { align: 'right' });
    doc.text(`Status: ${order.status}`, rightMargin, 58, { align: 'right' });
    
    // Reset text color
    doc.setTextColor(0, 0, 0);
    top = 80;

    // ===================== GST & BUSINESS INFO SECTION =====================
    if (businessSettings.gstin || businessSettings.businessAddress) {
      addBox(leftMargin, top - 10, 515, 45);
      doc.setFontSize(11);
      doc.setFont('helvetica', 'bold');
      addLine('Business Details', { size: 12, style: 'bold' });
      
      doc.setFont('helvetica', 'normal');
      doc.setFontSize(9);
      let businessInfo = '';
      if (businessSettings.gstin) businessInfo += `GSTIN: ${businessSettings.gstin}  |  `;
      if (businessSettings.businessPhone) businessInfo += `Ph: ${businessSettings.businessPhone}  |  `;
      if (businessSettings.businessEmail) businessInfo += `Email: ${businessSettings.businessEmail}`;
      if (businessInfo) addLine(businessInfo, { size: 9 });
      
      if (businessSettings.businessAddress) {
        addLine(`Address: ${businessSettings.businessAddress}`, { size: 9 });
      }
      top += 10;
    }

    // ===================== BILL TO & SHIP TO SECTION =====================
    // Create two columns for billing and shipping
    const colWidth = 240;
    const col1X = leftMargin;
    const col2X = leftMargin + colWidth + 35;
    
    addBox(col1X, top - 5, colWidth, 70);
    addBox(col2X, top - 5, colWidth, 70);
    
    doc.setFontSize(11);
    doc.setFont('helvetica', 'bold');
    doc.text('Bill To (Customer)', col1X + 10, top + 8);
    doc.text('Ship To (Shipping Address)', col2X + 10, top + 8);
    
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(10);
    const billY = top + 22;
    doc.text(cleanInvoiceText(order.shipping?.name) || 'N/A', col1X + 10, billY);
    doc.text(cleanInvoiceText(order.shipping?.name) || 'N/A', col2X + 10, billY);
    
    const emailY = billY + 12;
    doc.text(`Email: ${cleanInvoiceText(order.shipping?.email) || 'N/A'}`, col1X + 10, emailY);
    doc.text(`Email: ${cleanInvoiceText(order.shipping?.email) || 'N/A'}`, col2X + 10, emailY);
    
    const mobileY = emailY + 12;
    doc.text(`Mobile: ${cleanInvoiceText(order.shipping?.mobile) || 'N/A'}`, col1X + 10, mobileY);
    doc.text(`Mobile: ${cleanInvoiceText(order.shipping?.mobile) || 'N/A'}`, col2X + 10, mobileY);
    
    const addressY = mobileY + 12;
    const address = [
      cleanInvoiceText(order.shipping?.address),
      cleanInvoiceText(order.shipping?.city),
      cleanInvoiceText(order.shipping?.postalCode),
      cleanInvoiceText(order.shipping?.country)
    ].filter(Boolean).join(', ');
    doc.text(address || 'N/A', col1X + 10, addressY, { maxWidth: colWidth - 15 });
    doc.text(address || 'N/A', col2X + 10, addressY, { maxWidth: colWidth - 15 });
    
    top += 80;

    // ===================== ORDER DETAILS SECTION =====================
    addHorizontalLine(top);
    top += 10;
    doc.setFontSize(13);
    doc.setFont('helvetica', 'bold');
    addLine('Order Information', { size: 13, style: 'bold' });

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(10);

    let infoY = top;
    doc.setFont('helvetica', 'bold');
    doc.text('Order ID:', leftMargin, infoY);
    doc.setFont('helvetica', 'normal');
    doc.text(cleanInvoiceText(order.orderNumber || String(order._id)), leftMargin + 90, infoY);

    infoY += 15;
    doc.setFont('helvetica', 'bold');
    doc.text('Order Date:', leftMargin, infoY);
    doc.setFont('helvetica', 'normal');
    doc.text(new Date(order.createdAt).toLocaleDateString('en-IN'), leftMargin + 90, infoY);

    infoY += 15;
    doc.setFont('helvetica', 'bold');
    doc.text('Payment Status:', leftMargin, infoY);
    doc.setFont('helvetica', 'normal');
    doc.text(cleanInvoiceText(order.status), leftMargin + 90, infoY);

    infoY += 15;
    doc.setFont('helvetica', 'bold');
    doc.text('Transaction ID:', leftMargin, infoY);
    doc.setFont('helvetica', 'normal');
    doc.text(cleanInvoiceText(order.transactionId) || 'N/A', leftMargin + 90, infoY);

    if (order.trackingId) {
      infoY += 15;
      doc.setFont('helvetica', 'bold');
      doc.text('Tracking ID:', leftMargin, infoY);
      doc.setFont('helvetica', 'normal');
      doc.text(cleanInvoiceText(order.trackingId), leftMargin + 90, infoY);
    }
    if (order.deliveryCompanyName) {
      infoY += 15;
      doc.setFont('helvetica', 'bold');
      doc.text('Courier:', leftMargin, infoY);
      doc.setFont('helvetica', 'normal');
      doc.text(cleanInvoiceText(order.deliveryCompanyName), leftMargin + 90, infoY);
    }

    top = infoY + 20;

    // ===================== PRODUCTS TABLE =====================
    addHorizontalLine(top);
    top += 10;
    doc.setFontSize(13);
    doc.setFont('helvetica', 'bold');
    addLine('Product Details', { size: 13, style: 'bold' });
    
    // Table header
    doc.setFillColor(240, 240, 240);
    doc.rect(leftMargin, top - 5, 515, 20, 'F');
    
    doc.setFontSize(10);
    doc.setFont('helvetica', 'bold');
    doc.text('S.No', leftMargin + 5, top + 5);
    doc.text('Product Name', leftMargin + 30, top + 5);
    doc.text('Qty', leftMargin + 280, top + 5);
    doc.text('Price (₹)', leftMargin + 320, top + 5);
    doc.text('Total (₹)', leftMargin + 420, top + 5, { align: 'right' });
    
    top += 20;
    doc.setFont('helvetica', 'normal');
    
    // Table rows
    order.products.forEach((item, index) => {
      const productName = cleanInvoiceText(item.productName || item.product?.name || 'Deleted Product');
      const productPrice = Number.isFinite(item.price) ? item.price : (item.product?.originalPrice || 0);
      const total = productPrice * item.quantity;

      doc.text(`${index + 1}`, leftMargin + 5, top + 5);
      doc.text(productName.substring(0, 40), leftMargin + 30, top + 5);
      doc.text(String(item.quantity), leftMargin + 280, top + 5);
      doc.text(productPrice.toFixed(2), leftMargin + 320, top + 5);
      doc.text(total.toFixed(2), leftMargin + 420, top + 5, { align: 'right' });

      top += 15;
    });
    
    top += 10;
    addHorizontalLine(top);
    top += 15;

    // ===================== PAYMENT SUMMARY =====================
    const summaryX = leftMargin + 300;
    
    doc.setFont('helvetica', 'normal');
    doc.text('Subtotal:', summaryX, top);
    const subtotal = order.products.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    doc.text(`₹${subtotal.toFixed(2)}`, summaryX + 100, top, { align: 'right' });
    top += 15;

    if (order.discountAmount && order.discountAmount > 0) {
      doc.setTextColor(220, 50, 50);
      doc.text('Discount:', summaryX, top);
      doc.text(`-₹${order.discountAmount.toFixed(2)}`, summaryX + 100, top, { align: 'right' });
      doc.setTextColor(0, 0, 0);
      top += 15;
    }

    doc.setFont('helvetica', 'bold');
    doc.setFontSize(12);
    doc.text('Grand Total:', summaryX, top);
    doc.text(`₹${order.total.toFixed(2)}`, summaryX + 100, top, { align: 'right' });
    top += 25;

    // ===================== PAYMENT & BANK DETAILS =====================
    if (businessSettings.upiId || businessSettings.bankName) {
      addBox(leftMargin, top - 5, 515, 50);
      doc.setFontSize(11);
      doc.setFont('helvetica', 'bold');
      addLine('Payment Details', { size: 11, style: 'bold' });
      
      doc.setFont('helvetica', 'normal');
      doc.setFontSize(9);
      
      if (businessSettings.upiId) {
        addLine(`UPI ID: ${businessSettings.upiId}`, { size: 9 });
      }
      if (businessSettings.bankName) {
        addLine(`Bank: ${businessSettings.bankName} | A/C: ${businessSettings.accountNumber} | IFSC: ${businessSettings.ifscCode}`, { size: 9 });
      }
      top += 20;
    }

    // ===================== QR CODE SECTION =====================
    // Generate QR code with order info
    try {
      // Simple QR code placeholder - in production, use a QR library
      doc.setFillColor(245, 245, 245);
      doc.rect(leftMargin, top, 80, 80, 'F');
      doc.setDrawColor(200, 200, 200);
      doc.rect(leftMargin, top, 80, 80);
      
      doc.setFontSize(8);
      doc.setFont('helvetica', 'normal');
      doc.text('Scan to verify', leftMargin + 40, top + 35, { align: 'center' });
      doc.text('Order Details', leftMargin + 40, top + 45, { align: 'center' });
      
      // Add order summary in QR box
      doc.setFontSize(7);
      const qrSummary = [
        `Order: ${cleanInvoiceText(order.orderNumber || String(order._id)).slice(-8)}`,
        `Amount: ₹${order.total.toFixed(2)}`,
        `Status: ${cleanInvoiceText(order.status)}`
      ];
      qrSummary.forEach((line, i) => {
        doc.text(line, leftMargin + 40, top + 58 + (i * 8), { align: 'center' });
      });
    } catch (e) {
      console.error('Failed to add QR code:', e);
    }

    // ===================== TRACKING INFO =====================
    doc.setFontSize(10);
    doc.setFont('helvetica', 'bold');
    addLine('Shipping Tracking', { size: 10, style: 'bold' });
    
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(9);
    if (order.trackingId) {
      addLine(`Tracking ID: ${cleanInvoiceText(order.trackingId)}`, { size: 9 });
    }
    if (order.deliveryCompanyName) {
      addLine(`Courier: ${cleanInvoiceText(order.deliveryCompanyName)}`, { size: 9 });
    }
    if (order.deliveryCompanyDetails) {
      addLine(`Info: ${cleanInvoiceText(order.deliveryCompanyDetails)}`, { size: 9 });
    }
    if (!order.trackingId && !order.deliveryCompanyName) {
      addLine('Tracking details will be updated once shipped', { size: 9 });
    }

    // ===================== FOOTER =====================
    top = 720;
    addHorizontalLine(top);
    top += 10;
    
    doc.setFontSize(8);
    doc.setTextColor(100, 100, 100);
    doc.text('Thank you for your purchase!', 297.5, top, { align: 'center' });
    top += 12;
    doc.text(`Generated on ${new Date().toLocaleString('en-IN')} | ${businessSettings.websiteName}`, 297.5, top, { align: 'center' });
    
    // Reset text color
    doc.setTextColor(0, 0, 0);

    // Save the PDF
    doc.save(`invoice-${cleanInvoiceText(order.orderNumber || String(order._id)).slice(-8)}.pdf`);
  };

  return (
    <div className="p-8 bg-gradient-to-br from-slate-50 via-white to-blue-50 min-h-screen">
      <h1 className="text-5xl font-black mb-2 text-blue-950 dark:text-cyan-100 leading-tight drop-shadow-lg" aria-label="My Orders" style={{ textShadow: '0 0 12px rgba(0,0,0,.35)' }}>
        My Orders
      </h1>
      <p className="mb-6 text-lg font-semibold text-slate-800 dark:text-slate-100 drop-shadow-sm">Track your latest purchases and manage returns/cancellations.</p>
      {error && (
        <div className="mb-6 p-4 bg-red-50 border border-red-300 rounded-lg">
          <p className="text-red-700 font-semibold">⚠️ Error:</p>
          <p className="text-red-600 text-sm mt-1">{error}</p>
          <button onClick={() => { setError(null); setLoading(true); window.location.reload(); }} className="mt-3 px-4 py-2 bg-red-600 text-white rounded hover:bg-red-700 text-sm">
            Retry
          </button>
        </div>
      )}
      {loading ? (
        <p>Loading...</p>
      ) : orders.length === 0 ? (
        <p>You have not placed any orders yet.</p>
      ) : (
        <>
          {(marketLoading ? true : marketActivity.offers.length > 0 || marketActivity.bids.length > 0) && (
            <div className="mb-6 p-4 bg-emerald-50 border border-emerald-300 rounded-lg">
              <h3 className="text-lg font-semibold mb-2 text-emerald-900">🎯 Bargain & Auction Activity</h3>
              {marketLoading ? (
                <p className="text-sm text-emerald-800">Loading your bargain and bid status...</p>
              ) : (
                <div className="space-y-3">
                  {marketActivity.offers.map((offer) => (
                    <div key={`offer-${offer.productId}-${offer.createdAt}`} className="rounded-lg bg-white p-3 border border-emerald-200">
                      <div className="flex flex-col md:flex-row md:justify-between gap-3">
                        <div>
                          <p className="text-sm text-gray-700 font-semibold">Bargain Offer for {offer.productName}</p>
                          <p className="text-sm text-gray-600">Offered: ₹{offer.price.toFixed(2)}</p>
                        </div>
                        <div className="text-sm text-gray-700">
                          Status: <span className="font-semibold">{offer.status}</span>
                        </div>
                      </div>
                      {offer.couponCode && (
                        <p className="mt-2 text-sm text-green-800">Coupon: <strong>{offer.couponCode}</strong> (valid until {offer.reservedUntil ? new Date(offer.reservedUntil).toLocaleDateString() : 'N/A'})</p>
                      )}
                    </div>
                  ))}
                  {marketActivity.bids.map((bid) => (
                    <div key={`bid-${bid.productId}-${bid.createdAt}`} className="rounded-lg bg-white p-3 border border-emerald-200">
                      <div className="flex flex-col md:flex-row md:justify-between gap-3">
                        <div>
                          <p className="text-sm text-gray-700 font-semibold">Auction Bid for {bid.productName}</p>
                          <p className="text-sm text-gray-600">Bid: ₹{bid.price.toFixed(2)}</p>
                        </div>
                        <div className="text-sm text-gray-700">
                          Status: <span className="font-semibold">{bid.status}</span>
                        </div>
                      </div>
                      {bid.couponCode && (
                        <p className="mt-2 text-sm text-green-800">Coupon: <strong>{bid.couponCode}</strong> (valid until {bid.reservedUntil ? new Date(bid.reservedUntil).toLocaleDateString() : 'N/A'})</p>
                      )}
                    </div>
                  ))}
                  {marketActivity.offers.length === 0 && marketActivity.bids.length === 0 && (
                    <p className="text-sm text-gray-700">No bargain or bidding activity to show yet.</p>
                  )}
                </div>
              )}
            </div>
          )}
          {orders.some(order => order.status === 'Payment Pending' || order.status === 'Payment Completed') && (
            <div className="mb-6 p-4 bg-blue-50 border border-blue-300 rounded-lg">
              <h3 className="text-lg font-semibold mb-2 text-blue-900">⏱️ Payment Verification Time</h3>
              <p className="text-sm text-blue-800 mb-1">Your payment will be verified during admin working hours:</p>
              <p className="text-lg font-bold text-blue-900">{settings.paymentVerificationStartTime || '09:00'} to {settings.paymentVerificationEndTime || '17:00'}</p>
              <p className="text-xs text-blue-700 mt-2">आपके भुगतान का सत्यापन इन कार्य घंटों के दौरान किया जाएगा</p>
            </div>
          )}
          {changing && (
            <div className="mb-6 p-4 border rounded bg-white">
              <h2 className="font-semibold mb-2">Change Password</h2>
              {pwdMsg && <p className="text-sm text-center mb-2">{pwdMsg}</p>}
              <input
                type="password"
                placeholder="Current password"
                value={currentPwd}
                onChange={(e) => setCurrentPwd(e.target.value)}
                className="w-full mb-2 p-2 border rounded"
              />
              <input
                type="password"
                placeholder="New password"
                value={newPwd}
                onChange={(e) => setNewPwd(e.target.value)}
                className="w-full mb-2 p-2 border rounded"
              />
              <div className="flex gap-2">
                <button onClick={changePassword} className="px-3 py-1 bg-blue-600 text-white rounded">Save</button>
                <button onClick={() => setChanging(false)} className="px-3 py-1 bg-gray-300 rounded">Cancel</button>
              </div>
            </div>
          )}
          {returnOrderId && (
            <div className="mb-6 p-4 border rounded bg-white">
              <h2 className="font-semibold mb-2">Request Return</h2>
              <textarea
                placeholder="Please provide reason for return"
                value={returnReason}
                onChange={(e) => setReturnReason(e.target.value)}
                className="w-full mb-2 p-2 border rounded"
                rows={3}
              />
              <div className="flex gap-2">
                <button onClick={requestReturn} className="px-3 py-1 bg-orange-600 text-white rounded">Submit Return Request</button>
                <button onClick={() => { setReturnOrderId(null); setReturnReason(''); }} className="px-3 py-1 bg-gray-300 rounded">Cancel</button>
              </div>
            </div>
          )}
          {cancellationOrderId && (
            <div className="mb-6 p-4 border rounded bg-white">
              <h2 className="font-semibold mb-2">Request Cancellation</h2>
              <textarea
                placeholder="Please provide reason for cancellation"
                value={cancellationReason}
                onChange={(e) => setCancellationReason(e.target.value)}
                className="w-full mb-2 p-2 border rounded bg-white text-gray-900 placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-red-500"
                rows={3}
              />
              <div className="flex gap-2">
                <button onClick={requestCancellation} className="px-3 py-1 bg-red-600 text-white rounded">Submit Cancellation Request</button>
                <button onClick={() => { setCancellationOrderId(null); setCancellationReason(''); }} className="px-3 py-1 bg-gray-300 rounded">Cancel</button>
              </div>
            </div>
          )}
          {modificationOrderId && (
            <div className="mb-6 p-4 border rounded bg-white">
              <h2 className="font-semibold mb-2">Request Order Modification</h2>
              <textarea
                placeholder="Please explain what you want to modify"
                value={modificationReason}
                onChange={(e) => setModificationReason(e.target.value)}
                className="w-full mb-2 p-2 border rounded bg-white text-gray-900 placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-blue-500"
                rows={3}
              />
              <div className="flex gap-2">
                <button onClick={requestModification} className="px-3 py-1 bg-blue-600 text-white rounded">Submit Modification Request</button>
                <button onClick={() => { setModificationOrderId(null); setModificationReason(''); }} className="px-3 py-1 bg-gray-300 rounded">Cancel</button>
              </div>
            </div>
          )}
          {reviewProductId && (
            <div className="mb-6 p-4 border rounded bg-white">
              <div className="flex items-center justify-between mb-4">
                <div>
                  <h2 className="font-semibold text-lg">Review {reviewProductName}</h2>
                  <p className="text-sm text-gray-600">Leave your review for the delivered product.</p>
                </div>
                <button onClick={closeReviewForm} className="text-gray-500 hover:text-gray-900">✕</button>
              </div>
              <div className="mb-4">
                <label className="block text-sm font-semibold text-gray-700 mb-2">Rating</label>
                <div className="flex gap-2">
                  {[1, 2, 3, 4, 5].map((star) => (
                    <button
                      key={star}
                      type="button"
                      onClick={() => setReviewRating(star)}
                      className={`rounded-full px-4 py-2 text-sm font-semibold transition ${reviewRating === star ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'}`}
                    >
                      {star} ★
                    </button>
                  ))}
                </div>
              </div>
              <div className="mb-4">
                <label className="block text-sm font-semibold text-gray-700 mb-2">Comment</label>
                <textarea
                  value={reviewComment}
                  onChange={(e) => setReviewComment(e.target.value)}
                  rows={4}
                  className="w-full rounded-lg border border-gray-300 p-3 focus:outline-none focus:ring-2 focus:ring-blue-500"
                  placeholder="Share your experience with this product."
                />
              </div>
              {reviewError && <p className="text-sm text-red-600 mb-3">{reviewError}</p>}
              {reviewMessage && <p className="text-sm text-green-700 mb-3">{reviewMessage}</p>}
              <div className="flex gap-2">
                <button onClick={submitReview} disabled={reviewLoading} className="px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700 disabled:opacity-50">{reviewLoading ? 'Submitting...' : 'Submit Review'}</button>
                <button onClick={closeReviewForm} className="px-4 py-2 bg-gray-200 text-gray-800 rounded hover:bg-gray-300">Cancel</button>
              </div>
            </div>
          )}
          <button onClick={() => setChanging(true)} className="mb-4 text-blue-600">Change Password</button>
          <table className="w-full bg-white border border-gray-200 rounded-lg overflow-hidden">
          <thead className="bg-gray-100">
            <tr>
              <th className="text-left px-3 py-2 text-xs font-bold text-gray-700 uppercase tracking-wide">Order ID</th>
              <th className="text-left px-3 py-2 text-xs font-bold text-gray-700 uppercase tracking-wide">Date</th>
              <th className="text-left px-3 py-2 text-xs font-bold text-gray-700 uppercase tracking-wide">Products</th>
              <th className="text-left px-3 py-2 text-xs font-bold text-gray-700 uppercase tracking-wide">Total</th>
              <th className="text-left px-3 py-2 text-xs font-bold text-gray-700 uppercase tracking-wide">Status</th>
              <th className="text-left px-3 py-2 text-xs font-bold text-gray-700 uppercase tracking-wide">Return Status</th>
              <th className="text-left px-3 py-2 text-xs font-bold text-gray-700 uppercase tracking-wide">Refund Status</th>
              <th className="text-left px-3 py-2 text-xs font-bold text-gray-700 uppercase tracking-wide">Cancellation Status</th>
              <th className="text-left px-3 py-2 text-xs font-bold text-gray-700 uppercase tracking-wide">Actions</th>
            </tr>
          </thead>
          <tbody>
            {orders.map(order => (
              <React.Fragment key={order._id}>
                <tr className="border-t bg-white even:bg-gray-50">
                  <td className="p-2 text-gray-800">{order.orderNumber || order._id.slice(-8)}</td>
                <td className="p-2">{new Date(order.createdAt).toLocaleString()}</td>
                <td className="p-2 space-y-2">
                  {order.products.map((item, idx) => (
                    <div key={`${order._id}-${item.product?._id || 'deleted'}-${idx}`} className="flex flex-col gap-2">
                      <div className="flex flex-wrap items-center justify-between gap-2">
                        <span>{item.product ? item.product.name : 'Deleted Product'} x{item.quantity}</span>
                        {order.status === 'Delivered' && item.product?._id ? (
                          <button
                            onClick={() => openReviewForm(item.product!._id, item.product!.name)}
                            className="px-2 py-1 bg-blue-600 text-white rounded text-xs hover:bg-blue-700"
                          >
                            Review
                          </button>
                        ) : null}
                      </div>
                    </div>
                  ))}
                </td>
                <td className="p-2">₹{order.total.toFixed(2)}</td>
                <td className="p-2">
                  <div>
                    <span className={`px-2 py-1 rounded text-sm font-semibold ${
                      order.status === 'Payment Pending' ? 'bg-orange-100 text-orange-800' :
                      order.status === 'Payment Completed' ? 'bg-yellow-100 text-yellow-800' :
                      order.status === 'Payment Verified' ? 'bg-emerald-100 text-emerald-800' :
                      order.status === 'Payment Rejected' ? 'bg-red-100 text-red-800' :
                      order.status === 'Order Preparing' ? 'bg-sky-100 text-sky-800' :
                      order.status === 'Shipped' ? 'bg-indigo-100 text-indigo-800' :
                      order.status === 'Delivered' ? 'bg-green-100 text-green-800' :
                      order.status === 'Order Rejected' ? 'bg-rose-100 text-rose-800' :
                      'bg-gray-100 text-gray-800'
                    }`}>
                      {order.status === 'Payment Completed' ? 'Payment Completed (पेमेंट पूरा, admin सत्यापन बाकी)' : order.status}
                    </span>
                  </div>
                  {order.status === 'Payment Completed' && (
                    <p className="text-xs text-orange-700 mt-1">
                      Payment completed but not verified by admin. <br /> भुगतान अभी तक admin द्वारा सत्यापित नहीं हुआ है। <br />
                      Admin सत्यापन समय: {getVerificationTimeSlotString()} (Admin सेट समय स्लॉट)
                    </p>
                  )}
                </td>
                <td className="p-2">
                  <span className={`px-2 py-1 rounded text-sm font-semibold ${
                    order.returnStatus === 'No Return' ? 'bg-gray-100 text-gray-700' :
                    order.returnStatus === 'Return Requested' ? 'bg-orange-100 text-orange-800' :
                    order.returnStatus === 'Return Approved' ? 'bg-emerald-100 text-emerald-800' :
                    order.returnStatus === 'Return Rejected' ? 'bg-red-100 text-red-800' :
                    order.returnStatus === 'Return Received' ? 'bg-indigo-100 text-indigo-800' :
                    'bg-green-100 text-green-800'
                  }`}>
                    {order.returnStatus}
                  </span>
                  {order.returnReason && (
                    <div className="text-xs text-gray-700 font-medium mt-1">
                      Reason: {order.returnReason}
                    </div>
                  )}
                </td>
                <td className="p-2">
                  <span className={`px-2 py-1 rounded text-sm font-semibold ${
                    order.refundStatus === 'No Refund' ? 'bg-gray-100 text-gray-700' :
                    order.refundStatus === 'Refund Pending' ? 'bg-yellow-100 text-yellow-800' :
                    order.refundStatus === 'Refund Approved' ? 'bg-green-100 text-green-800' :
                    order.refundStatus === 'Refund Rejected' ? 'bg-red-100 text-red-800' :
                    'bg-indigo-100 text-indigo-800'
                  }`}>
                    {order.refundStatus}
                  </span>
                </td>
                <td className="p-2">
                  <span className={`px-2 py-1 rounded text-sm font-semibold ${
                    order.cancellationStatus === 'None' ? 'bg-gray-100 text-gray-700' :
                    order.cancellationStatus === 'Cancellation Requested' ? 'bg-orange-100 text-orange-800' :
                    order.cancellationStatus === 'Cancellation Approved' ? 'bg-emerald-100 text-emerald-800' :
                    order.cancellationStatus === 'Cancellation Rejected' ? 'bg-red-100 text-red-800' :
                    'bg-gray-100 text-gray-700'
                  }`}>
                    {order.cancellationStatus}
                  </span>
                  {order.cancellationReason && (
                    <div className="text-xs text-gray-900 font-medium mt-1">
                      Reason: {order.cancellationReason}
                    </div>
                  )}
                </td>
                <td className="p-2">
                  {order.status !== 'Delivered' && order.cancellationStatus === 'None' && order.modificationRequest?.status !== 'Requested' && (
                    <button
                      onClick={() => setModificationOrderId(order._id)}
                      className="px-3 py-1 bg-blue-600 text-white rounded text-sm hover:bg-blue-700 mr-2"
                    >
                      Request Modification
                    </button>
                  )}
                  {order.status !== 'Delivered' && order.modificationRequest?.status === 'Requested' && (
                    <span className="inline-flex px-3 py-1 rounded text-sm bg-blue-100 text-blue-800 mr-2">
                      Modification requested
                    </span>
                  )}
                  {order.status !== 'Delivered' && order.cancellationStatus === 'None' && (
                    <button
                      onClick={() => setCancellationOrderId(order._id)}
                      className="px-3 py-1 bg-red-600 text-white rounded text-sm hover:bg-red-700 mr-2"
                    >
                      Request Cancellation
                    </button>
                  )}
                  {order.status === 'Delivered' && order.returnStatus === 'No Return' && order.returnDeadline && new Date(order.returnDeadline) > new Date() && (
                    <button
                      onClick={() => setReturnOrderId(order._id)}
                      className="px-3 py-1 bg-orange-600 text-white rounded text-sm hover:bg-orange-700 mr-2"
                    >
                      Request Return
                    </button>
                  )}
                  {settings.contactInfoEnabled !== false && (settings.contactWhatsapp || settings.whatsapp || settings.adminWhatsapp || settings.staffWhatsapp) && (
                    <button
                      onClick={() => sendOrderWhatsApp(order)}
                      className="px-3 py-1 bg-green-600 text-white rounded text-sm hover:bg-green-700 mr-2"
                    >
                      Share Order on WhatsApp
                    </button>
                  )}
                  {['Payment Verified', 'Order Preparing', 'Shipped', 'Delivered'].includes(order.status) && (
                    <button
                      onClick={() => downloadInvoice(order)}
                      className="px-3 py-1 bg-slate-700 text-white rounded text-sm hover:bg-slate-800"
                    >
                      Download Invoice
                    </button>
                  )}
                </td>
              </tr>
              {(order.trackingId || order.deliveryCompanyName || order.deliveryCompanyDetails) && (
                <tr className="bg-slate-50">
                  <td colSpan={9} className="p-3 text-sm text-slate-700 border-t border-slate-200">
                    <div className="font-semibold mb-1">Delivery Details</div>
                    {order.deliveryCompanyName && <div><span className="font-medium">Company:</span> {order.deliveryCompanyName}</div>}
                    {order.trackingId && <div><span className="font-medium">Tracking ID:</span> {order.trackingId}</div>}
                    {order.deliveryCompanyDetails && <div><span className="font-medium">Details:</span> {order.deliveryCompanyDetails}</div>}
                  </td>
                </tr>
              )}
            </React.Fragment>
          ))}
          </tbody>
        </table>
        </>
      )}
    </div>
  );
}

'use client';

import { useEffect, useState } from 'react';
import { useSearchParams, useRouter } from 'next/navigation';
import { useSession } from 'next-auth/react';

interface PaymentStatus {
  orderId: string;
  status: 'success' | 'failed' | 'pending' | 'processing' | 'error';
  message: string;
  amount?: number;
  transactionId?: string;
}

export default function PaymentReturnPage() {
  const searchParams = useSearchParams();
  const router = useRouter();
  const { data: session } = useSession();
  const [paymentStatus, setPaymentStatus] = useState<PaymentStatus | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function checkPaymentStatus() {
      const orderId = searchParams?.get('order_id');
      const cfOrderId = searchParams?.get('cf_order_id');
      const status = searchParams?.get('status');
      const txStatus = searchParams?.get('txStatus');

      if (!orderId && !cfOrderId) {
        setPaymentStatus({
          orderId: '',
          status: 'error',
          message: 'No order information received',
        });
        setLoading(false);
        return;
      }

      const finalOrderId = orderId || cfOrderId || '';

      // Check payment status from Cashfree
      try {
        const response = await fetch(`/api/payments/create?orderId=${finalOrderId}`);
        const data = await response.json();

        if (response.ok && data.orderStatus) {
          let paymentStatus: 'success' | 'failed' | 'pending' | 'processing' | 'error' = 'error';
          let message = '';

          switch (data.orderStatus) {
            case 'PAID':
            case 'captured':
              paymentStatus = 'success';
              message = 'Payment successful! Your order is confirmed.';
              break;
            case 'ACTIVE':
            case 'pending':
              paymentStatus = 'pending';
              message = 'Payment is being processed. You will be notified once confirmed.';
              break;
            case 'FAILED':
            case 'failed':
              paymentStatus = 'failed';
              message = 'Payment failed. Please try again or use alternative payment method.';
              break;
            case 'EXPIRED':
              paymentStatus = 'error';
              message = 'Payment session expired. Please try again.';
              break;
            default:
              paymentStatus = 'processing';
              message = 'Processing your payment...';
          }

          setPaymentStatus({
            orderId: finalOrderId,
            status: paymentStatus,
            message,
            amount: data.orderAmount,
            transactionId: data.payments?.[0]?.cf_payment_id,
          });
        } else {
          // Fallback: check URL parameters
          if (txStatus === 'SUCCESS' || status === 'SUCCESS') {
            setPaymentStatus({
              orderId: finalOrderId,
              status: 'success',
              message: 'Payment successful! Your order is confirmed.',
            });
          } else if (txStatus === 'FAILED' || status === 'FAILED') {
            setPaymentStatus({
              orderId: finalOrderId,
              status: 'failed',
              message: 'Payment failed. Please try again.',
            });
          } else {
            setPaymentStatus({
              orderId: finalOrderId,
              status: 'error',
              message: data.error || 'Unable to verify payment status',
            });
          }
        }
      } catch (error) {
        console.error('Payment status check failed:', error);
        
        // Fallback to URL parameters
        if (txStatus === 'SUCCESS' || status === 'SUCCESS') {
          setPaymentStatus({
            orderId: finalOrderId,
            status: 'success',
            message: 'Payment successful! Your order is confirmed.',
          });
        } else if (txStatus === 'FAILED' || status === 'FAILED') {
          setPaymentStatus({
            orderId: finalOrderId,
            status: 'failed',
            message: 'Payment failed. Please try again.',
          });
        } else {
          setPaymentStatus({
            orderId: finalOrderId,
            status: 'error',
            message: 'Unable to verify payment. Please check your orders.',
          });
        }
      }

      setLoading(false);
    }

    checkPaymentStatus();
  }, [searchParams]);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <div className="text-center">
          <div className="animate-spin rounded-full h-16 w-16 border-b-2 border-blue-600 mx-auto mb-4"></div>
          <h2 className="text-xl font-semibold text-gray-800">Verifying Payment...</h2>
          <p className="text-gray-600 mt-2">Please wait while we confirm your payment</p>
        </div>
      </div>
    );
  }

  if (!paymentStatus) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <div className="text-center">
          <h2 className="text-xl font-semibold text-gray-800">Something went wrong</h2>
          <button
            onClick={() => router.push('/cart')}
            className="mt-4 px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700"
          >
            Return to Cart
          </button>
        </div>
      </div>
    );
  }

  const statusConfig = {
    success: {
      icon: '✅',
      color: 'green',
      bgColor: 'bg-green-50',
      borderColor: 'border-green-300',
    },
    failed: {
      icon: '❌',
      color: 'red',
      bgColor: 'bg-red-50',
      borderColor: 'border-red-300',
    },
    pending: {
      icon: '⏳',
      color: 'yellow',
      bgColor: 'bg-yellow-50',
      borderColor: 'border-yellow-300',
    },
    processing: {
      icon: '🔄',
      color: 'blue',
      bgColor: 'bg-blue-50',
      borderColor: 'border-blue-300',
    },
    error: {
      icon: '⚠️',
      color: 'gray',
      bgColor: 'bg-gray-50',
      borderColor: 'border-gray-300',
    },
  };

  const config = statusConfig[paymentStatus.status] || statusConfig.error;

  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-50 p-4">
      <div className={`max-w-md w-full ${config.bgColor} border ${config.borderColor} rounded-lg p-8 shadow-lg`}>
        <div className="text-center">
          <div className="text-6xl mb-4">{config.icon}</div>
          <h2 className={`text-2xl font-bold text-${config.color}-800 mb-2`}>
            {paymentStatus.status === 'success' && 'Payment Successful!'}
            {paymentStatus.status === 'failed' && 'Payment Failed'}
            {paymentStatus.status === 'pending' && 'Payment Pending'}
            {paymentStatus.status === 'processing' && 'Processing Payment'}
            {paymentStatus.status === 'error' && 'Payment Error'}
          </h2>
          <p className="text-gray-700 mb-4">{paymentStatus.message}</p>
          
          {paymentStatus.orderId && (
            <div className="text-sm text-gray-600 mb-4">
              <p>Order ID: <span className="font-mono font-semibold">{paymentStatus.orderId}</span></p>
              {paymentStatus.transactionId && (
                <p>Transaction ID: <span className="font-mono">{paymentStatus.transactionId}</span></p>
              )}
            </div>
          )}

          <div className="flex flex-col gap-3 mt-6">
            {paymentStatus.status === 'success' ? (
              <>
                <button
                  onClick={() => router.push(`/order-success?orderId=${paymentStatus.orderId}`)}
                  className="w-full px-4 py-2 bg-green-600 text-white rounded hover:bg-green-700 font-semibold"
                >
                  View Order Details
                </button>
                <button
                  onClick={() => router.push('/orders')}
                  className="w-full px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700"
                >
                  Go to My Orders
                </button>
              </>
            ) : paymentStatus.status === 'failed' || paymentStatus.status === 'error' ? (
              <>
                <button
                  onClick={() => router.push('/cart')}
                  className="w-full px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700 font-semibold"
                >
                  Try Again
                </button>
                <button
                  onClick={() => router.push('/orders')}
                  className="w-full px-4 py-2 bg-gray-600 text-white rounded hover:bg-gray-700"
                >
                  View My Orders
                </button>
              </>
            ) : (
              <>
                <button
                  onClick={() => router.push('/orders')}
                  className="w-full px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700"
                >
                  Check Order Status
                </button>
                <button
                  onClick={() => router.push('/')}
                  className="w-full px-4 py-2 bg-gray-600 text-white rounded hover:bg-gray-700"
                >
                  Go to Home
                </button>
              </>
            )}
          </div>

          <p className="text-xs text-gray-500 mt-6">
            If you have any questions, please contact support.
          </p>
        </div>
      </div>
    </div>
  );
}

'use client';

import Link from 'next/link';
import { useParams, useRouter } from 'next/navigation';
import { useEffect, useMemo, useState } from 'react';
import { useCart } from '@/components/CartContext';
import { useWishlist } from '@/components/WishlistContext';

interface Variant {
  sku: string;
  attributes: { color?: string; size?: string };
  price: number;
  stock: number;
  images: string[];
}
interface Product {
  _id: string;
  name: string;
  description: string;
  originalPrice: number;
  discountPercent: number;
  gstPercent?: number;
  quantity: number;
  images: string[];
  status?: string;
  variants?: Variant[];
}

export default function ProductDetailPage() {
  const params = useParams();
  const productId = params?.id as string;
  const router = useRouter();
  const { addItem } = useCart();
  const { isInWishlist, addToWishlist, removeFromWishlist } = useWishlist();
  const [product, setProduct] = useState<Product | null>(null);
  const [activeImage, setActiveImage] = useState<string>('');
  const [quantity, setQuantity] = useState<number>(1);
  const [isLoading, setIsLoading] = useState(true);
  const [recentlyViewed, setRecentlyViewed] = useState<Product[]>([]);

  useEffect(() => {
    const loadProduct = async () => {
      setIsLoading(true);
      try {
        const res = await fetch('/api/products', { cache: 'no-store' });
        if (!res.ok) return;
        const data: Product[] = await res.json();
        const match = data.find((item) => item._id === productId);
        if (match) {
          setProduct(match);
          setActiveImage(match.images?.[0] || '');
          const stored = typeof window !== 'undefined' ? window.localStorage.getItem('recentProducts') : null;
          const recent = stored ? (JSON.parse(stored) as Product[]) : [];
          const updated = [match, ...recent.filter((item) => item._id !== match._id)].slice(0, 5);
          if (typeof window !== 'undefined') {
            window.localStorage.setItem('recentProducts', JSON.stringify(updated));
          }
          setRecentlyViewed(updated.filter((item) => item._id !== match._id));
        }
      } catch (error) {
        console.error('Unable to load product', error);
      } finally {
        setIsLoading(false);
      }
    };
    loadProduct();
  }, [productId]);

  const finalPrice = useMemo(() => {
    if (!product) return 0;
    return product.originalPrice * (1 - product.discountPercent / 100);
  }, [product]);

  const handleAddToCart = () => {
    if (!product) return;
    if (quantity < 1) return;
    if (quantity > product.quantity) return;
    addItem({
      productId: product._id,
      name: product.name,
      price: finalPrice,
      gstPercent: product.gstPercent || 0,
      quantity,
    });
    router.push('/cart');
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center px-4 py-16">
        <div className="text-center">
          <div className="h-16 w-16 rounded-full border-4 border-blue-600 border-t-transparent animate-spin mx-auto"></div>
          <p className="mt-4 text-slate-600">Loading product details...</p>
        </div>
      </div>
    );
  }

  if (!product) {
    return (
      <div className="min-h-screen px-4 py-20 text-center">
        <p className="text-xl font-semibold text-slate-900">Product not found</p>
        <p className="mt-3 text-slate-500">Please return to the homepage or choose another item.</p>
        <div className="mt-6">
          <Link href="/" className="rounded-full bg-blue-600 px-6 py-3 text-sm font-semibold text-white hover:bg-blue-700">
            Back to Home
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 px-4 py-10 sm:px-6 lg:px-8">
      <div className="mx-auto max-w-7xl space-y-8">
        <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
          <div>
            <p className="text-sm uppercase tracking-[0.3em] text-slate-500">Product details</p>
            <h1 className="mt-3 text-3xl font-bold text-slate-900">{product.name}</h1>
          </div>
          <Link href="/cart" className="inline-flex items-center rounded-full bg-white px-4 py-3 text-sm font-semibold text-slate-700 shadow-sm ring-1 ring-slate-200 hover:bg-slate-50">
            🛒 View Cart
          </Link>
        </div>

        <div className="grid gap-8 xl:grid-cols-[1.35fr_0.65fr]">
          <section className="space-y-6 rounded-[32px] bg-white p-6 shadow-soft">
            <div className="grid gap-4 lg:grid-cols-[1.2fr_0.8fr]">
              <div className="rounded-[32px] overflow-hidden bg-slate-100">
                <img src={activeImage || '/icon-192.png'} alt={product.name} className="h-full w-full object-cover" />
              </div>
              <div className="space-y-4">
                <div className="grid grid-cols-4 gap-3">
                  {product.images?.slice(0, 4).map((image) => (
                    <button
                      key={image}
                      type="button"
                      onClick={() => setActiveImage(image)}
                      className={`overflow-hidden rounded-3xl border ${activeImage === image ? 'border-blue-600' : 'border-slate-200'} bg-white`}
                    >
                      <img src={image} alt={product.name} className="h-24 w-full object-cover" />
                    </button>
                  ))}
                </div>
                <div className="rounded-[28px] bg-slate-50 p-5">
                  <div className="flex items-center justify-between gap-2">
                    <span className="rounded-full bg-emerald-100 px-3 py-1 text-xs font-semibold uppercase text-emerald-700">{product.quantity > 0 ? 'In stock' : 'Out of stock'}</span>
                    <span className="text-sm text-slate-500">Est. delivery: 2-5 days</span>
                  </div>
                  <div className="mt-5 space-y-3">
                    <p className="text-slate-500">Product code</p>
                    <p className="text-base font-semibold text-slate-900">{product._id}</p>
                  </div>
                </div>
              </div>
            </div>

            <div className="space-y-5">
              {/* Product Variants Table */}
              {product.variants && product.variants.length > 0 && (
                <div className="mb-6">
                  <h3 className="text-lg font-semibold text-gray-800 mb-2">Variants</h3>
                  <div className="overflow-x-auto">
                    <table className="min-w-full text-xs border">
                      <thead>
                        <tr className="bg-gray-100">
                          <th className="p-2 border">SKU</th>
                          <th className="p-2 border">Color</th>
                          <th className="p-2 border">Size</th>
                          <th className="p-2 border">Price</th>
                          <th className="p-2 border">Stock</th>
                          <th className="p-2 border">Images</th>
                        </tr>
                      </thead>
                      <tbody>
                        {product.variants.map((v, idx) => (
                          <tr key={v.sku + idx}>
                            <td className="p-2 border">{v.sku}</td>
                            <td className="p-2 border">{v.attributes?.color || ''}</td>
                            <td className="p-2 border">{v.attributes?.size || ''}</td>
                            <td className="p-2 border">₹{v.price}</td>
                            <td className="p-2 border">{v.stock}</td>
                            <td className="p-2 border">
                              {(v.images || []).map((img, i) => (
                                <img key={img + i} src={img} alt="var-img" width={24} height={24} className="inline-block mr-1 rounded border" />
                              ))}
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              )}
              <div className="rounded-[32px] bg-slate-50 p-6">
                <div className="flex flex-wrap items-center gap-4">
                  <div>
                    <p className="text-xs uppercase tracking-[0.3em] text-slate-500">Price</p>
                    <p className="mt-2 text-4xl font-semibold text-slate-900">₹{finalPrice.toFixed(2)}</p>
                    {product.discountPercent > 0 && (
                      <p className="text-sm text-slate-500 line-through">₹{product.originalPrice.toFixed(2)}</p>
                    )}
                  </div>
                  <div className="flex items-center gap-3 rounded-3xl bg-white px-4 py-2 text-sm font-semibold text-slate-700 shadow-sm ring-1 ring-slate-200">
                    {product.discountPercent > 0 ? `${product.discountPercent}% off` : 'Best value'}
                    <button
                      type="button"
                      aria-label={isInWishlist(product._id) ? 'Remove from wishlist' : 'Add to wishlist'}
                      className={`ml-2 text-xl ${isInWishlist(product._id) ? 'text-pink-600' : 'text-gray-400 hover:text-pink-500'}`}
                      onClick={async (e) => {
                        e.stopPropagation();
                        if (isInWishlist(product._id)) await removeFromWishlist(product._id);
                        else await addToWishlist(product._id);
                      }}
                    >
                      {isInWishlist(product._id) ? '♥' : '♡'}
                    </button>
                  </div>
                </div>

                <div className="mt-6 grid gap-4 sm:grid-cols-2">
                  <div className="rounded-3xl bg-white p-4 text-sm text-slate-600 shadow-sm ring-1 ring-slate-200">
                    GST: {product.gstPercent ?? 0}%
                  </div>
                  <div className="rounded-3xl bg-white p-4 text-sm text-slate-600 shadow-sm ring-1 ring-slate-200">
                    Condition: Refurbished
                  </div>
                </div>
              </div>

              <div className="grid gap-4 sm:grid-cols-[1fr_0.8fr]">
                <div className="rounded-[32px] bg-slate-50 p-6 shadow-sm ring-1 ring-slate-200">
                  <h2 className="text-lg font-semibold text-slate-900">Overview</h2>
                  <p className="mt-3 text-slate-600">{product.description || 'This refurbished product has been inspected and tested for quality. It offers reliable performance at a smart price.'}</p>
                </div>
                <div className="rounded-[32px] bg-slate-50 p-6 shadow-sm ring-1 ring-slate-200">
                  <h2 className="text-lg font-semibold text-slate-900">Why buy it</h2>
                  <ul className="mt-4 space-y-3 text-slate-600">
                    <li>✅ Thoroughly tested by experts</li>
                    <li>✅ Secure checkout and warranty support</li>
                    <li>✅ Fast delivery and customer help</li>
                  </ul>
                </div>
              </div>
            </div>
          </section>

          <aside className="space-y-6">
            <div className="rounded-[32px] bg-white p-6 shadow-soft ring-1 ring-slate-200">
              <p className="text-sm uppercase tracking-[0.3em] text-slate-500">Checkout</p>
              <div className="mt-4 space-y-4">
                <div className="rounded-3xl bg-slate-50 p-4">
                  <label className="text-sm font-semibold text-slate-700">Quantity</label>
                  <div className="mt-3 flex items-center justify-between gap-3 rounded-3xl border border-slate-200 bg-white px-4 py-3">
                    <button
                      type="button"
                      onClick={() => setQuantity((value) => Math.max(1, value - 1))}
                      className="inline-flex h-10 w-10 items-center justify-center rounded-2xl border border-slate-200 text-slate-700"
                    >
                      −
                    </button>
                    <span className="text-lg font-semibold text-slate-900">{quantity}</span>
                    <button
                      type="button"
                      onClick={() => setQuantity((value) => Math.min(product.quantity, value + 1))}
                      className="inline-flex h-10 w-10 items-center justify-center rounded-2xl border border-slate-200 text-slate-700"
                    >
                      +
                    </button>
                  </div>
                </div>

                <button
                  type="button"
                  onClick={handleAddToCart}
                  disabled={product.quantity <= 0}
                  className="w-full rounded-full bg-gradient-to-r from-blue-600 to-cyan-500 px-4 py-4 text-sm font-semibold text-white shadow-lg shadow-cyan-500/10 transition hover:opacity-95 disabled:cursor-not-allowed disabled:bg-slate-300 disabled:text-slate-500"
                >
                  Add to cart
                </button>

                <button
                  type="button"
                  onClick={() => router.push('/cart')}
                  className="w-full rounded-full border border-slate-200 bg-white px-4 py-4 text-sm font-semibold text-slate-900 transition hover:bg-slate-50"
                >
                  View cart
                </button>
              </div>
            </div>

            <div className="rounded-[32px] bg-slate-50 p-6 shadow-sm ring-1 ring-slate-200">
              <h3 className="text-lg font-semibold text-slate-900">Need help?</h3>
              <p className="mt-3 text-sm text-slate-600">Reach out to support for product advice, delivery updates or returns.</p>
              <div className="mt-4 space-y-3">
                <Link href="/support-tickets" className="block rounded-3xl bg-white px-4 py-3 text-sm font-semibold text-slate-900 shadow-sm ring-1 ring-slate-200 hover:bg-slate-100">
                  Create a support ticket
                </Link>
                <Link href="/" className="block rounded-3xl bg-blue-600 px-4 py-3 text-sm font-semibold text-white hover:bg-blue-700">
                  Browse more products
                </Link>
              </div>
            </div>

            {recentlyViewed.length > 0 && (
              <div className="rounded-[32px] bg-white p-6 shadow-soft ring-1 ring-slate-200">
                <h3 className="text-lg font-semibold text-slate-900">Recently viewed</h3>
                <div className="mt-4 space-y-3">
                  {recentlyViewed.map((item) => (
                    <button
                      key={item._id}
                      type="button"
                      onClick={() => router.push(`/product/${item._id}`)}
                      className="w-full text-left rounded-3xl border border-slate-200 bg-slate-50 px-4 py-3 text-sm text-slate-700 transition hover:bg-slate-100"
                    >
                      {item.name}
                    </button>
                  ))}
                </div>
              </div>
            )}
          </aside>
        </div>
      </div>
    </div>
  );
}

'use client';

import { useCallback, useEffect, useMemo, useState } from 'react';
import Link from 'next/link';
import { useParams, useRouter } from 'next/navigation';
import { useSession } from 'next-auth/react';
import CallRoom from '@/components/CallRoom';

interface ConsumerUser {
  _id: string;
  name?: string;
  email?: string;
  mobile?: string;
  customerId?: string;
}

interface ConsumerChat {
  _id: string;
  type: 'consumer';
  status: 'pending' | 'active' | 'closed';
  participants: ConsumerUser[];
  targetUser: ConsumerUser;
  user: ConsumerUser;
  requestedAt?: string;
  acceptedAt?: string;
  lastMessageAt?: string;
}

interface ConsumerMessage {
  _id: string;
  sender: 'user' | 'admin' | 'bot';
  senderId?: string;
  senderName?: string;
  type: 'text' | 'audio' | 'image';
  content: string;
  metadata?: any;
  createdAt: string;
  seen?: boolean;
}

export default function ProfileChatConversationPage() {
  const params = useParams();
  const router = useRouter();
  const { data: session, status } = useSession();
  const chatId = Array.isArray(params?.chatId) ? params.chatId[0] : params?.chatId;

  const [chat, setChat] = useState<ConsumerChat | null>(null);
  const [messages, setMessages] = useState<ConsumerMessage[]>([]);
  const [loading, setLoading] = useState(true);
  const [statusText, setStatusText] = useState('');
  const [newMessage, setNewMessage] = useState('');
  const [typingStatus, setTypingStatus] = useState('');
  const [otherUserOnline, setOtherUserOnline] = useState(false);
  const [selectedImage, setSelectedImage] = useState<File | null>(null);
  const [uploading, setUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [isRecording, setIsRecording] = useState(false);
  const [mediaRecorder, setMediaRecorder] = useState<MediaRecorder | null>(null);
  const [typingTimeout, setTypingTimeout] = useState<number | null>(null);

  const otherUser = useMemo(
    () => chat?.participants.find((user) => user._id !== session?.user?.id) ?? null,
    [chat, session?.user?.id]
  );

  const fetchChat = useCallback(async () => {
    if (!chatId) return;
    setLoading(true);
    try {
      const res = await fetch(`/api/consumer-chats/${chatId}`);
      if (!res.ok) {
        const errorData = await res.json().catch(() => ({}));
        setStatusText(errorData.error || 'Unable to load conversation');
        setChat(null);
        return;
      }
      const data = await res.json();
      setChat(data.chat || null);
    } catch (err) {
      console.error(err);
      setStatusText('Unable to load conversation');
      setChat(null);
    } finally {
      setLoading(false);
    }
  }, [chatId]);

  const fetchMessages = useCallback(async () => {
    if (!chatId) return;
    try {
      const res = await fetch(`/api/consumer-chats/${chatId}/messages`);
      if (!res.ok) return;
      const data = await res.json();
      setMessages(data.messages || []);
    } catch (err) {
      console.error(err);
    }
  }, [chatId]);

  const checkOnlineStatus = useCallback(async (userId: string) => {
    if (!userId) return false;
    try {
      const res = await fetch(`/api/user/online-status?userId=${userId}`);
      if (!res.ok) return false;
      const data = await res.json();
      return data.online === true;
    } catch (err) {
      console.error(err);
      return false;
    }
  }, []);

  useEffect(() => {
    if (status === 'unauthenticated') {
      router.push('/login');
      return;
    }
    if (status === 'authenticated') {
      fetchChat();
      fetchMessages();
      const refreshInterval = window.setInterval(() => {
        fetchMessages();
        fetchChat();
      }, 5000);
      return () => window.clearInterval(refreshInterval);
    }
  }, [status, router, fetchChat, fetchMessages]);

  useEffect(() => {
    if (otherUser?._id) {
      checkOnlineStatus(otherUser._id).then(setOtherUserOnline);
    } else {
      setOtherUserOnline(false);
    }
  }, [checkOnlineStatus, otherUser]);

  const parseJsonResponse = async (response: Response) => {
    const text = await response.text();
    if (!text) return {};
    try {
      return JSON.parse(text);
    } catch (error) {
      console.error('Unable to parse response:', error, text);
      return { error: 'Unexpected server response' };
    }
  };

  const sendMessage = async (type: 'text' | 'audio' | 'image' = 'text', content: string, metadata: any = {}) => {
    if (!chatId || !content.trim()) return;
    setStatusText('Sending message...');
    try {
      const res = await fetch(`/api/consumer-chats/${chatId}/messages`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ type, content: content.trim(), metadata }),
      });
      const data = await parseJsonResponse(res);
      if (!res.ok) {
        setStatusText(data.error || 'Message failed');
        return;
      }
      setNewMessage('');
      setSelectedImage(null);
      setUploadProgress(0);
      setStatusText('');
      await fetchMessages();
      await fetchChat();
    } catch (err) {
      console.error(err);
      setStatusText('Message send failed');
    }
  };

  const acceptChat = async () => {
    if (!chatId) return;
    setStatusText('Accepting chat request...');
    try {
      const res = await fetch(`/api/consumer-chats/${chatId}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'accept' }),
      });
      const data = await parseJsonResponse(res);
      if (!res.ok) {
        setStatusText(data.error || 'Unable to accept chat request');
        return;
      }
      setStatusText('Chat request accepted. You can now continue messaging.');
      await fetchChat();
      await fetchMessages();
    } catch (err) {
      console.error(err);
      setStatusText('Unable to accept chat request');
    }
  };

  const closeConversation = async () => {
    if (!chatId) return;
    setStatusText('Closing conversation...');
    try {
      const res = await fetch(`/api/consumer-chats/${chatId}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'close' }),
      });
      const data = await parseJsonResponse(res);
      if (!res.ok) {
        setStatusText(data.error || 'Unable to close conversation');
        return;
      }
      setStatusText('Conversation closed.');
      await fetchChat();
      await fetchMessages();
    } catch (err) {
      console.error(err);
      setStatusText('Unable to close conversation');
    }
  };

  const readFileAsDataURL = (file: Blob, onProgress?: (percent: number) => void): Promise<string> =>
    new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onprogress = (event) => {
        if (event.lengthComputable && onProgress) {
          onProgress(Math.round((event.loaded / event.total) * 100));
        }
      };
      reader.onload = () => {
        if (typeof reader.result === 'string') {
          onProgress?.(100);
          resolve(reader.result);
        } else {
          reject(new Error('Unable to read file as data URL'));
        }
      };
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });

  const handleImageSelect = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file && file.type.startsWith('image/')) {
      setSelectedImage(file);
      setUploadProgress(0);
      setStatusText('');
    }
  };

  const uploadAndSendAudio = async (blob: Blob) => {
    setUploading(true);
    setUploadProgress(0);
    try {
      const dataUrl = await readFileAsDataURL(blob, setUploadProgress);
      await sendMessage('audio', dataUrl, { fileName: `audio_${Date.now()}.webm` });
    } catch (err) {
      console.error(err);
      setStatusText('Failed to upload audio');
    } finally {
      setUploading(false);
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const recorder = new MediaRecorder(stream);
      const chunks: Blob[] = [];

      recorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          chunks.push(event.data);
        }
      };

      recorder.onstop = async () => {
        const audioBlob = new Blob(chunks, { type: 'audio/webm' });
        await uploadAndSendAudio(audioBlob);
        stream.getTracks().forEach((track) => track.stop());
      };

      recorder.start();
      setMediaRecorder(recorder);
      setIsRecording(true);
      setStatusText('Recording audio...');
    } catch (err) {
      console.error(err);
      setStatusText('Failed to start recording');
    }
  };

  const stopRecording = () => {
    if (mediaRecorder && isRecording) {
      mediaRecorder.stop();
      setIsRecording(false);
      setStatusText('Uploading audio...');
    }
  };

  const sendImage = async () => {
    if (!selectedImage) return;
    setUploading(true);
    setUploadProgress(0);
    try {
      const dataUrl = await readFileAsDataURL(selectedImage, setUploadProgress);
      await sendMessage('image', dataUrl, {
        fileName: selectedImage.name,
        size: selectedImage.size,
        mimeType: selectedImage.type,
      });
      setSelectedImage(null);
    } catch (err) {
      console.error(err);
      setStatusText('Failed to upload image');
    } finally {
      setUploading(false);
    }
  };

  const handleTypingInput = (value: string) => {
    setNewMessage(value);
    if (typingTimeout) {
      clearTimeout(typingTimeout);
    }
    const timeout = window.setTimeout(() => setTypingStatus(''), 3000);
    setTypingTimeout(timeout);
    if (value.trim()) {
      setTypingStatus('Typing...');
    }
  };

  if (status === 'loading') {
    return <div className="min-h-screen bg-slate-50 p-6">Loading conversation...</div>;
  }

  return (
    <div className="min-h-screen bg-slate-50 p-4 sm:p-6">
      <div className="mx-auto flex max-w-6xl flex-col gap-6">
        <div className="rounded-[32px] bg-white p-5 shadow-sm border border-slate-200">
          <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
            <div className="space-y-2">
              <Link href="/profile" className="inline-flex items-center gap-2 text-sm text-slate-600 hover:text-slate-900">
                ← Back to profile
              </Link>
              <div>
                <h1 className="text-3xl font-bold text-slate-900">Conversation</h1>
                <p className="mt-1 text-sm text-gray-600">A dedicated mobile-first chat page for customer conversations.</p>
              </div>
            </div>
            {chat && (
              <div className="rounded-3xl bg-slate-50 px-4 py-3 text-sm text-slate-700">
                {otherUser ? `${otherUser.name || otherUser.email || otherUser.mobile || 'Customer'}` : 'Chat details'}
              </div>
            )}
          </div>
        </div>

        <div className="grid gap-6 lg:grid-cols-[1.05fr_0.95fr]">
          <div className="space-y-6">
            <div className="rounded-[32px] bg-white p-5 shadow-sm border border-slate-200">
              <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
                <div>
                  <h2 className="text-2xl font-semibold text-slate-900">{chat?.participants ? otherUser?.name || otherUser?.email || otherUser?.mobile || 'Conversation' : 'Loading conversation...'}</h2>
                  <p className="mt-1 text-sm text-gray-600">{chat ? `Status: ${chat.status}` : 'Fetching conversation details.'}</p>
                </div>
                {chat?.status === 'pending' && otherUser?._id === session?.user?.id && (
                  <button onClick={acceptChat} className="rounded-2xl bg-blue-600 px-4 py-3 text-sm font-semibold text-white hover:bg-blue-700">Accept request</button>
                )}
              </div>

              {statusText && <div className="mt-4 rounded-3xl bg-amber-50 p-4 text-sm text-amber-900 border border-amber-200">{statusText}</div>}

              {chat && (
                <div className="mt-4 flex flex-wrap gap-3 text-sm text-slate-700">
                  <span className="rounded-full bg-slate-100 px-3 py-2">Requested: {chat.requestedAt ? new Date(chat.requestedAt).toLocaleString() : 'Unknown'}</span>
                  {chat.acceptedAt && <span className="rounded-full bg-slate-100 px-3 py-2">Accepted: {new Date(chat.acceptedAt).toLocaleString()}</span>}
                  <span className="rounded-full bg-slate-100 px-3 py-2">Updated: {chat.lastMessageAt ? new Date(chat.lastMessageAt).toLocaleString() : 'No messages yet'}</span>
                </div>
              )}
            </div>

            <div className="rounded-[32px] bg-white p-5 shadow-sm border border-slate-200">
              <div className="flex items-center justify-between gap-3">
                <div>
                  <h2 className="text-xl font-semibold text-slate-900">Messages</h2>
                  <p className="mt-1 text-sm text-gray-600">Swipe through messages in a dedicated chat experience.</p>
                </div>
                <span className={`rounded-full px-3 py-1 text-xs font-semibold ${otherUserOnline ? 'bg-emerald-100 text-emerald-900' : 'bg-slate-100 text-slate-700'}`}>
                  {otherUserOnline ? 'Online' : 'Offline'}
                </span>
              </div>

              <div className="mt-5 rounded-[32px] border border-slate-200 bg-slate-50 p-4 max-h-[66vh] overflow-y-auto">
                {loading && <p className="text-sm text-gray-500">Loading chat...</p>}
                {!loading && !chat && <p className="text-sm text-gray-500">Conversation not found or not accessible.</p>}
                {!loading && chat && messages.length === 0 && <p className="text-sm text-gray-500">No messages yet. Start the conversation below.</p>}

                <div className="space-y-4">
                  {messages.map((message) => (
