          <div>
            <label className="block text-sm font-medium mb-2">AWB Number</label>
            <div className="flex gap-2">
              <input
                type="text"
                value={awbNumber}
                onChange={(e) => setAwbNumber(e.target.value)}
                placeholder="Enter AWB number"
