      {/* Footer */}
      <footer className="mt-12 border-t border-blue-200 bg-white/50 backdrop-blur-sm">
        <div className="mx-auto max-w-7xl px-4 py-6 sm:px-6 lg:px-8">
          <div className="text-center text-sm text-gray-600">
            <p>Chat Mode Active - Connect with other consumers on PC Studio</p>
            <p className="mt-1">© 2026 PC Studio. All rights reserved.</p>
          </div>
        </div>
      </footer>
    </div>
  );
}

'use client';

import Link from 'next/link';
import { useEffect, useMemo, useRef, useState, useCallback } from 'react';
import { usePathname } from 'next/navigation';
import { useSession } from 'next-auth/react';
import { buildAdminGreeting, generateAdminBotResponse } from '@/lib/chatBot';

interface ChatItem {
  _id: string;
  status: 'active' | 'closed';
  escalated: boolean;
  joinedAt?: string;
  requestedByAdmin?: string;
}

interface MessageItem {
  _id: string;
  sender: 'user' | 'admin' | 'bot';
  message: string;
  seen: boolean;
  delivered?: boolean;
  createdAt: string;
}

interface AdminMessage {
  sender: 'user' | 'bot';
  message: string;
}

export default function ChatWidget() {
  const { data: session, status } = useSession();
  const [open, setOpen] = useState(false);
  const [chat, setChat] = useState<ChatItem | null>(null);
  const [messages, setMessages] = useState<MessageItem[]>([]);
  const [botName, setBotName] = useState('ShopBot');
  const [_botEnabled, setBotEnabled] = useState(true);

  const normalizeMessages = (msgs: any[]) => {
    return msgs.map((msg) => ({
      ...msg,
      message: msg.message || msg.content || '',
    }));
  };
  const [chatEnabled, setChatEnabled] = useState(true);
  const [showSupportOption, setShowSupportOption] = useState(false);
  const [settingsLoaded, setSettingsLoaded] = useState(false);
  const [supportStartTime, setSupportStartTime] = useState('09:00');
  const [supportEndTime, setSupportEndTime] = useState('17:00');
  const [input, setInput] = useState('');
  const [adminInput, setAdminInput] = useState('');
  const [adminMessages, setAdminMessages] = useState<AdminMessage[]>([]);
  const [loading, setLoading] = useState(false);
  const [sending, setSending] = useState(false);
  const [error, setError] = useState('');
  
  // Draggable state
  const [position, setPosition] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });
  const [dragType, setDragType] = useState<'mouse' | 'touch' | null>(null);
  const widgetRef = useRef<HTMLDivElement | null>(null);
  
  const messagesEndRef = useRef<HTMLDivElement | null>(null);
  const pathname = usePathname();
  const isAdminPage = pathname?.startsWith('/admin');
  const canAdminChat = status === 'authenticated' && (session?.user?.role === 'admin' || session?.user?.role === 'staff');
  const canCustomerChat = status === 'authenticated' && session?.user?.role === 'customer';
  const canChat = canCustomerChat || (canAdminChat && isAdminPage);

  // Load position from localStorage on mount
  useEffect(() => {
    const savedPosition = localStorage.getItem('chatWidgetPosition');
    if (savedPosition) {
      setPosition(JSON.parse(savedPosition));
    } else {
      // Default position: bottom right for mobile, adjust for desktop
      const isMobile = window.innerWidth < 768;
      setPosition({
        x: isMobile ? window.innerWidth - 120 : window.innerWidth - 120,
        y: isMobile ? window.innerHeight - 120 : window.innerHeight - 120
      });
    }
  }, []);

  // Handle pointer down for dragging (mouse + touch)
  const handlePointerDown = (e: React.PointerEvent) => {
    e.preventDefault();
    setIsDragging(true);
    setDragType(e.pointerType === 'touch' ? 'touch' : 'mouse');
    const rect = widgetRef.current?.getBoundingClientRect();
    if (rect) {
      setDragOffset({
        x: e.clientX - rect.left,
        y: e.clientY - rect.top,
      });
    }
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    e.preventDefault();
    setIsDragging(true);
    setDragType('touch');
    const rect = widgetRef.current?.getBoundingClientRect();
    if (rect && e.touches[0]) {
      setDragOffset({
        x: e.touches[0].clientX - rect.left,
        y: e.touches[0].clientY - rect.top,
      });
    }
  };

  // Handle move for dragging
  useEffect(() => {
    const handlePointerMove = (e: PointerEvent) => {
      if (!isDragging || !widgetRef.current) return;

      const newX = e.clientX - dragOffset.x;
      const newY = e.clientY - dragOffset.y;

      // Constrain to viewport
      const maxX = window.innerWidth - (widgetRef.current.offsetWidth || 100);
      const maxY = window.innerHeight - (widgetRef.current.offsetHeight || 100);

      const constrainedX = Math.max(0, Math.min(newX, maxX));
      const constrainedY = Math.max(0, Math.min(newY, maxY));

      setPosition({ x: constrainedX, y: constrainedY });
    };

    const handleTouchMove = (e: TouchEvent) => {
      if (!isDragging || !widgetRef.current || !e.touches[0]) return;
      e.preventDefault();

      const newX = e.touches[0].clientX - dragOffset.x;
      const newY = e.touches[0].clientY - dragOffset.y;
      const maxX = window.innerWidth - (widgetRef.current.offsetWidth || 100);
      const maxY = window.innerHeight - (widgetRef.current.offsetHeight || 100);
      const constrainedX = Math.max(0, Math.min(newX, maxX));
      const constrainedY = Math.max(0, Math.min(newY, maxY));

      setPosition({ x: constrainedX, y: constrainedY });
    };

    const handlePointerUp = () => {
      if (isDragging) {
        setIsDragging(false);
        setDragType(null);
      }
    };

    if (isDragging) {
      if (window.PointerEvent) {
        window.addEventListener('pointermove', handlePointerMove);
        window.addEventListener('pointerup', handlePointerUp);
      } else {
        window.addEventListener('touchmove', handleTouchMove, { passive: false });
        window.addEventListener('touchend', handlePointerUp);
        window.addEventListener('touchcancel', handlePointerUp);
      }
    }

    return () => {
      if (window.PointerEvent) {
        window.removeEventListener('pointermove', handlePointerMove);
        window.removeEventListener('pointerup', handlePointerUp);
      } else {
        window.removeEventListener('touchmove', handleTouchMove);
        window.removeEventListener('touchend', handlePointerUp);
        window.removeEventListener('touchcancel', handlePointerUp);
      }
    };
  }, [isDragging, dragOffset]);

  // Update position on window resize (especially for mobile orientation changes)
  useEffect(() => {
    const handleResize = () => {
      const isMobile = window.innerWidth < 768;
      const newX = Math.min(position.x, window.innerWidth - 120);
      const newY = Math.min(position.y, window.innerHeight - 120);

      // Ensure widget stays within viewport bounds
      setPosition({
        x: Math.max(0, newX),
        y: Math.max(0, newY)
      });
    };

    window.addEventListener('resize', handleResize);
    window.addEventListener('orientationchange', handleResize);

    return () => {
      window.removeEventListener('resize', handleResize);
      window.removeEventListener('orientationchange', handleResize);
    };
  }, [position.x, position.y]);

  const fetchChat = useCallback(async () => {
    if (status !== 'authenticated') return;
    setLoading(true);
    try {
      const res = await fetch('/api/chats?active=true');
      if (!res.ok) return;
      const data = await res.json();
      if (data.chat) {
        setChat(data.chat);
        setMessages(normalizeMessages(data.messages || []));
      }
    } catch (err) {
      console.error('Chat fetch failed:', err);
    } finally {
      setLoading(false);
    }
  }, [status]);

  const fetchSettings = useCallback(async () => {
    try {
      const res = await fetch('/api/chat-settings');
      if (!res.ok) return;
      const data = await res.json();
      setChatEnabled(data.chatEnabled !== false);
      setBotName(data.chatBotName || 'ShopBot');
      setBotEnabled(data.chatBotEnabled !== false);
      setSupportStartTime(data.paymentVerificationStartTime || '09:00');
      setSupportEndTime(data.paymentVerificationEndTime || '17:00');
    } catch (err) {
      console.error('Chat settings fetch failed:', err);
    } finally {
      setSettingsLoaded(true);
    }
  }, []);

  const fetchMessages = useCallback(async (chatId: string) => {
    try {
      const res = await fetch(`/api/chats/${chatId}/messages`);
      if (!res.ok) return;
      const data = await res.json();
      setMessages(data.messages || []);
      await markMessagesSeen(chatId);
    } catch (err) {
      console.error('Message fetch failed:', err);
    }
  }, []);

  const markMessagesSeen = async (chatId: string) => {
    try {
      await fetch(`/api/chats/${chatId}/messages?markSeen=true`, { method: 'PATCH' });
    } catch (err) {
      console.error('Failed to mark messages seen:', err);
    }
  };

  const createChat = async () => {
    setLoading(true);
    try {
      const res = await fetch('/api/chats', { method: 'POST' });
      if (!res.ok) {
        const data = await res.json().catch(() => ({}));
        setError(data.error || 'Unable to create chat session');
        return;
      }
      const data = await res.json();
      setChat(data.chat);
      setMessages(normalizeMessages(data.messages || []));
      setShowSupportOption(false);
    } catch (err) {
      console.error('Create chat failed:', err);
      setError('Unable to create chat session');
    } finally {
      setLoading(false);
    }
  };

  const sendMessage = async () => {
    if (!chat || !input.trim()) return;
    if (isPendingAdminRequest) {
      setError('Please accept the admin chat request before sending messages.');
      return;
    }
    setSending(true);
    setError('');
    try {
      const res = await fetch(`/api/chats/${chat._id}/messages`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ message: input.trim() }),
      });
      const data = await res.json();
      if (!res.ok) {
        setError(data.error || 'Failed to send message');
        return;
      }
      setChat(data.chat);
      setMessages(normalizeMessages(data.messages || []));
      setShowSupportOption(data.showSupportOption ?? false);
      setInput('');
      if (data.escalationRequested) {
        setError('A Support Specialist has been requested. Please wait for an agent.');
      }
    } catch (err) {
      console.error('Send message failed:', err);
      setError('Failed to send message. Please try again.');
    } finally {
      setSending(false);
    }
  };

  const connectToHuman = async () => {
    if (!chat) return;
    setSending(true);
    setError('');
    try {
      const res = await fetch(`/api/chats/${chat._id}/messages`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ escalate: true }),
      });
      const data = await res.json();
      if (!res.ok) {
        setError(data.error || 'Failed to connect to support.');
        return;
      }
      setChat(data.chat);
      setMessages(data.messages || []);
      setShowSupportOption(data.showSupportOption ?? false);
      if (data.escalationRequested) {
        setError('A Support Specialist has been requested. Please wait for an agent.');
      }
    } catch (err) {
      console.error('Connect human failed:', err);
      setError('Failed to connect to support. Please try again.');
    } finally {
      setSending(false);
    }
  };

  const acceptChatRequest = async () => {
    if (!chat) return;
    setSending(true);
    setError('');
    try {
      const res = await fetch(`/api/chats/${chat._id}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ acceptJoin: true }),
      });
      const data = await res.json();
      if (!res.ok) {
        setError(data.error || 'Failed to accept chat request.');
        return;
      }
      setChat(data.chat);
      await fetchMessages(chat._id);
    } catch (err) {
      console.error('Accept chat request failed:', err);
      setError('Failed to accept chat request. Please try again.');
    } finally {
      setSending(false);
    }
  };

  const sendAdminMessage = () => {
    if (!adminInput.trim()) return;
    const messageText = adminInput.trim();
    const updatedMessages: AdminMessage[] = [...adminMessages, { sender: 'user', message: messageText }];
    setAdminMessages(updatedMessages);
    setAdminInput('');
    const botResult = generateAdminBotResponse(messageText, updatedMessages);
    setTimeout(() => {
      setAdminMessages((prev) => [...prev, { sender: 'bot', message: botResult.text }]);
    }, 100);
  };

  useEffect(() => {
    fetchSettings();
  }, []);

  useEffect(() => {
    if (open && session?.user && status === 'authenticated' && canCustomerChat) {
      fetchChat();
    }
  }, [open, status, session, canCustomerChat, fetchChat]);

  useEffect(() => {
    if (open && canAdminChat && isAdminPage && adminMessages.length === 0) {
      setAdminMessages([{ sender: 'bot', message: buildAdminGreeting(botName) }]);
    }
  }, [open, canAdminChat, isAdminPage, adminMessages.length, botName]);

  useEffect(() => {
    if (chat?.status === 'active' && canCustomerChat) {
      const interval = setInterval(() => fetchChat(), 15000); // Increased from 5s to 15s
      return () => clearInterval(interval);
    }
  }, [chat, fetchChat, canCustomerChat]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const supportAvailable = useMemo(() => {
    const parseTime = (value: string) => {
      const [hours, minutes] = value.split(':').map(Number);
      return hours * 60 + minutes;
    };
    const start = parseTime(supportStartTime);
    const end = parseTime(supportEndTime);
    const now = new Date();
    const current = now.getHours() * 60 + now.getMinutes();

    if (start <= end) {
      return current >= start && current < end;
    }
    return current >= start || current < end;
  }, [supportStartTime, supportEndTime]);

  const isPendingAdminRequest = Boolean(chat?.escalated && !chat?.joinedAt && chat?.requestedByAdmin);
  const showJoinChatOption = Boolean(isPendingAdminRequest);

  const statusLabel = useMemo(() => {
    if (canAdminChat && isAdminPage) {
      return 'Admin assistant';
    }
    if (!chat) return chatEnabled ? 'No active chat' : 'Live chat disabled';
    if (chat.status === 'closed') return 'Closed';
    if (chat.escalated) {
      if (chat.requestedByAdmin) {
        return chat.joinedAt ? 'Agent joined the chat' : 'Agent requested chat';
      }
      return supportAvailable ? 'Connected to Support Specialist' : 'Support Specialist not available';
    }
    return 'Chatting with bot';
  }, [chat, supportAvailable, chatEnabled, canAdminChat, isAdminPage]);

  if (!settingsLoaded) {
    return null;
  }

  if (!chatEnabled && !canAdminChat) {
    return null;
  }

  const badgeCount = messages.filter((msg) => msg.sender !== 'user' && !msg.seen).length;

  return (
    <div
      ref={widgetRef}
      className="fixed z-[2147483647]"
      style={{
        left: `${position.x}px`,
        top: `${position.y}px`,
        cursor: isDragging ? 'grabbing' : 'grab',
        zIndex: 2147483647,
      }}
    >
      <button
        type="button"
        onPointerDown={handlePointerDown}
        onTouchStart={handleTouchStart}
        onMouseDown={handlePointerDown as any}
        onClick={(e) => {
          if (!isDragging) {
            e.preventDefault();
            setOpen((prev) => !prev);
          }
        }}
        className="inline-flex items-center gap-2 rounded-full bg-blue-600 px-4 py-3 text-white shadow-xl transition hover:bg-blue-700 active:scale-95 touch-manipulation"
        style={{
          userSelect: 'none',
          touchAction: 'none',
          WebkitTouchCallout: 'none',
          WebkitUserSelect: 'none'
        }}
      >
        <span>Chat</span>
        <span className="text-lg">💬</span>
        {badgeCount > 0 && (
          <span className="inline-flex h-6 min-w-[1.5rem] items-center justify-center rounded-full bg-red-500 px-2 text-xs font-bold text-white">
            {badgeCount > 9 ? '9+' : badgeCount}
          </span>
        )}
      </button>

      {open && (
        <div className="absolute mt-3 w-80 max-w-[calc(100vw-2rem)] rounded-3xl border border-slate-200 bg-white shadow-2xl left-0 right-0 mx-auto md:left-auto md:right-0 md:mx-0 z-[2147483647]" style={{ pointerEvents: 'auto', zIndex: 2147483647 }}>
          <div className="rounded-3xl bg-blue-700 p-4 text-white">
            <div className="flex items-center justify-between gap-3">
              <div>
                <p className="text-sm font-semibold">{botName} Support</p>
                <p className="text-xs text-slate-200/90">{statusLabel}</p>
              </div>
              <button onClick={() => setOpen(false)} className="rounded-full bg-blue-800 p-1 text-white hover:bg-blue-900 touch-manipulation">✕</button>
            </div>
          </div>

          <div className="max-h-[50vh] md:max-h-[380px] overflow-y-auto p-4 space-y-3">
            {loading ? (
              <p className="text-sm text-slate-500">Loading chat…</p>
            ) : !status || status === 'unauthenticated' ? (
              <div>
                <p className="text-sm text-slate-700">Please log in to start chat support.</p>
                <Link href="/login" className="mt-3 inline-flex w-full items-center justify-center rounded-2xl bg-blue-600 px-4 py-2 text-sm font-semibold text-white hover:bg-blue-700">
                  Login to chat
                </Link>
              </div>
            ) : canAdminChat && !isAdminPage ? (
              <p className="text-sm text-slate-700">Admin chatbot is available only inside the admin panel. Open an admin page to use it.</p>
            ) : canAdminChat && isAdminPage ? (
              <>
                <div className="rounded-3xl bg-slate-50 p-4 text-sm text-slate-700">
                  <p>Use this admin assistant to manage products, orders, users, coupons, and settings from the admin panel.</p>
                </div>
                <div className="space-y-3">
                  {adminMessages.map((message, index) => (
                    <div key={`${message.sender}-${index}`} className={`flex ${message.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                      <div className={`rounded-3xl p-3 max-w-[85%] ${message.sender === 'user' ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-900'}`}>
                        <p className={`text-xs uppercase tracking-wide ${message.sender === 'user' ? 'text-blue-200' : 'text-slate-500'}`}>
                          {message.sender === 'user' ? 'You' : botName}
                        </p>
                        <p className="mt-1 text-sm break-words">{message.message}</p>
                      </div>
                    </div>
                  ))}
                </div>
                {error && <p className="mt-2 text-sm text-red-600">{error}</p>}
                <div className="mt-3 flex gap-2">
                  <input
                    value={adminInput}
                    onChange={(event) => setAdminInput(event.target.value)}
                    onKeyDown={(event) => {
                      if (event.key === 'Enter' && !event.shiftKey) {
                        event.preventDefault();
                        sendAdminMessage();
                      }
                    }}
                    placeholder={`Ask ${botName} about admin tasks...`}
                    className="flex-1 rounded-2xl border border-slate-200 bg-white px-3 py-2 text-sm text-slate-900 focus:border-blue-500 focus:outline-none"
                  />
                  <button
                    type="button"
                    onClick={sendAdminMessage}
                    disabled={!adminInput.trim()}
                    className="inline-flex items-center justify-center rounded-2xl bg-blue-600 px-4 py-2 text-sm font-semibold text-white hover:bg-blue-700 disabled:opacity-50"
                  >
                    <span>Send</span>
                    <span className="ml-2 text-lg">➤</span>
                  </button>
                </div>
              </>
            ) : (
              <>
                {chat === null && (
                  <div className="rounded-3xl bg-slate-50 p-4 text-sm text-slate-700">
                    <p>Hello! Start a chat to get product help, order guidance, or account support.</p>
                    <button
                      onClick={createChat}
                      disabled={loading}
                      className="mt-3 inline-flex w-full items-center justify-center rounded-2xl bg-blue-600 px-4 py-2 text-sm font-semibold text-white hover:bg-blue-700 disabled:opacity-50"
                    >
                      Start Chat
                    </button>
                  </div>
                )}

                {chat && (
                  <>
                    <div className="space-y-3">
                      {messages.map((message) => (
                        <div key={message._id} className={`flex ${message.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                          <div className={`rounded-3xl p-3 max-w-[85%] ${message.sender === 'user' ? 'bg-blue-600 text-white' : message.sender === 'admin' ? 'bg-emerald-100 text-slate-900' : 'bg-slate-100 text-slate-900'}`}>
                            <div className="flex items-center justify-between gap-2">
                              <p className={`text-xs uppercase tracking-wide ${message.sender === 'user' ? 'text-blue-200' : 'text-slate-500'}`}>{message.sender === 'user' ? 'You' : message.sender === 'admin' ? 'Agent' : botName}</p>
                              <span className="text-[10px] text-slate-500">{new Date(message.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                            </div>
                            <p className="mt-1 text-sm break-words">{message.message}</p>
                            {message.sender === 'user' && (
                              <p className="mt-2 text-[10px] text-blue-200 opacity-80">{message.delivered ? (message.seen ? 'Seen' : 'Delivered') : 'Sent'}</p>
                            )}
                          </div>
                        </div>
                      ))}
                    </div>

                    {error && <p className="mt-2 text-sm text-red-600">{error}</p>}
                    {isPendingAdminRequest && (
                      <div className="rounded-3xl bg-orange-50 p-4 text-sm text-orange-700 border border-orange-200">
                        <p>A support agent has requested to chat with you.</p>
                        <p className="mt-1 text-xs text-orange-600">Click Join chat with requested admin to accept and continue the conversation.</p>
                      </div>
                    )}

                    {chat.status === 'closed' ? (
                      <div className="rounded-3xl bg-slate-50 p-4 text-sm text-slate-700">
                        <p>This chat has been closed. Start a new chat if you need more help.</p>
                        <button
                          onClick={createChat}
                          disabled={loading}
                          className="mt-3 inline-flex w-full items-center justify-center rounded-2xl bg-blue-600 px-4 py-2 text-sm font-semibold text-white hover:bg-blue-700 disabled:opacity-50"
                        >
                          Start New Chat
                        </button>
                      </div>
                    ) : (
                      <div className="mt-3 space-y-3">
                        <div className="space-y-2">
                          {showJoinChatOption && (
                            <button
                              type="button"
                              onClick={acceptChatRequest}
                              disabled={sending}
                              className="w-full rounded-2xl bg-emerald-600 px-4 py-2 text-sm font-semibold text-white hover:bg-emerald-700 disabled:opacity-50"
                            >
                              Join chat with requested admin
                            </button>
                          )}
                          {!chat.escalated && showSupportOption && (
                            <button
                              type="button"
                              onClick={connectToHuman}
                              disabled={sending || !supportAvailable}
                              className={`w-full rounded-2xl px-4 py-2 text-sm font-semibold text-white ${supportAvailable ? 'bg-orange-500 hover:bg-orange-600' : 'bg-slate-300 cursor-not-allowed'}`}
                            >
                              {supportAvailable ? 'Request Support Specialist' : 'Support Specialist not available'}
                            </button>
                          )}
                          <button
                            type="button"
                            onClick={async () => {
                              if (!chat) return;
                              setSending(true);
                              setError('');
                              try {
                                const res = await fetch(`/api/chats/${chat._id}`, {
                                  method: 'PUT',
                                  headers: { 'Content-Type': 'application/json' },
                                  body: JSON.stringify({ status: 'closed' }),
                                });
                                const data = await res.json();
                                if (!res.ok) {
                                  setError(data.error || 'Failed to end chat');
                                  return;
                                }
                                setChat(data.chat);
                              } catch (err) {
                                console.error('End chat failed:', err);
                                setError('Failed to end chat. Please try again.');
                              } finally {
                                setSending(false);
                              }
                            }}
                            disabled={sending}
                            className="w-full rounded-2xl bg-red-600 px-4 py-2 text-sm font-semibold text-white hover:bg-red-700 disabled:opacity-50"
                          >
                            End chat
                          </button>
                        </div>
                        <div className="flex gap-2">
                          <input
                            value={input}
                            onChange={(event) => setInput(event.target.value)}
                            onKeyDown={(event) => {
                              if (event.key === 'Enter' && !event.shiftKey) {
                                event.preventDefault();
                                sendMessage();
                              }
                            }}
                            placeholder={isPendingAdminRequest ? 'Accept the admin request to continue...' : chat.escalated ? 'Send a message to support...' : 'Ask the bot a question...'}
                            disabled={isPendingAdminRequest}
                            className="flex-1 rounded-2xl border border-slate-200 bg-white px-3 py-2 text-sm text-slate-900 focus:border-blue-500 focus:outline-none disabled:cursor-not-allowed disabled:bg-slate-100"
                          />
                          <button
                            type="button"
                            onClick={sendMessage}
                            disabled={!input.trim() || sending || isPendingAdminRequest}
                            className="inline-flex items-center justify-center rounded-2xl bg-blue-600 px-4 py-2 text-sm font-semibold text-white hover:bg-blue-700 disabled:opacity-50"
                          >
                            <span>Send</span>
                            <span className="ml-2 text-lg">➤</span>
                          </button>
                        </div>
                      </div>
                    )}
                    <div ref={messagesEndRef} />
                  </>
                )}
              </>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

'use client';

import { useEffect, useState } from 'react';
import Footer from './Footer';
import { useSearchParams } from 'next/navigation';
import ProductList from '@/components/ProductList';
import { Suspense } from 'react';

function toBool(val: any): boolean {
  if (typeof val === 'boolean') return val;
  if (typeof val === 'string') return val === 'true';
  return false;
}

interface HomepageSection {
  _id: string;
  type: 'banner' | 'feature' | 'custom';
  title: string;
  subtitle?: string;
  image?: string;
  link?: string;
  order: number;
  isActive: boolean;
  content?: string;
}

import type { BusinessSettings } from '../types/business';

export default function ClientHomePage() {
    // Default container style for layout
    const containerStyle = { maxWidth: '1200px', margin: '0 auto', width: '100%' };
  const [settings, setSettings] = useState<BusinessSettings>({});
  const [sections, setSections] = useState<HomepageSection[]>([]);
  const [isLoaded, setIsLoaded] = useState(false);
  const [sectionsLoaded, setSectionsLoaded] = useState(false);
  const searchParams = useSearchParams();
  const searchQuery = searchParams?.get('search') ?? '';

  useEffect(() => {
    const fetchSettings = async () => {
      try {
        const res = await fetch('/api/business-settings', {
          next: { revalidate: 300 },
        });
        if (res.ok) {
          const data = await res.json();
          const processedData = {
            ...data,
            heroEnabled: data.heroEnabled === undefined ? true : toBool(data.heroEnabled),
            announcementEnabled: data.announcementEnabled === undefined ? false : toBool(data.announcementEnabled),
            welcomeEnabled: data.welcomeEnabled === undefined ? true : toBool(data.welcomeEnabled),
            featuresEnabled: data.featuresEnabled === undefined ? true : toBool(data.featuresEnabled),
          };
          setSettings(processedData);
        }
      } catch (error) {
        console.error('Failed to fetch settings:', error);
      } finally {
        setIsLoaded(true);
      }
    };
    fetchSettings();
    const fetchSections = async () => {
      try {
        const res = await fetch('/api/homepage-sections');
        if (res.ok) {
          const data = await res.json();
          setSections(Array.isArray(data.sections) ? data.sections : []);
        }
      } catch (error) {
        console.error('Failed to fetch homepage sections:', error);
      } finally {
        setSectionsLoaded(true);
      }
    };
    fetchSections();
  }, []);

  if (!isLoaded || !sectionsLoaded) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-theme-background" style={{ color: settings.textColor || 'var(--text-color)' }}>
        <div className="text-center">
          <div className="w-16 h-16 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mx-auto"></div>
          <p className="mt-4 text-gray-600">Loading...</p>
        </div>
      </div>
    );
  }

  // Render homepage sections (banners, features, custom)
  return (
    <div className="min-h-screen flex flex-col bg-theme-background" style={{ color: settings.textColor || 'var(--text-color)' }}>
      {/* Announcement Banner */}
      {/* Homepage Sections (banners/features/custom) */}
      {/* {renderHomepageSections()} */}
      {settings.announcementEnabled && (
        <div 
          className="py-3 text-center font-medium"
          style={{ 
            backgroundColor: settings.announcementBgColor || '#10b981',
            color: settings.announcementTextColor || '#ffffff'
          }}
        >
          {settings.announcementText || 'Announcement'}
        </div>
      )}

      {/* Hero Section */}
      {settings.heroEnabled && (
        <section 
          className="py-12 md:py-16 px-4 text-center"
          style={{ 
            backgroundColor: settings.heroBgColor || '#3b82f6',
            color: settings.heroTextColor || '#ffffff'
          }}
        >
          <div style={containerStyle} className="mx-auto max-w-4xl">
            <h1 className="text-3xl md:text-4xl lg:text-5xl font-bold mb-3 md:mb-4 leading-tight">
              {settings.heroTitle || 'Welcome to Our Store'}
            </h1>
            <p className="text-base md:text-lg lg:text-xl mb-6 md:mb-8 max-w-3xl mx-auto opacity-95">
              {settings.heroSubtitle || 'Discover amazing products at great prices'}
            </p>
            <div className="flex flex-col sm:flex-row justify-center items-center gap-3 md:gap-4">
              <a
                href="#products"
                className="inline-flex items-center justify-center px-6 md:px-8 py-3 md:py-4 text-base md:text-lg font-semibold rounded-full shadow-lg transition-transform hover:scale-105 min-h-[48px]"
                style={{ 
                  backgroundColor: settings.heroButtonBg || '#ffffff',
                  color: settings.heroButtonTextColor || '#3b82f6'
                }}
              >
                {settings.heroButtonText || 'Shop Now'}
              </a>
              <a
                href={settings.contactWhatsapp ? `https://wa.me/${settings.contactWhatsapp}` : '#'}
                target="_blank"
                rel="noreferrer"
                className="inline-flex items-center justify-center px-6 md:px-8 py-3 md:py-4 text-base md:text-lg font-semibold rounded-full border border-white/90 bg-white/10 text-white hover:bg-white hover:text-slate-900 transition min-h-[48px]"
              >
                🗨️ Contact Support
              </a>
            </div>
          </div>
        </section>
      )}

      <section className="py-8 px-4">
        <div style={containerStyle}>
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
            <div className="rounded-3xl bg-white p-6 shadow-lg border border-slate-200">
              <h2 className="text-xl font-semibold text-slate-900 mb-3">Fast Shopping</h2>
              <p className="text-slate-600 mb-4">Search, compare and checkout in just a few taps.</p>
              <div className="grid grid-cols-2 gap-3 sm:grid-cols-4">
                <span className="rounded-2xl bg-slate-50 px-3 py-2 text-xs font-semibold text-slate-700">Quick delivery</span>
                <span className="rounded-2xl bg-slate-50 px-3 py-2 text-xs font-semibold text-slate-700">Easy returns</span>
                <span className="rounded-2xl bg-slate-50 px-3 py-2 text-xs font-semibold text-slate-700">Trusted quality</span>
                <span className="rounded-2xl bg-slate-50 px-3 py-2 text-xs font-semibold text-slate-700">Secure pay</span>
              </div>
            </div>

            <div className="rounded-3xl bg-gradient-to-br from-blue-600 to-sky-500 p-6 text-white shadow-lg border border-blue-300">
              <h2 className="text-xl font-semibold mb-3">Smart Product Discovery</h2>
              <p className="mb-4 opacity-90">Browse personalized deals, auctions and bargains from one smart panel.</p>
              <div className="space-y-2 text-sm">
                <p>⏏ Mobile-friendly product cards</p>
                <p>⏏ Live auction countdowns</p>
                <p>⏏ Save products, buy faster</p>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* Product List and Filters (restored above footer) */}
      <div style={containerStyle}>
        <Suspense fallback={<div>Loading products...</div>}>
          <ProductList />
        </Suspense>
      </div>

      {/* Footer at the very end */}
      <Footer settings={settings} />
    </div>
  );
}

'use client';

import { useCallback, useEffect, useState } from 'react';
import Link from 'next/link';
import { useSession } from 'next-auth/react';

interface ConsumerUser {
  _id: string;
  name?: string;
  email?: string;
  mobile?: string;
  customerId?: string;
}

interface ConsumerChat {
  _id: string;
  type: 'consumer';
  status: 'pending' | 'active' | 'closed';
  participants: ConsumerUser[];
  targetUser: ConsumerUser;
  user: ConsumerUser;
  requestedAt?: string;
  acceptedAt?: string;
  lastMessageAt?: string;
}

interface ConsumerMessage {
  _id: string;
  sender: 'user' | 'admin' | 'bot';
  senderId?: string;
  senderName?: string;
  type: 'text' | 'audio' | 'image';
  content: string;
  metadata?: any;
  createdAt: string;
  seen?: boolean;
}

export default function ConsumerChatPanel({ enabled = true }: { enabled?: boolean }) {
  const { data: session, status } = useSession();
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<ConsumerUser[]>([]);
  const [selectedTarget, setSelectedTarget] = useState<ConsumerUser | null>(null);
  const [requestMessage, setRequestMessage] = useState('');
  const [requestStatus, setRequestStatus] = useState('');
  const [chats, setChats] = useState<ConsumerChat[]>([]);
  const [selectedChat, setSelectedChat] = useState<ConsumerChat | null>(null);
  const [messages, setMessages] = useState<ConsumerMessage[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const [loading, setLoading] = useState(false);
  const [statusText, setStatusText] = useState('');
  const [typingStatus, setTypingStatus] = useState('');
  const [otherUserOnline, setOtherUserOnline] = useState(false);
  const [participantStatuses, setParticipantStatuses] = useState<Record<string, boolean>>({});
  const [typingTimeout, setTypingTimeout] = useState<NodeJS.Timeout | null>(null);
  const [isRecording, setIsRecording] = useState(false);
  const [mediaRecorder, setMediaRecorder] = useState<MediaRecorder | null>(null);
  const [audioChunks, setAudioChunks] = useState<Blob[]>([]);
  const [selectedImage, setSelectedImage] = useState<File | null>(null);
  const [uploading, setUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);

  const loadChats = useCallback(async () => {
    setLoading(true);
    try {
      const res = await fetch('/api/consumer-chats');
      if (!res.ok) {
        setChats([]);
        return;
      }
      const data = await res.json();
      const updatedChats = data.chats || [];
      setChats(updatedChats);
      if (!selectedChat && updatedChats.length > 0) {
        setSelectedChat(updatedChats[0]);
      } else if (selectedChat) {
        const matching = updatedChats.find((chat: ConsumerChat) => chat._id === selectedChat._id);
        if (matching) {
          setSelectedChat(matching);
        }
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  }, [selectedChat]);

  const loadMessages = useCallback(async (chatId: string) => {
    try {
      const res = await fetch(`/api/consumer-chats/${chatId}/messages`);
      if (!res.ok) return;
      const data = await res.json();
      setMessages(data.messages || []);
    } catch (err) {
      console.error(err);
    }
  }, []);

  const checkOnlineStatus = useCallback(async (userId: string) => {
    if (!userId) return false;
    try {
      const res = await fetch(`/api/user/online-status?userId=${userId}`);
      if (!res.ok) return false;
      const data = await res.json();
      console.log(`Online status for ${userId}:`, data.online); // Debug log
      return data.online === true;
    } catch (err) {
      console.error('Error checking online status:', err);
      return false;
    }
  }, []);

  const updateParticipantStatuses = useCallback(async (userIds: string[]) => {
    if (!userIds.length) return;
    const statusMap: Record<string, boolean> = {};
    await Promise.all(
      userIds.map(async (userId) => {
        statusMap[userId] = await checkOnlineStatus(userId);
      })
    );
    setParticipantStatuses((prev) => ({ ...prev, ...statusMap }));
    const otherUser = selectedChat?.participants.find((u) => u._id !== session?.user?.id);
    if (otherUser) {
      setOtherUserOnline(statusMap[otherUser._id] ?? false);
    }
  }, [checkOnlineStatus, selectedChat, session?.user?.id]);

  const updateMyStatus = useCallback(async () => {
    try {
      await fetch('/api/user/online-status', { method: 'POST' });
    } catch (err) {
      console.error('Error updating status:', err);
    }
  }, []);

  useEffect(() => {
    if (status === 'authenticated') {
      loadChats();
      updateMyStatus();

      const statusInterval = setInterval(() => updateMyStatus(), 30000); // 30s for presence updates
      const chatListInterval = setInterval(() => loadChats(), 8000); // 8s for chat list refresh

      const handleVisibilityChange = () => {
        if (document.visibilityState === 'visible') {
          updateMyStatus();
          loadChats();
        }
      };

      const handleFocus = () => {
        updateMyStatus();
      };

      const handleBeforeUnload = () => {
        if (navigator.sendBeacon) {
          navigator.sendBeacon('/api/user/online-status');
        }
      };

      document.addEventListener('visibilitychange', handleVisibilityChange);
      window.addEventListener('focus', handleFocus);
      window.addEventListener('beforeunload', handleBeforeUnload);

      return () => {
        clearInterval(statusInterval);
        clearInterval(chatListInterval);
        document.removeEventListener('visibilitychange', handleVisibilityChange);
        window.removeEventListener('focus', handleFocus);
        window.removeEventListener('beforeunload', handleBeforeUnload);
      };
    }
  }, [status, loadChats, updateMyStatus]);

  useEffect(() => {
    if (selectedChat) {
      loadMessages(selectedChat._id);
      const otherUser = selectedChat.participants.find((u) => u._id !== session?.user?.id);
      if (otherUser) {
        updateParticipantStatuses([otherUser._id]);
      }

      const refreshInterval = setInterval(() => {
        loadMessages(selectedChat._id);
        if (otherUser) {
          updateParticipantStatuses([otherUser._id]);
        }
      }, 5000); // 5s for message refresh (faster delivery)

      return () => clearInterval(refreshInterval);
    }

    setMessages([]);
    setOtherUserOnline(false);
  }, [selectedChat, loadMessages, updateParticipantStatuses, session?.user?.id]);

  const searchCustomers = async () => {
    if (!searchQuery.trim()) {
      setSearchResults([]);
      return;
    }
    setStatusText('Searching customers...');
    try {
      const res = await fetch(`/api/consumer-chats/search?q=${encodeURIComponent(searchQuery.trim())}`);
      if (!res.ok) {
        setSearchResults([]);
        setStatusText('Unable to search customers');
        return;
      }
      const data = await res.json();
      setSearchResults(data.users || []);
      setStatusText((data.users || []).length ? '' : 'No customers found');
    } catch (err) {
      console.error(err);
      setStatusText('Search failed');
    }
  };

  const parseJsonResponse = async (response: Response) => {
    const text = await response.text();
    if (!text) return {};
    try {
      return JSON.parse(text);
    } catch (parseError) {
      console.error('Failed to parse API response as JSON:', parseError, text);
      return { error: 'Unexpected server response. Please try again.' };
    }
  };

  const readFileAsDataURL = (file: Blob, onProgress?: (percent: number) => void): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onprogress = (event) => {
        if (event.lengthComputable && onProgress) {
          const percent = Math.round((event.loaded / event.total) * 100);
          onProgress(percent);
        }
      };
      reader.onload = () => {
        if (typeof reader.result === 'string') {
          onProgress?.(100);
          resolve(reader.result);
        } else {
          reject(new Error('Unable to read file as data URL'));
        }
      };
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });
  };

  const sendChatRequest = async (targetIdentifier: string) => {
    if (!targetIdentifier.trim()) {
      setRequestStatus('Please select a target customer');
      return;
    }
    setRequestStatus('Sending chat request...');
    try {
      const res = await fetch('/api/consumer-chats', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ targetIdentifier: targetIdentifier.trim(), message: requestMessage.trim() }),
      });

      const data: any = await parseJsonResponse(res);
      if (!res.ok) {
        setRequestStatus(data.error || `Failed to send chat request (${res.status})`);
        return;
      }
      setRequestStatus('Chat request sent successfully.');
      setSelectedTarget(null);
      setSearchQuery('');
      setRequestMessage('');
      setSearchResults([]);
      await loadChats();
      if (data.chat) {
        setSelectedChat(data.chat);
        loadMessages(data.chat._id);
      }
    } catch (err) {
      console.error(err);
      setRequestStatus('Unable to send chat request.');
    }
  };

  const acceptChat = async (chatId: string) => {
    setStatusText('Accepting chat request...');
    try {
      const res = await fetch(`/api/consumer-chats/${chatId}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'accept' }),
      });
      const data: any = await parseJsonResponse(res);
      if (!res.ok) {
        setStatusText(data.error || `Unable to accept chat request (${res.status})`);
        return;
      }
      setStatusText('Chat request accepted. You may now chat.');
      await loadChats();
      if (data.chat) {
        setSelectedChat(data.chat);
        loadMessages(data.chat._id);
      }
    } catch (err) {
      console.error(err);
      setStatusText('Unable to accept chat request.');
    }
  };

  const closeConversation = async () => {
    if (!selectedChat) return;
    setStatusText('Closing conversation...');
    try {
      const res = await fetch(`/api/consumer-chats/${selectedChat._id}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'close' }),
      });
      const data: any = await parseJsonResponse(res);
      if (!res.ok) {
        setStatusText(data.error || `Unable to close conversation (${res.status})`);
        return;
      }
      setStatusText('Conversation closed.');
      await loadChats();
      if (data.chat) {
        setSelectedChat(data.chat);
        loadMessages(data.chat._id);
      }
    } catch (err) {
      console.error(err);
      setStatusText('Unable to close conversation.');
    }
  };

  const sendMessage = async (type: 'text' | 'audio' | 'image' = 'text', content: string, metadata: any = {}) => {
    if (!selectedChat || !content.trim()) return;
    const isRequester = selectedChat.user._id === session?.user?.id;
    if (selectedChat.status === 'pending' && !isRequester) {
      setStatusText('Waiting for the other customer to accept before sending messages.');
      return;
    }
    if (selectedChat.status === 'closed') {
      setStatusText('Conversation is closed.');
      return;
    }
    setStatusText('Sending message...');
    setTypingStatus('');
    try {
      const res = await fetch(`/api/consumer-chats/${selectedChat._id}/messages`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ type, content: content.trim(), metadata }),
      });
      const data: any = await parseJsonResponse(res);
      if (!res.ok) {
        setStatusText(data.error || 'Message failed');
        return;
      }
      setNewMessage('');
      setStatusText('');
      setUploadProgress(0);
      setOtherUserOnline(true);
      setTimeout(() => {
        setTypingStatus(`${selectedChat.participants.find((u) => u._id !== session?.user?.id)?.name || 'User'} is typing...`);
        setTimeout(() => setTypingStatus(''), 2000);
      }, 1000);
      await loadMessages(selectedChat._id);
      await loadChats();
    } catch (err) {
      console.error(err);
      setStatusText('Message send failed');
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const recorder = new MediaRecorder(stream);
      const chunks: Blob[] = [];

      recorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          chunks.push(event.data);
        }
      };

      recorder.onstop = async () => {
        const audioBlob = new Blob(chunks, { type: 'audio/webm' });
        await uploadAndSendAudio(audioBlob);
        stream.getTracks().forEach(track => track.stop());
      };

      setMediaRecorder(recorder);
      setAudioChunks(chunks);
      recorder.start();
      setIsRecording(true);
    } catch (err) {
      console.error('Error starting recording:', err);
      setStatusText('Failed to start recording');
    }
  };

  const stopRecording = () => {
    if (mediaRecorder && isRecording) {
      mediaRecorder.stop();
      setIsRecording(false);
    }
  };

  const uploadAndSendAudio = async (blob: Blob) => {
    setUploading(true);
    setUploadProgress(0);
    try {
      const dataUrl = await readFileAsDataURL(blob, setUploadProgress);
      await sendMessage('audio', dataUrl, { fileName: `audio_${Date.now()}.webm`, duration: 0 });
    } catch (err) {
      console.error('Error uploading audio:', err);
      setStatusText('Failed to upload audio');
    } finally {
      setUploading(false);
      setUploadProgress(0);
    }
  };

  const sendImage = async () => {
    if (!selectedImage) return;
    setUploading(true);
    setUploadProgress(0);
    try {
      const dataUrl = await readFileAsDataURL(selectedImage, setUploadProgress);
      await sendMessage('image', dataUrl, {
        fileName: selectedImage.name,
        size: selectedImage.size,
        mimeType: selectedImage.type,
      });
      setSelectedImage(null);
    } catch (err) {
      console.error('Error uploading image:', err);
      setStatusText('Failed to upload image');
    } finally {
      setUploading(false);
      setUploadProgress(0);
    }
  };

  const handleImageSelect = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file && file.type.startsWith('image/')) {
      setSelectedImage(file);
      setUploadProgress(0);
    }
  };
    
  const handleTypingInput = (value: string) => {
    setNewMessage(value);
    // Clear existing timeout
    if (typingTimeout) {
      clearTimeout(typingTimeout);
    }
    // Send typing indicator logic would go here
    
    const timeout = setTimeout(() => {
      setTypingStatus('');
    }, 3000);
    setTypingTimeout(timeout);
  };

  const isRequester = selectedChat?.user?._id === session?.user?.id;

  if (status !== 'authenticated') {
    return null;
  }

  if (!enabled) {
    return (
      <div className="mt-8 max-w-5xl mx-auto px-4">
        <div className="overflow-hidden rounded-[28px] bg-white shadow-2xl ring-1 ring-slate-200">
          <div className="bg-gradient-to-r from-slate-900 via-slate-800 to-slate-700 px-6 py-7 text-white">
            <h2 className="text-2xl font-semibold">👥 Customer-to-Customer Chat</h2>
            <p className="mt-3 max-w-2xl text-sm text-slate-200">This feature is currently disabled. Enable it in your profile settings to chat directly with other customers.</p>
          </div>
          <div className="space-y-6 p-6">
            {chats.length > 0 && (
              <div className="rounded-[28px] border border-slate-200 bg-slate-50 p-6 shadow-sm">
                <h3 className="text-lg font-semibold text-slate-900 mb-4">Your existing conversations</h3>
                <div className="space-y-3">
                  {chats.map((chat) => (
                    <div key={chat._id} className="flex items-center justify-between gap-4 rounded-3xl bg-white border border-slate-200 p-4 shadow-sm">
                      <div>
                        <p className="font-semibold text-slate-900">
                          {chat.participants.find((u) => u._id !== session?.user?.id)?.name || 'Unknown customer'}
                        </p>
                        <p className="text-sm text-slate-600">Status: {chat.status}</p>
                      </div>
                      <span className="text-sm text-slate-500">Disabled - Enable to chat</span>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="mt-10 max-w-7xl mx-auto px-4">
      <div className="overflow-hidden rounded-[32px] bg-white shadow-2xl ring-1 ring-slate-200">
        <div className="bg-gradient-to-r from-sky-700 via-indigo-600 to-sky-600 px-6 py-8 text-white">
          <p className="text-sm font-semibold uppercase tracking-[0.3em] text-sky-50">Customer conversation</p>
          <h2 className="mt-3 text-3xl font-bold tracking-tight text-white">Customer-to-Customer Chat</h2>
          <p className="mt-3 max-w-2xl text-sm text-sky-100">Search a customer by email, mobile, or customer ID, then send a chat request to start a direct conversation.</p>
        </div>

        <div className="grid gap-5 p-6 lg:grid-cols-[1.2fr_0.8fr]">
          <div className="space-y-4">
            <div className="rounded-[28px] border border-slate-200 bg-slate-50 p-6 shadow-sm">
              <div className="mb-4 flex items-center justify-between gap-4">
                <div>
                  <h3 className="text-xl font-semibold text-slate-900">Find a customer</h3>
                  <p className="text-sm text-slate-600">Search and select a customer to request a private chat.</p>
                </div>
                <span className="rounded-full bg-sky-100 px-3 py-1 text-xs font-semibold text-sky-800">Quick access</span>
              </div>
              <label className="block text-gray-700 font-semibold">Search customer by email, mobile, or customer ID</label>
              <div className="mt-3 flex flex-col gap-3 sm:flex-row">
                <input
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  placeholder="Type email, mobile, or ID"
                  className="w-full rounded-3xl border border-slate-300 bg-white px-4 py-3 text-slate-900 shadow-sm focus:border-sky-500 focus:ring-2 focus:ring-sky-200"
                />
                <button onClick={searchCustomers} className="w-full rounded-3xl bg-sky-600 px-5 py-3 text-sm font-semibold text-white transition hover:bg-sky-700 sm:w-auto">Search</button>
              </div>
            </div>

            {searchResults.length > 0 && (
              <div className="space-y-3 rounded-[24px] border border-slate-200 bg-white p-4 shadow-sm">
                <p className="text-sm text-gray-700 font-medium">Select a customer to send a chat request</p>
                {searchResults.map((customer) => (
                  <div key={customer._id} className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3 p-3 rounded-lg bg-white border border-gray-200">
                    <div>
                      <p className="font-semibold text-gray-900">{customer.name || 'Unnamed customer'}</p>
                      <p className="text-sm text-gray-600">{customer.email || 'No email'} &middot; {customer.mobile}</p>
                      <p className="text-sm text-gray-500">ID: {customer.customerId || 'N/A'}</p>
                    </div>
                    <button
                      onClick={() => { setSelectedTarget(customer); setRequestStatus(''); }}
                      className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700"
                    >
                      Select
                    </button>
                  </div>
                ))}
              </div>
            )}

            <div className="rounded-[28px] border border-slate-200 bg-white p-6 shadow-sm">
              <p className="text-sm font-semibold text-gray-900">Request details</p>
              <div className="space-y-3">
                <div>
                  <label className="block text-gray-700 text-sm mb-2">Selected customer</label>
                  <div className="min-h-[60px] rounded-lg border border-gray-300 bg-white px-4 py-3 text-gray-700">
                    {selectedTarget ? (
                      <div>
                        <p className="font-semibold">{selectedTarget.name || 'Unnamed customer'}</p>
                        <p className="text-sm text-gray-600">{selectedTarget.email || 'No email'} · {selectedTarget.mobile}</p>
                      </div>
                    ) : (
                      <span className="text-gray-500">No customer selected yet.</span>
                    )}
                  </div>
                </div>
                <div>
                  <label className="block text-gray-700 text-sm mb-2">Optional request message</label>
                  <textarea
                    rows={3}
                    value={requestMessage}
                    onChange={(e) => setRequestMessage(e.target.value)}
                    placeholder="Add a short note for the customer"
                    className="w-full rounded-3xl border border-slate-300 px-4 py-3 focus:outline-none focus:ring-2 focus:ring-sky-200"
                  />
                </div>
                <button
                  onClick={() => sendChatRequest(selectedTarget?.customerId || selectedTarget?._id || searchQuery)}
                  className="inline-flex items-center justify-center rounded-3xl bg-green-600 px-5 py-3 text-white hover:bg-green-700"
                >
                  Send chat request
                </button>
                {requestStatus && <p className="text-sm text-gray-700">{requestStatus}</p>}
              </div>
            </div>
          </div>

          <div className="space-y-4">
            <div className="rounded-[28px] border border-slate-200 bg-white p-6 shadow-sm">
              <div className="flex items-center justify-between gap-4">
                <div>
                  <h3 className="text-xl font-semibold text-gray-900">Your conversations</h3>
                  <p className="text-sm text-gray-600">Manage requests and continue active chats.</p>
                </div>
                <button onClick={loadChats} className="rounded-2xl border border-gray-300 px-4 py-2 text-sm font-semibold text-slate-700 hover:bg-slate-50">Refresh</button>
              </div>

              <div className="mt-4 space-y-3">
                {loading && <p className="text-sm text-gray-500">Loading chats...</p>}
                {!loading && chats.length === 0 && <p className="text-sm text-gray-500">No consumer conversations yet.</p>}
                {chats.map((chat) => {
                  const isPending = chat.status === 'pending';
                  const isActive = chat.status === 'active';
                  const otherUser = chat.participants.find((u) => u._id !== session?.user?.id);
                  return (
                    <div
                      key={chat._id}
                      className={`rounded-[24px] border p-4 transition ${selectedChat?._id === chat._id ? 'border-blue-500 bg-blue-50 shadow-sm' : 'border-slate-200 bg-white hover:border-slate-300 hover:shadow-sm'}`}
                    >
                      <div className="flex items-center justify-between gap-3">
                        <div>
                          <p className="font-semibold text-gray-900">{otherUser?.name || otherUser?.email || otherUser?.mobile || 'Customer'}</p>
                          <p className="text-sm text-gray-600">{otherUser?.customerId ? `ID: ${otherUser.customerId}` : ''}</p>
                        </div>
                        <span className={`rounded-full px-3 py-1 text-xs font-semibold ${isActive ? 'bg-green-100 text-green-800' : isPending ? 'bg-yellow-100 text-yellow-800' : 'bg-gray-100 text-gray-700'}`}>
                          {chat.status}
                        </span>
                      </div>
                      <div className="mt-3 flex flex-wrap items-center gap-2 text-sm text-gray-600">
                        <span>{chat.lastMessageAt ? new Date(chat.lastMessageAt).toLocaleString() : 'No updates yet'}</span>
                        {chat.acceptedAt && <span>· accepted {new Date(chat.acceptedAt).toLocaleString()}</span>}
                      </div>
                      <div className="mt-4 flex flex-wrap gap-2">
                        {isPending && chat.targetUser && chat.targetUser._id === session?.user?.id && (
                          <button onClick={() => acceptChat(chat._id)} className="rounded-lg bg-blue-600 px-4 py-2 text-white hover:bg-blue-700">Accept request</button>
                        )}
                        <Link
                          href={`/profile/chat/${chat._id}`}
                          onClick={() => setSelectedChat(chat)}
                          className="rounded-lg border border-gray-300 px-4 py-2 bg-white text-gray-900 hover:bg-gray-50"
                        >
                          Open chat
                        </Link>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        </div>

        <div className="mt-6 rounded-[28px] border border-slate-200 bg-slate-50 p-6 shadow-sm">
          <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
            <div>
              <h3 className="text-xl font-semibold text-gray-900">Dedicated chat view</h3>
              <p className="mt-1 text-sm text-gray-600">Open any conversation in a dedicated chat page with back navigation and a mobile-first layout.</p>
            </div>
            <div className="text-sm text-slate-600">Select a chat and tap “Open chat” to continue.</div>
          </div>
          {selectedChat && (
            <div className="mt-6 rounded-3xl border border-gray-200 bg-white p-5 shadow-sm">
              <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
                <div>
                  <p className="text-sm text-gray-500">Selected conversation</p>
                  <h4 className="mt-1 text-lg font-semibold text-gray-900">{selectedChat.participants.find((u) => u._id !== session?.user?.id)?.name || 'Customer'}</h4>
                  <p className="mt-1 text-sm text-gray-600">{selectedChat.status === 'pending' ? 'Pending acceptance' : selectedChat.status === 'active' ? 'Active conversation' : 'Closed conversation'}</p>
                </div>
                <Link href={`/profile/chat/${selectedChat._id}`} className="inline-flex items-center justify-center rounded-2xl bg-blue-600 px-4 py-3 text-sm font-semibold text-white hover:bg-blue-700">
                  Open conversation
                </Link>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import Link from 'next/link';
import {
  FaFacebookF,
  FaTwitter,
  FaInstagram,
  FaLinkedinIn,
  FaWhatsapp,
  FaMapMarkerAlt,
  FaEnvelope,
  FaPhoneAlt,
  FaShippingFast,
  FaLock,
  FaCheckCircle,
  FaHeadset
} from 'react-icons/fa';

import type { BusinessSettings } from '../types/business';

export default function Footer({ settings = {} as BusinessSettings }) {
  // Dynamic styles from settings
  const bgColor = settings.footerBgColor || '#1e293b';
  const textColor = settings.footerTextColor || settings.textColor || '#f1f5f9';
  const borderColor = settings.footerBorderColor || '#334155';
  return (
    <footer
      className="w-full pt-12 pb-0 px-0 mt-auto shadow-2xl rounded-t-3xl border-t"
      style={{
        background: bgColor,
        color: textColor,
        borderTopColor: borderColor,
        borderTopWidth: '1px',
      }}
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-10 md:gap-8 pb-8 border-b" style={{ borderColor }}>
          {/* Brand/Description */}
          <div className="flex flex-col gap-4">
            {settings.brandLogo && (
              <img src={settings.brandLogo} alt={settings.websiteName || 'Brand Logo'} className="h-12 w-auto mb-2 rounded-xl shadow-lg bg-white/10 p-1" />
            )}
            <h3 className="text-2xl font-bold tracking-tight drop-shadow-lg" style={{ color: settings.websiteNameColor || textColor }}>
              {settings.websiteName || 'Refurbished PC Studio'}
            </h3>
            <p className="text-sm leading-relaxed max-w-xs" style={{ color: settings.footerDescColor || textColor }}>
              {settings.footerText || 'Shop premium refurbished laptops & computers. Quality assured, best prices, trusted by professionals.'}
            </p>
            <span className="inline-block text-xs font-semibold mt-2 px-3 py-1 rounded-full shadow" style={{ background: settings.footerBadgeBg || 'rgba(30,64,175,0.2)', color: settings.footerBadgeColor || '#38bdf8' }}>
              {settings.footerBadgeText || 'Trusted Refurbished Marketplace'}
            </span>
          </div>

          {/* Quick Links */}
          <div>
            <h4 className="text-lg font-semibold mb-4" style={{ color: textColor }}>Quick Links</h4>
            <ul className="space-y-2">
              <li><Link href="/" className="hover:text-blue-400 transition-colors">Browse Stock</Link></li>
              <li><Link href="/offers" className="hover:text-blue-400 transition-colors">Offers</Link></li>
              <li><Link href="/orders" className="hover:text-blue-400 transition-colors">Orders</Link></li>
              <li><Link href="/support-tickets" className="hover:text-blue-400 transition-colors">Support</Link></li>
              <li><Link href="/contact" className="hover:text-blue-400 transition-colors">Contact</Link></li>
            </ul>
          </div>

          {/* Contact / Visit Us */}
          <div>
            <h4 className="text-lg font-semibold mb-4" style={{ color: textColor }}>Contact / Visit Us</h4>
            <ul className="space-y-2 text-sm">
              <li className="flex items-center gap-2"><FaMapMarkerAlt className="text-blue-400" />{settings.ownerAddress || settings.businessAddress || 'Business address here'}</li>
              <li className="flex items-center gap-2"><FaEnvelope className="text-blue-400" /><a href={`mailto:${settings.contactEmail || 'support@example.com'}`} className="hover:text-blue-400 transition-colors">{settings.contactEmail || 'support@example.com'}</a></li>
              <li className="flex items-center gap-2"><FaWhatsapp className="text-blue-400" /><a href={`https://wa.me/${settings.contactWhatsapp || ''}`} className="hover:text-blue-400 transition-colors">{settings.contactWhatsapp || 'WhatsApp'}</a></li>
              <li className="flex items-center gap-2"><FaPhoneAlt className="text-blue-400" />{settings.ownerPhone1 || settings.businessPhone || 'Phone number'}</li>
              <li className="flex items-center gap-2"><FaMapMarkerAlt className="text-blue-400" />{settings.ownerMapLink ? (<a href={settings.ownerMapLink} target="_blank" rel="noopener" className="hover:text-blue-400 transition-colors">Location</a>) : 'Location'}</li>
              <li className="flex items-center gap-2"><span className="text-blue-400 font-bold">⏰</span>{settings.storeTiming || 'Mon-Sat 10am-7pm'}</li>
            </ul>
          </div>

          {/* Support & Benefits */}
          <div>
            <h4 className="text-lg font-semibold mb-4" style={{ color: textColor }}>Support & Benefits</h4>
            <ul className="space-y-3 text-sm">
              <li className="flex items-center gap-2"><FaShippingFast className="text-blue-400" />Free Shipping</li>
              <li className="flex items-center gap-2"><FaLock className="text-blue-400" />Secure Payment</li>
              <li className="flex items-center gap-2"><FaCheckCircle className="text-blue-400" />Quality Assured</li>
              <li className="flex items-center gap-2"><FaHeadset className="text-blue-400" />24/7 Support</li>
            </ul>
          </div>
        </div>

        {/* Bottom Bar */}
        <div className="flex flex-col md:flex-row md:justify-between items-center py-5 gap-3 text-xs" style={{ color: settings.footerBottomTextColor || '#94a3b8' }}>
          <div className="flex flex-wrap items-center gap-3">
            <span>&copy; {new Date().getFullYear()} {settings.footerCopyright || settings.websiteName || 'Refurbished PC Studio'}. All rights reserved.</span>
            <span className="hidden md:inline">|</span>
            <a href="/privacy" className="hover:text-blue-400 transition-colors">Privacy Policy</a>
            <span className="hidden md:inline">|</span>
            <a href="/terms" className="hover:text-blue-400 transition-colors">Terms</a>
          </div>
          <div className="flex items-center gap-2">
            <span>{settings.footerMadeWith || <>Made with <span className="text-red-500">&#10084;&#65039;</span> by <span className="font-semibold text-blue-400">{settings.websiteName || 'Refurbished PC Studio'}</span></>}</span>
            {settings.footerFacebook && <a href={settings.footerFacebook} className="ml-2 hover:text-blue-400" target="_blank" rel="noopener"><FaFacebookF /></a>}
            {settings.footerTwitter && <a href={settings.footerTwitter} className="hover:text-blue-400" target="_blank" rel="noopener"><FaTwitter /></a>}
            {settings.footerInstagram && <a href={settings.footerInstagram} className="hover:text-blue-400" target="_blank" rel="noopener"><FaInstagram /></a>}
            {settings.footerLinkedin && <a href={settings.footerLinkedin} className="hover:text-blue-400" target="_blank" rel="noopener"><FaLinkedinIn /></a>}
          </div>
        </div>
      </div>
    </footer>
  );
}

