'use client';

import { useEffect, useState } from 'react';
import Link from 'next/link';
import SupportTicketForm from '@/components/SupportTicketForm';

interface SupportTicket {
  _id: string;
  subject: string;
  category: 'ticket' | 'cancellation' | 'shipping' | 'general-support';
  status: 'open' | 'in-progress' | 'waiting-customer' | 'resolved' | 'closed';
  priority: 'low' | 'medium' | 'high';
  createdAt: string;
  updatedAt: string;
  resolvedAt?: string;
}

export default function SupportTicketsList({ admin = false }: { admin?: boolean } = {}) {
  const [tickets, setTickets] = useState<SupportTicket[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [showForm, setShowForm] = useState(false);


  useEffect(() => {
    fetchTickets();
  }, [admin]);

  const fetchTickets = async () => {
    try {
      setLoading(true);
      const url = admin ? '/api/support-tickets?admin=1' : '/api/support-tickets';
      const res = await fetch(url);
      if (!res.ok) {
        setError('Failed to load tickets');
        return;
      }
      const data = await res.json();
      setTickets(data.tickets);
    } catch (err) {
      console.error('Error fetching tickets:', err);
      setError('Failed to load tickets');
    } finally {
      setLoading(false);
    }
  };

  const statusColors = {
    open: 'bg-blue-100 text-blue-800',
    'in-progress': 'bg-yellow-100 text-yellow-800',
    'waiting-customer': 'bg-orange-100 text-orange-800',
    resolved: 'bg-green-100 text-green-800',
    closed: 'bg-slate-100 text-slate-800',
  };

  const priorityColors = {
    low: 'text-blue-600',
    medium: 'text-yellow-600',
    high: 'text-red-600',
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center p-6">
        <p className="text-slate-600">Loading tickets...</p>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-3xl font-bold text-slate-900">Support Tickets</h1>
        {!admin && (
          <button
            onClick={() => setShowForm(!showForm)}
            className="rounded-lg bg-blue-600 px-4 py-2 text-sm font-semibold text-white hover:bg-blue-700"
          >
            {showForm ? 'Cancel' : 'Create New Ticket'}
          </button>
        )}
      </div>

      {error && (
        <div className="rounded-lg bg-red-50 p-4 text-red-700">{error}</div>
      )}

      {!admin && showForm && (
        <SupportTicketForm
          onSuccess={() => {
            setShowForm(false);
            fetchTickets();
          }}
        />
      )}

      <div className="rounded-lg border border-slate-200 bg-white">
        {tickets.length === 0 ? (
          <div className="p-6 text-center">
            <p className="text-slate-600">No support tickets found.</p>
            {!admin && (
              <button
                onClick={() => setShowForm(true)}
                className="mt-4 rounded-lg bg-blue-600 px-4 py-2 text-sm font-semibold text-white hover:bg-blue-700"
              >
                Create Your First Ticket
              </button>
            )}
          </div>
        ) : (
          <div className="divide-y divide-slate-200">
            {tickets.map((ticket) => (
              <div key={ticket._id} className="p-6 hover:bg-slate-50">
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <Link
                      href={`/support-tickets/${ticket._id}`}
                      className="text-lg font-semibold text-blue-600 hover:text-blue-700"
                    >
                      {ticket.subject}
                    </Link>
                    <p className="mt-1 text-sm text-slate-600">{ticket.category.replace('-', ' ')}</p>
                    <p className="mt-2 text-sm text-slate-700">
                      Created {new Date(ticket.createdAt).toLocaleDateString()}
                    </p>
                  </div>
                  <div className="flex items-center gap-4">
                    <span className={`inline-block rounded-full px-3 py-1 text-xs font-semibold ${statusColors[ticket.status]}`}>
                      {ticket.status.replace('-', ' ')}
                    </span>
                    <span className={`text-sm font-semibold capitalize ${priorityColors[ticket.priority]}`}>
                      {ticket.priority}
                    </span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

import React, { createContext, useContext, useEffect, useState } from 'react';
import { useSession } from 'next-auth/react';

interface WishlistContextType {
  wishlist: string[];
  loading: boolean;
  addToWishlist: (productId: string) => Promise<void>;
  removeFromWishlist: (productId: string) => Promise<void>;
  isInWishlist: (productId: string) => boolean;
  refreshWishlist: () => Promise<void>;
}

const WishlistContext = createContext<WishlistContextType | undefined>(undefined);

export function useWishlist() {
  const ctx = useContext(WishlistContext);
  if (!ctx) throw new Error('useWishlist must be used within WishlistProvider');
  return ctx;
}

export function WishlistProvider({ children }: { children: React.ReactNode }) {
  const { data: session } = useSession();
  const [wishlist, setWishlist] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);

  const fetchWishlist = async () => {
    setLoading(true);
    try {
      const res = await fetch('/api/wishlist');
      if (!res.ok) throw new Error('Failed to fetch wishlist');
      const data = await res.json();
      setWishlist((data.wishlist?.products || []).map((p: any) => {
        const id = typeof p === 'string' ? p : (p._id || p).toString();
        return id;
      }));
    } catch {
      setWishlist([]);
    }
    setLoading(false);
  };

  useEffect(() => {
    if (session?.user) fetchWishlist();
    else setWishlist([]);
  }, [session?.user]);


  const addToWishlist = async (productId: string) => {
    if (session?.user) {
      await fetch('/api/wishlist', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ productId }),
      });
      await fetchWishlist();
    } else {
      // Guest: use localStorage
      const local = JSON.parse(localStorage.getItem('wishlist') || '[]').map((id: any) => id.toString());
      if (!local.includes(productId.toString())) {
        const updated = [...local, productId.toString()];
        localStorage.setItem('wishlist', JSON.stringify(updated));
        setWishlist(updated);
      }
    }
  };

  const removeFromWishlist = async (productId: string) => {
    if (session?.user) {
      await fetch(`/api/wishlist?productId=${productId}`, { method: 'DELETE' });
      await fetchWishlist();
    } else {
      // Guest: use localStorage
      const local = JSON.parse(localStorage.getItem('wishlist') || '[]').map((id: any) => id.toString());
      const updated = local.filter((id: string) => id !== productId.toString());
      localStorage.setItem('wishlist', JSON.stringify(updated));
      setWishlist(updated);
    }
  };

  const isInWishlist = (productId: string) => wishlist.includes(productId?.toString());

  // On mount, load guest wishlist from localStorage
  useEffect(() => {
    if (!session?.user) {
      const local = JSON.parse(localStorage.getItem('wishlist') || '[]').map((id: any) => id.toString());
      setWishlist(local);
    }
  }, [session?.user]);

  return (
    <WishlistContext.Provider value={{ wishlist, loading, addToWishlist, removeFromWishlist, isInWishlist, refreshWishlist: fetchWishlist }}>
      {children}
    </WishlistContext.Provider>
  );
}

// Simple icon generator for PC Studio
// Run: node generate-icons.js
/* eslint-disable @typescript-eslint/no-require-imports */

const fs = require('fs');
const path = require('path');
const canvas = require('canvas');

const publicDir = path.join(__dirname, 'public');

// Create canvas and generate icons
const sizes = [192, 512];
const maskable = true;

async function generateIcon(size, isMaskable = false) {
  const canvasObj = canvas.createCanvas(size, size);
  const ctx = canvasObj.getContext('2d');
  
  // Background
  ctx.fillStyle = '#1e3a8a';
  ctx.fillRect(0, 0, size, size);
  
  // Add border for maskable icons
  if (isMaskable) {
    ctx.strokeStyle = '#0f172a';
    ctx.lineWidth = Math.max(1, size / 64);
    ctx.strokeRect(0, 0, size, size);
  }
  
  // Draw "PC" text
  ctx.fillStyle = '#ffffff';
  ctx.font = `bold ${Math.floor(size * 0.4)}px Arial`;
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.fillText('PC', size / 2, size / 2);
  
  // Save file
  const suffix = isMaskable ? '-maskable' : '';
  const filename = `icon-${size}${suffix}.png`;
  const filepath = path.join(publicDir, filename);
  
  const buffer = canvasObj.toBuffer('image/png');
  fs.writeFileSync(filepath, buffer);
  console.log(`✓ Generated: ${filename}`);
}

async function main() {
  try {
    console.log('Generating PWA icons...');
    for (const size of sizes) {
      await generateIcon(size, false);
      await generateIcon(size, true);
    }
    
    // Generate screenshot
    const screenshotCanvas = canvas.createCanvas(540, 720);
    const ctx = screenshotCanvas.getContext('2d');
    ctx.fillStyle = '#1e3a8a';
    ctx.fillRect(0, 0, 540, 720);
    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 48px Arial';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText('PC Studio', 270, 360);
    
    const screenshotBuffer = screenshotCanvas.toBuffer('image/png');
    fs.writeFileSync(path.join(publicDir, 'screenshot-540x720.png'), screenshotBuffer);
    console.log('✓ Generated: screenshot-540x720.png');
    
    console.log('\n✓ All icons generated successfully!');
  } catch (err) {
    console.error('Error generating icons:', err);
    process.exit(1);
  }
}

main();

