  }

  verify() {
    // Simulate successful verification in development
    if (this.callback) {
      this.callback();
    }
    return Promise.resolve(this.getResponse());
  }

  clear() {
    console.log('[MockRecaptchaVerifier] Cleared');
  }

  render() {
